# ── /start deeplink resolver ─────────────────────────────


async def _dl_send_edge_no_longer_available(
    update: "Update",  # type: ignore[name-defined]
    ctx: "ContextTypes.DEFAULT_TYPE",  # type: ignore[name-defined]
    match_key: str,
) -> None:
    await update.message.reply_text(
        "This edge is no longer available — here's what's live now:",
        parse_mode=ParseMode.HTML,
        reply_markup=InlineKeyboardMarkup([[
            InlineKeyboardButton("💎 Edge Picks", callback_data="hot:go"),
        ]]),
    )


async def _handle_card_deeplink(
    update: "Update",  # type: ignore[name-defined]
    ctx: "ContextTypes.DEFAULT_TYPE",  # type: ignore[name-defined]
    user_id: int,
    match_key: str,
) -> None:
    """AC-D: Resolve /start card_<match_key> deeplink from @MzansiEdgeAlerts button.

    Renders the same card photo the user would see tapping an edge in Hot Tips.
    match_key format: team_a_vs_team_b_YYYY-MM-DD (URL-safe, no spaces).
    Invalid or expired match_key → fallback with Top Edge Picks button.
    """
    if match_key.startswith("edge_"):
        log.warning(
            "DEEPLINK REJECT: edge_ prefix not produced by any live surface: %r",
            match_key,
        )
        await _dl_send_edge_no_longer_available(update, ctx, match_key)
        return

    import re as _re_dl
    if not _re_dl.match(r"^[a-zA-Z0-9_-]+$", match_key):
        await update.message.reply_text(
            "⚠️ That edge link doesn't look right. Here's what's live now:",
            parse_mode=ParseMode.HTML,
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("💎 Edge Picks", callback_data="hot:go"),
            ]]),
        )
        return

    # Decode tier suffix appended by alerts_direct.post_to_alerts at post time.
    # This preserves the tier used when the alert was posted even if the scraper
    # later recalculates the edge_results row with a different tier.
    _dl_tier_override: str | None = None
    for _sfx in ("_diamond", "_gold", "_silver", "_bronze"):
        if match_key.endswith(_sfx):
            _dl_tier_override = _sfx[1:]
            match_key = match_key[:-len(_sfx)]
            break

    # Load canonical tip dict — same format as hot tips list (includes bookmaker_key,
    # sport_key, odds_by_bookmaker, edge_v2, league_key needed by _enrich_tip_for_card).
    _dl_tip: dict | None = None
    _dl_tier = _dl_tier_override or "gold"
    try:
        _dl_seed = await asyncio.wait_for(
            asyncio.to_thread(_load_tips_from_edge_results, 100, True),
            timeout=5.0,
        )
        for _dl_candidate in _dl_seed:
            if (_dl_candidate.get("match_id") or _dl_candidate.get("match_key") or "") == match_key:
                _dl_tip = {**_dl_candidate, "match_key": match_key}
                # Only use DB tier if no override was encoded in the deeplink URL.
                if not _dl_tier_override:
                    _dl_tier = (_dl_tip.get("display_tier") or _dl_tip.get("edge_tier") or "gold").lower()
                # Stamp the final tier into the tip dict so card rendering uses it.
                _dl_tip["display_tier"] = _dl_tier
                _dl_tip["edge_tier"] = _dl_tier
                _dl_tip["edge_rating"] = _dl_tier
                break
    except Exception as _dl_exc:
        log.warning("card_deeplink: canonical tip lookup failed for %s: %s", match_key, _dl_exc)

    # Fallback for settled/expired edges not returned by _load_tips_from_edge_results
    if _dl_tip is None:
        try:
            from scrapers.db_connect import connect_odds_db as _dl_conn_fn
            from scrapers.edge.edge_config import DB_PATH as _dl_db
            _dl_conn = _dl_conn_fn(_dl_db)
            _dl_conn.row_factory = lambda c, r: dict(zip([col[0] for col in c.description], r))
            try:
                _dl_row = _dl_conn.execute(
                    "SELECT match_key, edge_tier, bet_type, recommended_odds, bookmaker, "
                    "predicted_ev, league, match_date, result, composite_score, confirming_signals "
                    "FROM edge_results WHERE match_key = ? "
                    "ORDER BY result IS NULL DESC, recommended_at DESC LIMIT 1",
                    (match_key,),
                ).fetchone()
            finally:
                _dl_conn.close()
            if _dl_row:
                # Only use DB tier if no override was encoded in the deeplink URL.
                if not _dl_tier_override:
                    _dl_tier = (_dl_row.get("edge_tier") or "gold").lower()
                _dl_home, _dl_away = _teams_from_vs_event_id(match_key)
                _dl_ok_raw = (_dl_row.get("bet_type") or "Home Win")
                _dl_ok_key = _dl_ok_raw.lower().replace(" win", "").replace(" ", "")
                _dl_ok_display = (
                    _display_team_name(_dl_home.lower().replace(" ", "_")) if _dl_ok_key == "home"
                    else _display_team_name(_dl_away.lower().replace(" ", "_")) if _dl_ok_key == "away"
                    else "Draw"
                )
                _dl_bk_key = (_dl_row.get("bookmaker") or "").strip().lower()
                _dl_rec_odds = float(_dl_row.get("recommended_odds") or 0)
                _dl_tip = {
                    "match_id": match_key, "match_key": match_key,
                    "home_team": _dl_home, "away_team": _dl_away,
                    "outcome": _dl_ok_display, "outcome_key": _dl_ok_key,
                    "edge_tier": _dl_tier, "display_tier": _dl_tier, "edge_rating": _dl_tier,
                    "odds": _dl_rec_odds,
                    "bookmaker": _display_bookmaker_name(_dl_bk_key),
                    "bookmaker_key": _dl_bk_key,
                    "ev": float(_dl_row.get("predicted_ev") or 0),
                    "edge_score": float(_dl_row.get("composite_score") or 0),
                    "confirming_signals": int(_dl_row.get("confirming_signals") or 0),
                    "odds_by_bookmaker": {_dl_bk_key: _dl_rec_odds} if _dl_bk_key and _dl_rec_odds > 0 else {},
                    "edge_v2": {
                        "composite_score": float(_dl_row.get("composite_score") or 0),
                        "edge_pct": float(_dl_row.get("predicted_ev") or 0),
                        "outcome": _dl_row.get("bet_type", "home"),
                        "confirming_signals": int(_dl_row.get("confirming_signals") or 0),
                    },
                }
        except Exception as _dl_fb_exc:
            log.warning("card_deeplink: fallback DB lookup failed for %s: %s", match_key, _dl_fb_exc)

    _user_tier = await get_effective_tier(user_id)

    # Send a loading message, then replace with the rendered card photo
    _dl_loading = None
    try:
        _dl_loading = await update.message.reply_text("⚡ Loading edge…")
    except Exception:
        pass

    if not _dl_tip:
        log.info(
            "DEEPLINK EMPTY-TIP: routing %r to edge-no-longer-available fallback",
            match_key,
        )
        if _dl_loading:
            try:
                await _dl_loading.delete()
            except Exception:
                pass
        await _dl_send_edge_no_longer_available(update, ctx, match_key)
        return

    try:
        _dl_tip_for_render = _dl_tip
        _dl_tip_enriched = await asyncio.wait_for(
            asyncio.to_thread(_enrich_tip_for_card, _dl_tip_for_render, match_key),
            timeout=10.0,
        )
        _dl_data = build_edge_detail_data(_dl_tip_enriched)
        # FIX-NARRATIVE-AIBREAKDOWN-REGRESSION-01: alerts deep-link entry — gate button on
        # narrative cache presence so users landing from DM alerts see AI Breakdown too.
        _dl_has_narrative = await asyncio.to_thread(_has_any_cached_narrative, match_key)
        _dl_btns = _build_game_buttons(
            [_dl_tip_for_render], match_key, user_id,
            source="alerts_deeplink", user_tier=_user_tier,
            edge_tier=_dl_tier, back_page=0,
            back_cb_override="hot:go",
            has_narrative=_dl_has_narrative,
        )
        _dl_markup = InlineKeyboardMarkup(_dl_btns)
        _dl_fallback = (
            f"<b>{h(_dl_tip_for_render.get('home_team', ''))} vs "
            f"{h(_dl_tip_for_render.get('away_team', ''))}</b>"
        )
        if _dl_loading:
            try:
                await _dl_loading.delete()
            except Exception:
                pass
        await send_card_or_fallback(
            bot=ctx.bot, chat_id=update.effective_chat.id,
            template="edge_detail.html", data=_dl_data,
            text_fallback=_dl_fallback, markup=_dl_markup,
        )
        return
    except Exception as _dl_card_err:
        log.warning("card_deeplink: card pipeline failed for %s: %s", match_key, _dl_card_err)

    # Fallback: show Top Edge Picks if card pipeline failed
    if _dl_loading:
        try:
            await _dl_loading.delete()
        except Exception:
            pass
    await _dl_send_edge_no_longer_available(update, ctx, match_key)


_WELCOME_IMG_PATH = pathlib.Path("/home/paulsportsza/assets/welcome/welcome_today.png")
_FALLBACK_IMG_PATH = pathlib.Path("/home/paulsportsza/assets/welcome/fallback.png")
_WELCOME_PICK_JSON = pathlib.Path("/home/paulsportsza/assets/welcome/welcome_pick.json")


def _welcome_img_path() -> pathlib.Path | None:
    """Return the freshest welcome image path, or None if unavailable."""
    import datetime as _dt
    if _WELCOME_IMG_PATH.exists():
        age_h = (_dt.datetime.now().timestamp() - _WELCOME_IMG_PATH.stat().st_mtime) / 3600
        if age_h <= 30:
            return _WELCOME_IMG_PATH
        log.warning("welcome_today.png stale (%.1fh) — using fallback", age_h)
    if _FALLBACK_IMG_PATH.exists():
        return _FALLBACK_IMG_PATH
    return None


# Welcome pick — cached 1h, only Gold/Diamond
_welcome_pick_cache: dict | None = None
_welcome_pick_ts: float = 0.0
_WELCOME_PICK_TTL = 3600


def _load_welcome_pick() -> dict | None:
    """Return the pick used to generate today's welcome image (sync, cached 1h).

    Primary path: reads welcome_pick.json sidecar written by generate_welcome_image.py.
    This guarantees the button always refers to the exact same match as the hero image.
    Fallback: DB query (Diamond/Gold) for backward compat when sidecar is absent/stale.
    """
    global _welcome_pick_cache, _welcome_pick_ts
    import time
    now = time.time()
    if _welcome_pick_ts > 0 and now - _welcome_pick_ts < _WELCOME_PICK_TTL:
        return _welcome_pick_cache
    # Primary: sidecar written by publisher/generate_welcome_image.py
    if _WELCOME_PICK_JSON.exists():
        import json as _json
        try:
            _age_h = (now - _WELCOME_PICK_JSON.stat().st_mtime) / 3600
            if _age_h <= 30:
                pick = _json.loads(_WELCOME_PICK_JSON.read_text())
                if pick.get("match_key"):
                    log.debug("_load_welcome_pick: sidecar hit (%s)", pick.get("match_key"))
                    _welcome_pick_cache = pick
                    _welcome_pick_ts = now
                    return pick
        except Exception as exc:
            log.debug("_load_welcome_pick sidecar failed: %s", exc)
    # Fallback: DB query (pre-sidecar compat / sidecar absent)
    try:
        from scrapers.db_connect import connect_odds_db
        from scrapers.edge.edge_config import DB_PATH
        from datetime import datetime, timedelta
        from zoneinfo import ZoneInfo
        _sast = ZoneInfo("Africa/Johannesburg")
        today = datetime.now(_sast).date().isoformat()
        yesterday = (datetime.now(_sast).date() - timedelta(days=1)).isoformat()
        conn = connect_odds_db(DB_PATH)
        conn.row_factory = lambda cur, row: dict(zip([c[0] for c in cur.description], row))
        _order = (
            "CASE edge_tier WHEN 'diamond' THEN 1 WHEN 'gold' THEN 2 ELSE 3 END, "
            "confirming_signals DESC, composite_score DESC"
        )
        pick = None
        for _date in [today, yesterday]:
            pick = conn.execute(
                "SELECT match_key, edge_tier FROM edge_results "
                f"WHERE match_date = ? AND edge_tier IN ('diamond', 'gold') "
                f"ORDER BY {_order} LIMIT 1",
                (_date,),
            ).fetchone()
            if pick:
                break
        conn.close()
        log.debug("_load_welcome_pick: DB fallback (%s)", pick and pick.get("match_key"))
        _welcome_pick_cache = pick
        _welcome_pick_ts = now
        return pick
    except Exception as exc:
        log.debug("_load_welcome_pick failed: %s", exc)
        return _welcome_pick_cache


def _load_edge_tip_by_key(match_key: str) -> dict | None:
    """Slow-path: load a single edge tip from edge_results by match_key.

    Used when menu:pick handler cannot find the pick in any hot-tips cache
    (e.g. pick is settled, or is a silver-tier pick not in the D/G hot list).
    Unlike _load_tips_from_edge_results() this does NOT filter by result IS NULL,
    so it works for yesterday's settled picks too.
    """
    if not match_key:
        return None
    try:
        import re as _re_etk
        from scrapers.db_connect import connect_odds_db as _etk_conn
        from scrapers.edge.edge_config import DB_PATH as _etk_db
        conn = _etk_conn(_etk_db)
        conn.row_factory = lambda cur, row: dict(zip([c[0] for c in cur.description], row))
        row = conn.execute(
            "SELECT match_key, edge_id, edge_tier, composite_score, bet_type, "
            "recommended_odds, bookmaker, predicted_ev, league, match_date, "
            "confirming_signals "
            "FROM edge_results WHERE match_key = ? "
            "ORDER BY CASE WHEN result IS NULL THEN 0 ELSE 1 END, id DESC LIMIT 1",
            (match_key,),
        ).fetchone()
        conn.close()
        if not row:
            return None
        mk = row["match_key"] or ""
        mk_no_date = _re_etk.sub(r"_\d{4}-\d{2}-\d{2}$", "", mk)
        if "_vs_" in mk_no_date:
            _h, _a = mk_no_date.split("_vs_", 1)
        else:
            _h = _a = mk_no_date
        return {
            **row,
            "match_id": mk,
            "event_id": mk,
            "home_team": _display_team_name(_h),
            "away_team": _display_team_name(_a),
            "edge_rating": row.get("edge_tier", "silver"),
            "display_tier": row.get("edge_tier", "silver"),
            "ev": float(row.get("predicted_ev") or 0),
            "tier": row.get("edge_tier", "silver"),
        }
    except Exception as exc:
        log.debug("_load_edge_tip_by_key failed for %s: %s", match_key, exc)
        return None


async def _welcome_kb(user_id: int) -> InlineKeyboardMarkup:
    """Build the welcome screen keyboard with a tier-gated edge pick button when available."""
    rows: list[list[InlineKeyboardButton]] = [
        [InlineKeyboardButton(_DIAMOND_EDGE_PICKS, callback_data="hot:go")],
        [InlineKeyboardButton("⚽ My Matches", callback_data="yg:all:0")],
        [
            InlineKeyboardButton("📖 Guide", callback_data="guide:menu"),
            InlineKeyboardButton("⚙️ Settings", callback_data="settings:home"),
        ],
        [InlineKeyboardButton("🏠 Community", url="https://t.me/MzansiEdge")],
    ]

    # Only add pick button when the daily image (not fallback) is showing
    if _welcome_img_path() == _WELCOME_IMG_PATH:
        pick = await asyncio.to_thread(_load_welcome_pick)
        if pick:
            edge_tier = (pick.get("edge_tier") or "gold").lower()
            match_key = pick.get("match_key", "")
            vs_part = match_key.rsplit("_", 1)[0]
            if "_vs_" in vs_part:
                home_slug, away_slug = vs_part.split("_vs_", 1)
                home = home_slug.replace("_", " ").title()
                away = away_slug.replace("_", " ").title()
            else:
                home, away = vs_part.replace("_", " ").title(), ""

            user_tier = await get_effective_tier(user_id)
            from tier_gate import get_edge_access_level
            access = get_edge_access_level(user_tier, edge_tier)
            tier_emoji = {"diamond": "💎", "gold": "🥇", "silver": "🥈", "bronze": "🥉"}.get(edge_tier, "🥇")
            tier_pretty = {"diamond": "Diamond", "gold": "Gold", "silver": "Silver", "bronze": "Bronze"}.get(edge_tier, "Gold")

            if access in ("full", "partial"):
                btn_text = f"{tier_emoji} View Edge of The Day ↗"
                btn_cb = "menu:pick"
            else:
                btn_text = f"🔒 {tier_emoji} View Edge of The Day"
                btn_cb = "menu:pick_lock"

            rows.insert(0, [InlineKeyboardButton(btn_text, callback_data=btn_cb)])

    return InlineKeyboardMarkup(rows)


