_SMART_BTN_MAX = 20  # Telegram mobile truncation threshold (chars)


def smart_abbreviate(name: str, max_len: int = _SMART_BTN_MAX) -> str:
    """Abbreviate a team name only when it would truncate on mobile buttons.

    Full name shown when len(name) <= max_len. Otherwise first word kept
    full, remaining words reduced to initial + '.'.
    """
    if len(name) <= max_len:
        return name
    parts = name.split()
    if len(parts) == 1:
        return name[:max_len]
    return parts[0] + " " + " ".join(p[0] + "." for p in parts[1:])


def _abbreviate_btn(name: str, max_len: int = 8) -> str:
    """Abbreviate team name for inline button text (max ~8 chars)."""
    if name in _BTN_ABBREVS:
        return _BTN_ABBREVS[name]
    # Try config abbreviations
    abbr = config.TEAM_ABBREVIATIONS.get(name)
    if abbr:
        return abbr
    # Short names stay as-is
    if len(name) <= max_len:
        return name
    # Multi-word: take first 3 chars of first 2 words
    words = name.split()
    if len(words) >= 2:
        return " ".join(w[:3] for w in words[:2])
    return name[:max_len]


def _display_team_name(key: str) -> str:
    """Convert odds.db normalised key to display name: 'mamelodi_sundowns' → 'Mamelodi Sundowns'."""
    try:
        from scrapers.odds_normaliser import display_name
        return display_name(key)
    except (ImportError, Exception):
        return key.replace("_", " ").title()


def _display_bookmaker_name(key: str) -> str:
    """Convert bookmaker key to display name."""
    return _BK_DISPLAY.get(key, key.title())


# Module-level verdict content blacklist — applied at both generation and serve time
# (VERDICT-FIX-02: refactored from local var in _generate_verdict to module level)
_VERDICT_BLACKLIST = [
    "home advantage", "away advantage",
    "historically", "tradition", "traditionally",
    "derby", "rivalry",
    "big game", "big match",
    "relegation battle", "title race",
    "form suggests", "expected to",
    "known for", "famous for",
    "ev edge", "ev%", "expected value",
    # QF-3 (2026-04-24) W84-Q9 regression restore — audit found 2 live cards leaked this phrase
    "structural gap",
    "the home side", "the away side",
    # BUILD-CARD-FIX-01: banned staking/hedge language
    "measured lean",
    "keep stakes controlled",
    "stay proportionate",
    "factor that in",
    "factor this in",
    "small stake",
    "proceed with caution",
    "worth monitoring",
    "keep an eye on",
    "keep stakes",
    "stake manageable",
    "size your stake",
    "limit your stake",
    # BUILD-VERDICT-FLOOR-01 / P0-HOTFIX-LEAN-REGEX 2026-04-24: substring " lean" removed —
    # replaced with _VERDICT_BLACKLIST_RE below. Catches LLM-voice forms ("I lean toward",
    # "lean on home") while allowing SA sports noun usage ("the lean here", "is the lean").
    # FIX-D1-VERDICT-BLACKLIST-01: import LLM meta-markers from narrative_spec (single source of truth)
    *_LLM_META_MARKERS,
]

# P0-HOTFIX-LEAN-REGEX 2026-04-24: regex companion to _VERDICT_BLACKLIST.
# Targets LLM-voice "lean" forms (verb + first-person/model self-reference + directional
# phrasing) while allowing SA sports noun usage ("the lean here", "is the lean",
# "Arsenal is the lean at 1.45"). Pure style gate — factual accuracy is enforced by
# _fact_check_verdict, validate_diamond_price_prefix, validate_manager_names, DERIVED CLAIMS
# check, BANNED_TRIVIAL_VERDICT_TEMPLATES, and tier length floors, all independent of this.
_VERDICT_BLACKLIST_RE = re.compile(
    r"\b(?:I|we|my|our|the\s+model)\s+leans?\b|\bleans?\s+(?:toward|towards|on|into|against|heavily)\b",
    re.IGNORECASE,
)

# BUILD-VERDICT-RENDER-FIXES-01: detect orphan "Back X." sentence at end of verdict
_ORPHAN_BACK_RE = re.compile(
    r'\.\s+(Back (?:the )?[A-Z][\w\' \-]+\.)\s*$'
)

# BUILD-SONNET-BURN-FIX-03 FIX-1: cap shape-guard Sonnet retry at 1 per match per hour
_SHAPE_GUARD_RETRY_TIMES: dict[str, float] = {}
_SHAPE_GUARD_RETRY_TTL = 3600  # seconds


