def _fact_check_verdict(verdict: str, spec: dict) -> str | None:
    """PIPELINE-BUILD-01 Task 3: Strip hallucination patterns from verdict output.

    Returns cleaned verdict, or None if >50% of content was stripped
    (caller should fall back to deterministic baseline).
    """
    import re as _re
    if not verdict:
        return None

    _HALLUCINATION_PATTERNS = [
        _re.compile(r"hasn't (beaten|won|scored) .{3,30} since \d{4}", _re.IGNORECASE),
        _re.compile(r"\btraditionally\b", _re.IGNORECASE),
        _re.compile(r"\bhistorically\b", _re.IGNORECASE),
        _re.compile(r"\bknown for\b", _re.IGNORECASE),
        _re.compile(r"\bfamous for\b", _re.IGNORECASE),
        _re.compile(r"\btends to\b", _re.IGNORECASE),
        _re.compile(r"\busually\b", _re.IGNORECASE),
        _re.compile(r"\btypically\b", _re.IGNORECASE),
        _re.compile(r"\balways\b", _re.IGNORECASE),
        _re.compile(r"\blast time they met\b", _re.IGNORECASE),
        _re.compile(r"\b(manager|coach|gaffer)\b", _re.IGNORECASE),
        _re.compile(r"\btravel fatigue\b", _re.IGNORECASE),
        _re.compile(r"\b(stadium|bridge|park|ground|arena|bowl|oval|field|centre|center)\b", _re.IGNORECASE),
        _re.compile(r"\b[A-Z][a-z]+ (Bridge|Park|Ground|Stadium|Arena|Field|Bowl|Oval|Centre)\b"),
    ]

    # SA conversational phrases — never strip sentences containing these
    _SA_SLANG = {"bru", "the move", "the play", "doesn't lie", "sort it out", "the call"}

    original_len = len(verdict)
    sentences = _re.split(r'(?<=[.!?])\s+', verdict.strip())
    kept: list[str] = []
    for sentence in sentences:
        sentence_lower = sentence.lower()
        if any(slang in sentence_lower for slang in _SA_SLANG):
            kept.append(sentence)
            continue
        if any(pat.search(sentence) for pat in _HALLUCINATION_PATTERNS):
            log.warning("_fact_check_verdict: stripped '%s'", sentence[:60])
            continue
        kept.append(sentence)

    if not kept:
        return None

    cleaned = " ".join(kept)
    stripped_ratio = 1 - (len(cleaned) / max(original_len, 1))
    if stripped_ratio > 0.5:
        log.warning(
            "_fact_check_verdict: >50%% stripped (%.0f%%), falling back to deterministic",
            stripped_ratio * 100,
        )
        return None
    return cleaned


def _cap_verdict(text: str, limit: int = 300) -> str:
    """BUILD-VERDICT-CAP-01 / BUILD-EDGE-CARD-INJURY-TO-MYMATCHES-01: Truncate verdict to word boundary at limit chars."""
    if len(text) > limit:
        text = text[:limit].rsplit(" ", 1)[0].rstrip(",. ")
    return text


def _strip_markdown(text: str) -> str:
    """BUILD-SANITIZER-MARKDOWN-STRIP-01: Strip markdown formatting from verdict text.

    Applied BEFORE _fix_orphan_back() in both verdict generators.
    Order matters: strip markdown first, then orphan-back fix (orphan-back
    works on prose, not markdown-decorated text).

    Strips: bold (**x** / __x__ → x), italic (*x* / _x_ → x),
    headers (# at start of line → removed), backticks (`x` → x),
    bullets at line start (- x or * x → x), blockquotes (> x → x).
    Preserves: em dashes —, quotes, apostrophes, parentheses, ?!
    """
    if not text:
        return text
    # Bold: **x** → x
    text = re.sub(r'\*\*(.+?)\*\*', r'\1', text)
    # Bold: __x__ → x
    text = re.sub(r'__(.+?)__', r'\1', text)
    # Italic: *x* → x (not touching **)
    text = re.sub(r'(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)', r'\1', text)
    # Italic: _x_ → x (word-boundary guard)
    text = re.sub(r'(?<!\w)_(.+?)_(?!\w)', r'\1', text)
    # Headers: # ## ### ... at start of line → removed
    text = re.sub(r'^#{1,6}\s*', '', text, flags=re.MULTILINE)
    # Backticks: `x` → x
    text = re.sub(r'`(.+?)`', r'\1', text)
    # Bullets at line start: - x or * x → x (not mid-line *)
    text = re.sub(r'^[\-\*]\s+', '', text, flags=re.MULTILINE)
    # Blockquotes: > x → x
    text = re.sub(r'^>\s*', '', text, flags=re.MULTILINE)
    return text


def _fix_orphan_back(verdict: str, char_budget: int = 1024) -> str:
    """BUILD-VERDICT-RENDER-FIXES-01: Join orphan 'Back X.' to previous sentence.

    If verdict ends with a standalone 'Back X.' clause (preceded by '. '), join it
    to the previous sentence with an em dash. Only strip if joining exceeds
    char_budget (never in practice — verdict max is 300 chars).
    """
    m = _ORPHAN_BACK_RE.search(verdict)
    if not m:
        return verdict
    # Join: replace '. Back X.' with ' — Back X.'
    joined = _ORPHAN_BACK_RE.sub(lambda _m: f' \u2014 {_m.group(1)}', verdict).strip()
    if len(joined) <= char_budget:
        return joined
    # Strip: remove the 'Back X.' clause entirely
    stripped = verdict[:m.start()].rstrip() + "."
    return stripped


def _trim_to_last_sentence(text: str, max_chars: int = 140) -> str:
    """BUILD-VERDICT-TRUNCATE-02 / -HARDEN-03 / -HARDEN-04: Trim Sonnet output to last
    complete sentence within max_chars.

    1. Sentence-terminal boundary (.!?) at position >= 20 → trim there.
    2. Em-dash (—) or en-dash (–) after position 60 → trim AT dash, append ".."
       (BUILD-VERDICT-TRIM-HARDEN-04: dash-heavy single-sentence verdicts).
    3. No clean boundary → word-boundary fallback (parity with _cap_verdict).
    NEVER returns empty for non-empty input (HARDEN-03).
    """
    if not text:
        return ""
    text = text.strip()
    if not text:
        return ""
    if len(text) > max_chars:
        text = text[:max_chars]
    # 1. Sentence-terminal boundary — exclude decimal periods (digit.digit)
    period_matches = [i for i, c in enumerate(text)
                      if c == '.' and not (
                          i > 0 and text[i-1].isdigit()
                          and i + 1 < len(text) and text[i+1].isdigit()
                      )]
    other_terminals = [i for i, c in enumerate(text) if c in '!?']
    all_terminals = period_matches + other_terminals
    last = max(all_terminals) if all_terminals else -1
    if last >= 20:
        return text[:last + 1].strip()
    # 2. Em-dash / en-dash as soft boundary (BUILD-VERDICT-TRIM-HARDEN-04)
    last_dash = max(text.rfind('\u2014'), text.rfind('\u2013'))  # — and –
    if last_dash > 60:
        return text[:last_dash].rstrip() + ".."
    # 3. Fallback: word-boundary trim (parity with _cap_verdict)
    return text.rsplit(" ", 1)[0].rstrip(",. ").strip()


