def _normalise_mm_event_id(tip: dict, snapshot_match: dict) -> str:
    """Convert a snapshot entry's _event_id (may be Odds API UUID) to canonical match_key.

    Priority:
    1. ``tip["match_id"]`` when it looks like ``home_vs_away_YYYY-MM-DD`` (already canonical).
    2. Build from snapshot home/away + _commence_time via ``build_match_id()``.
    3. Return ``""`` with a warning when neither source yields a canonical key.
    """
    # 1 — tip already carries canonical match_id
    existing = tip.get("match_id") or ""
    if existing and "_vs_" in existing:
        return existing

    # 2 — build from snapshot fields
    home = snapshot_match.get("home", "")
    away = snapshot_match.get("away", "")
    commence_time = snapshot_match.get("_commence_time", "")
    if home and away:
        try:
            from services.odds_service import build_match_id as _bmi
            key = _bmi(home, away, commence_time)
            if key:
                return key
        except Exception as exc:
            log.warning("_normalise_mm_event_id: build_match_id failed for %s vs %s: %s", home, away, exc)

    log.warning("_normalise_mm_event_id: could not resolve canonical key for event_id=%s home=%s away=%s",
                snapshot_match.get("_event_id", ""), home, away)
    return ""


# ENRICH-FIX-01 helpers ──────────────────────────────────────────────────────

def _enrich_query_form(conn, team_key: str, limit: int = 5) -> list:
    """Query match_results for last N matches of a team. Returns list of dicts."""
    if conn is None or not team_key:
        return []
    try:
        rows = conn.execute(
            "SELECT home_team, away_team, home_score, away_score "
            "FROM match_results "
            "WHERE home_team = ? OR away_team = ? "
            "ORDER BY match_date DESC LIMIT ?",
            (team_key, team_key, limit),
        ).fetchall()
        return [{"home": r[0], "away": r[1], "home_score": r[2], "away_score": r[3]} for r in rows]
    except Exception:
        return []


# Keys where the bookmaker short name differs completely from match_results canonical name.
# Mirrors _STATS_KEY_ALIASES in card_pipeline.py — keep in sync on additions.
_H2H_KEY_ALIASES: dict[str, str] = {
    "wolves": "wolverhampton_wanderers",
    "atletico_madrid": "atl_tico_madrid",
    "reds": "queensland_reds",
    "waratahs": "new_south_wales_waratahs",
    "man_city": "manchester_city",          # 'man_city' is not a substring of 'manchester_city'
    # 'blues' and 'chiefs' are stored as-is in match_results — no alias needed.
}


def _enrich_query_h2h(conn, home_key: str, away_key: str, limit: int = 5) -> list:
    """Query match_results for H2H meetings between two teams.

    Uses LIKE %key% patterns so short bookmaker keys (e.g. 'bournemouth') match
    canonical match_results names (e.g. 'afc_bournemouth').  Completely-different
    aliases (e.g. wolves→wolverhampton_wanderers) are resolved via _H2H_KEY_ALIASES
    before pattern construction.
    """
    if conn is None or not home_key or not away_key:
        return []
    hk = _H2H_KEY_ALIASES.get(home_key.lower(), home_key.lower())
    ak = _H2H_KEY_ALIASES.get(away_key.lower(), away_key.lower())
    hp, ap = f"%{hk}%", f"%{ak}%"
    try:
        rows = conn.execute(
            "SELECT home_team, away_team, home_score, away_score "
            "FROM match_results "
            "WHERE (home_team LIKE ? AND away_team LIKE ?) OR (home_team LIKE ? AND away_team LIKE ?) "
            "ORDER BY match_date DESC LIMIT ?",
            (hp, ap, ap, hp, limit),
        ).fetchall()
        return [{"home": r[0], "away": r[1], "home_score": r[2], "away_score": r[3]} for r in rows]
    except Exception:
        return []


def _enrich_format_form(form_list: list) -> str:
    """Convert W/D/L list to plain English form summary."""
    if not form_list:
        return ""
    n = len(form_list)
    wins = form_list.count("W")
    draws = form_list.count("D")
    losses = form_list.count("L")
    if wins >= n - 1:
        return f"won {wins} of their last {n}"
    if losses >= n - 1:
        return f"lost {losses} of their last {n}"
    if draws >= n - 1:
        return f"drawn {draws} of their last {n}"
    if wins > losses:
        return f"won {wins}, drawn {draws}, lost {losses} in their last {n}"
    return f"won {wins}, drawn {draws}, lost {losses} in their last {n}"


def _enrich_format_h2h(rows: list, home_key: str, away_key: str) -> str:
    """Format H2H rows as '5 meetings: 2W 1D 2A' string."""
    played = hw = d = aw = 0
    hk = home_key.lower()
    for r in rows:
        hs = r.get("home_score")
        as_ = r.get("away_score")
        if hs is None or as_ is None:
            continue
        try:
            hs_i, as_i = int(hs), int(as_)
        except (TypeError, ValueError):
            continue
        played += 1
        home_is_hk = hk in (r.get("home") or "").lower()
        if hs_i == as_i:
            d += 1
        elif home_is_hk:
            if hs_i > as_i:
                hw += 1
            else:
                aw += 1
        else:
            if as_i > hs_i:
                hw += 1
            else:
                aw += 1
    if not played:
        return ""
    return f"{played} meetings: {hw}W {d}D {aw}A"


# ────────────────────────────────────────────────────────────────────────────

def _enrich_tip_for_card(tip: dict, match_key: str = "") -> dict:
    """Enrich a tip/match dict with verified DB data for card rendering.

    BUILD-CARDWIRE: Calls build_verified_data_block() once per match and maps
    the result into the fields expected by build_edge_detail_data() and
    build_match_detail_data(). Synchronous — wrap in asyncio.to_thread() inside
    async handlers.

    Returns a shallow copy of tip with enrichment merged in. Empty sections
    are set to empty list (not None) so Jinja2 {% if signals %} blocks hide
    them gracefully rather than throwing errors.
    """
    from card_pipeline import (
        build_verified_data_block as _bvdb,
        _compute_team_form,
        _compute_h2h,
        _compute_match_detail_stats,
        _split_injuries,
        _compute_signals,
        _ro_conn,
        _ODDS_DB_PATH,
        _team_display,
    )
    import re as _re
    enriched = dict(tip)

    if not match_key:
        return enriched

    try:
        verified = _bvdb(match_key)
    except Exception as exc:
        log.exception("_enrich_tip_for_card: build_verified_data_block failed for %s", match_key)
        return enriched

    home_key = verified.get("home_key", "")
    away_key = verified.get("away_key", "")
    results = verified.get("results") or []
    injuries = verified.get("injuries") or []

    # 1) Signals — 6-key dict {price_edge, form, movement, market, tipster, injury}
    enriched["signals"] = _compute_signals(tip, verified)

    # 2) all_odds — bookmaker comparison list for edge detail card
    outcome_key = (tip.get("outcome_key") or "home").lower()
    if outcome_key not in ("home", "away", "draw"):
        outcome_key = "home"
    raw_odds = verified.get("odds") or {}
    all_odds = []
    for bk, odds_data in raw_odds.items():
        v = odds_data.get(outcome_key) or 0
        try:
            v = float(v)
        except (TypeError, ValueError):
            continue
        if v > 1.0:
            all_odds.append({"bookie": _display_bookmaker_name(bk), "odds": v})
    # CARD-FIX-K: Fall back to odds_by_bookmaker when odds_snapshots has no data
    # (match >48h old, rugby/cricket not scraped, or key mismatch).
    if len(all_odds) < 2 and tip.get("odds_by_bookmaker"):
        for _obk, _ov in tip["odds_by_bookmaker"].items():
            try:
                _ov = float(_ov)
            except (TypeError, ValueError):
                continue
            if _ov > 1.0:
                _od = _display_bookmaker_name(_obk)
                if not any(o["bookie"] == _od for o in all_odds):
                    all_odds.append({"bookie": _od, "odds": _ov})
    # Deduplicate by display name — keep highest odds per bookmaker
    _seen_bk: dict[str, dict] = {}
    for o in all_odds:
        bk = o["bookie"]
        if bk not in _seen_bk or o["odds"] > _seen_bk[bk]["odds"]:
            _seen_bk[bk] = o
    all_odds = list(_seen_bk.values())
    # CARD-FIX-K: Use bookmaker_key (raw DB key) not bookmaker (display name) so that
    # _display_bookmaker_name maps correctly — tip["bookmaker"] already IS the display
    # name ("HWB"), passing it through _display_bookmaker_name returns "Hwb" (wrong).
    pick_bk_raw = (tip.get("bookmaker_key") or "").lower()
    if not pick_bk_raw:
        # bookmaker field may be a raw key if bookmaker_key wasn't populated
        pick_bk_raw = (tip.get("bookmaker") or "").lower()
    pick_bk_display = _display_bookmaker_name(pick_bk_raw)
    pick_odds = 0.0
    try:
        pick_odds = float(tip.get("odds") or 0)
    except (TypeError, ValueError):
        pass
    if pick_bk_raw and pick_odds > 1.0:
        if not any(o["bookie"] == pick_bk_display for o in all_odds):
            all_odds.append({"bookie": pick_bk_display, "odds": pick_odds, "is_pick": True})
    # Mark the pick bookmaker in existing entries
    for o in all_odds:
        if pick_bk_raw and o["bookie"] == pick_bk_display:
            o["is_pick"] = True
    # CARD-FIX-H Task 1 / CARD-FIX-K: chip selection — pick first, then 3 lowest others
    _pick_chips = [o for o in all_odds if o.get("is_pick")]
    _other_chips = [o for o in all_odds if not o.get("is_pick")]
    _other_chips.sort(key=lambda x: x["odds"])  # ascending = lowest first = worst
    enriched["all_odds"] = (_pick_chips + _other_chips)[:3]

    # 3) Form — last 5 results per team as ['W','D','L'] lists
    # CARD-REBUILD-04-02: asymmetric guard + most-recent-RIGHT reversal.
    _hf = _compute_team_form(results, home_key) if home_key else []
    _af = _compute_team_form(results, away_key) if away_key else []
    if not _hf or not _af:
        enriched["home_form"] = []
        enriched["away_form"] = []
    else:
        _fn = min(len(_hf), len(_af))
        enriched["home_form"] = _hf[:_fn][::-1]
        enriched["away_form"] = _af[:_fn][::-1]

    # 4) H2H — FIX 3 (CARD-REBUILD-03A): use evidence_pack for richer H2H (up to 5 meetings)
    _h2h_set = False
    try:
        from evidence_pack import _fetch_h2h_from_match_results as _ep_h2h
        _ep_league = (tip.get("league_key") or tip.get("league", "")).lower()
        _ep_sport = tip.get("sport_key") or tip.get("sport") or "soccer"
        _mm_parts = verified.get("matchup", "").split(" vs ", 1)
        _ep_home_name = _mm_parts[0].strip() if _mm_parts else ""
        _ep_away_name = _mm_parts[1].strip() if len(_mm_parts) > 1 else ""
        if home_key and away_key and _ep_league:
            _h2h_block = _ep_h2h(
                home_key, away_key, _ep_home_name, _ep_away_name,
                _ep_league, _ep_sport, limit=5,
            )
            if _h2h_block and _h2h_block.summary:
                _s = _h2h_block.summary
                enriched["h2h"] = {
                    "n": _s.get("total", 0),
                    "hw": _s.get("home_wins", 0),
                    "d": _s.get("draws", 0),
                    "aw": _s.get("away_wins", 0),
                }
                _h2h_set = True
    except Exception as _h2h_exc:
        log.debug("_enrich_tip_for_card: evidence_pack H2H failed (%s), falling back", _h2h_exc)
    if not _h2h_set:
        _h2h_fb = _compute_h2h(results, home_key, away_key)
        enriched["h2h"] = {
            "n": _h2h_fb.get("played", 0),
            "hw": _h2h_fb.get("hw", 0),
            "d": _h2h_fb.get("d", 0),
            "aw": _h2h_fb.get("aw", 0),
        }

    # ENRICH-FIX-01: Guarantee form/H2H fields before verdict call.
    # When _compute_team_form got no data (e.g. IPL, Super Rugby), query match_results
    # directly. If still empty, set fallback string so _generate_verdict never goes
    # meta-commentary on missing data.
    _fb_conn = None
    try:
        if not enriched.get("home_form") or not enriched.get("away_form"):
            _fb_conn = _ro_conn(_ODDS_DB_PATH)
            if not enriched.get("home_form"):
                _mr_home = _enrich_query_form(_fb_conn, home_key, limit=5)
                _hf_fb = _compute_team_form(_mr_home, home_key)
                if _hf_fb:
                    enriched["home_form"] = _hf_fb[::-1]
                else:
                    enriched["form_home_plain"] = "Form data unavailable"
            if not enriched.get("away_form"):
                _mr_away = _enrich_query_form(_fb_conn, away_key, limit=5)
                _af_fb = _compute_team_form(_mr_away, away_key)
                if _af_fb:
                    enriched["away_form"] = _af_fb[::-1]
                else:
                    enriched["form_away_plain"] = "Form data unavailable"
        _cur_h2h = enriched.get("h2h") or {}
        if not _cur_h2h.get("n"):
            if _fb_conn is None:
                _fb_conn = _ro_conn(_ODDS_DB_PATH)
            _h2h_hk = _H2H_KEY_ALIASES.get((home_key or "").lower(), home_key)
            _h2h_ak = _H2H_KEY_ALIASES.get((away_key or "").lower(), away_key)
            _h2h_rows = _enrich_query_h2h(_fb_conn, _h2h_hk, _h2h_ak, limit=5)
            _h2h_str = _enrich_format_h2h(_h2h_rows, home_key, away_key)
            if _h2h_str:
                _h2h_m = _re.match(r"(\d+) meetings: (\d+)W (\d+)D (\d+)A", _h2h_str)
                if _h2h_m:
                    enriched["h2h"] = {
                        "n": int(_h2h_m.group(1)),
                        "hw": int(_h2h_m.group(2)),
                        "d": int(_h2h_m.group(3)),
                        "aw": int(_h2h_m.group(4)),
                    }
            else:
                enriched["h2h_summary"] = "H2H data unavailable"
    except Exception as _fix01_exc:
        log.debug("_enrich_tip_for_card ENRICH-FIX-01 fallback failed: %s", _fix01_exc)
    finally:
        if _fb_conn is not None:
            try:
                _fb_conn.close()
            except Exception:
                pass

    # 5) Injuries — split by team into ['Player (status)'] lists
    home_inj, away_inj = _split_injuries(injuries, home_key, away_key)
    enriched["home_injuries"] = home_inj
    enriched["away_injuries"] = away_inj

    # 6) Confidence from edge_score (0-100)
    if not enriched.get("confidence") and tip.get("edge_score"):
        enriched["confidence"] = int(float(tip["edge_score"]))

    # 7) Fair value from probability estimate
    if not enriched.get("fair_value") and enriched.get("prob"):
        enriched["fair_value"] = int(float(enriched["prob"]))

    # 8) Best odds per outcome for match detail card (home_odds/draw_odds/away_odds + bookmakers)
    best = verified.get("best_odds") or {}
    if not enriched.get("home_odds") and best.get("home", {}).get("odds"):
        enriched["home_odds"] = best["home"]["odds"]
        enriched["home_bookie"] = _display_bookmaker_name(best["home"].get("bookmaker", ""))
    elif not enriched.get("home_odds") and enriched.get("odds_home"):
        enriched["home_odds"] = enriched["odds_home"]
    if not enriched.get("draw_odds") and best.get("draw", {}).get("odds"):
        enriched["draw_odds"] = best["draw"]["odds"]
        enriched["draw_bookie"] = _display_bookmaker_name(best["draw"].get("bookmaker", ""))
    elif not enriched.get("draw_odds") and enriched.get("odds_draw"):
        enriched["draw_odds"] = enriched["odds_draw"]
    if not enriched.get("away_odds") and best.get("away", {}).get("odds"):
        enriched["away_odds"] = best["away"]["odds"]
        enriched["away_bookie"] = _display_bookmaker_name(best["away"].get("bookmaker", ""))
    elif not enriched.get("away_odds") and enriched.get("odds_away"):
        enriched["away_odds"] = enriched["odds_away"]

    # 8b) Channel — removed (FIX-DSTV-CHANNEL-PERM-01). Channel display is permanently off.

    # 8d) KO time — BUILD-KO-TIME-FIX-01: sport-aware resolver with fixture-table fallbacks.
    # Never falls back to 'TBC' — returns empty string when no time data exists
    # (rugby date-only, mma date-only, etc.). Midnight-UTC sentinels are also dropped.
    # BUILD-CARD-RENDER-01 D2: call resolver whenever time is absent, even when
    # _bc_kickoff is set — it may be date-only (no time component) from the scraper.
    if not enriched.get("time"):
        try:
            _match_key = tip.get("match_id") or tip.get("match_key") or match_key or ""
            _sport = (
                tip.get("sport")
                or tip.get("sport_key")
                or enriched.get("sport")
                or "soccer"
            )
            _home_d = _team_display(home_key) if home_key else tip.get("home_team", "")
            _away_d = _team_display(away_key) if away_key else tip.get("away_team", "")
            _ct = tip.get("_commence_time") or tip.get("commence_time") or tip.get("starts_at") or ""
            _kd, _kt = _resolve_kickoff_time(
                sport=_sport,
                match_key=_match_key,
                home=_home_d,
                away=_away_d,
                commence_time=_ct,
                league=tip.get("league") or tip.get("league_key") or "",
            )
            if _kd and not enriched.get("date"):
                enriched["date"] = _kd
            if _kt:
                enriched["time"] = _kt
        except Exception as _ke:
            log.debug("_enrich_tip_for_card: _resolve_kickoff_time failed: %s", _ke)

    # 8e) Channel — BUILD-KO-SUPERSPORT-PRIMARY-01: supersport_scraper is the
    # primary authoritative source for broadcast channels across all sports.
    # Supersedes FIX-DSTV-CHANNEL-PERM-01 (channel was permanently off).
    if not enriched.get("channel"):
        try:
            _mk_ch = tip.get("match_id") or tip.get("match_key") or match_key or ""
            _home_ch = _team_display(home_key) if home_key else tip.get("home_team", "")
            _away_ch = _team_display(away_key) if away_key else tip.get("away_team", "")
            _league_ch = (tip.get("league") or tip.get("league_key") or "").lower()
            _ch, _ch_logo = _get_supersport_channel(_home_ch, _away_ch, _mk_ch, league=_league_ch)
            if _ch:
                enriched["channel"] = _ch
            if _ch_logo and not enriched.get("channel_logo_url"):
                enriched["channel_logo_url"] = _ch_logo
        except Exception as _ce:
            log.debug("_enrich_tip_for_card: _get_supersport_channel failed: %s", _ce)

    # 9) Pick name — outcome display for summary and detail cards
    if not enriched.get("pick"):
        enriched["pick"] = tip.get("outcome") or tip.get("home_team") or ""

    # 10) Verdict — PIPELINE-BUILD-01: check narrative_cache first, then generate
    tipster = verified.get("tipster") or {}
    if not enriched.get("verdict"):
        # Try cached verdict from narrative_cache (pre-computed by pregenerate_narratives)
        _cached_verdict = _get_cached_verdict(match_key)
        _use_cached_verdict = False
        if _cached_verdict and not _is_verdict_stale(_cached_verdict):
            # Serve-time staleness check: skip cached verdict if odds/bookie changed
            _cached_bk = _cached_verdict.get("cached_bookmaker", "")
            _cached_odds_val = _cached_verdict.get("cached_odds", 0.0)
            _current_bk = enriched.get("bookmaker") or tip.get("bookmaker") or ""
            _current_odds = float(enriched.get("odds") or tip.get("odds") or 0)
            _bk_mismatch = bool(_cached_bk and _current_bk and _cached_bk != _current_bk)
            _odds_mismatch = bool(
                _cached_odds_val and _current_odds
                and abs(_cached_odds_val - _current_odds) > 0.10  # BUILD-SONNET-BURN-FIX-03 FIX-2
            )
            # EV mismatch: cached verdict embedding a stale EV% should be regenerated
            _cached_ev = float(_cached_verdict.get("cached_ev") or 0)
            _current_ev = float(enriched.get("ev") or tip.get("ev") or tip.get("predicted_ev") or 0)
            _ev_mismatch = bool(
                _cached_ev and _current_ev
                and abs(_cached_ev - _current_ev) > 1.0  # BUILD-SONNET-BURN-FIX-03 FIX-2: 1.0% tolerance
            )
            # ODDS-FRESHNESS-01: force regeneration if same-day odds are >90 min stale
            _odds_age_stale = False
            _max_scraped_at = max(
                (v.get("scraped_at", "") for v in (verified.get("odds") or {}).values()),
                default="",
            )
            if _max_scraped_at:
                try:
                    from datetime import datetime, timezone
                    _oa_ts = datetime.fromisoformat(_max_scraped_at.replace("Z", "+00:00"))
                    _oa_mins = (datetime.now(timezone.utc) - _oa_ts).total_seconds() / 60
                    _today = datetime.now(timezone.utc).date().isoformat()
                    if _oa_mins > 90 and date_str == _today:
                        _odds_age_stale = True
                except Exception:
                    pass
            if _bk_mismatch or _odds_mismatch or _ev_mismatch or _odds_age_stale:
                log.info(
                    "VERDICT_STALE: %s%s%s%s for %s, regenerating",
                    "bookie_mismatch " if _bk_mismatch else "",
                    "odds_mismatch " if _odds_mismatch else "",
                    "ev_mismatch " if _ev_mismatch else "",
                    "odds_age_stale " if _odds_age_stale else "",
                    match_key,
                )
            else:
                _use_cached_verdict = True
        if _use_cached_verdict:
            _cv_text = _cached_verdict.get("verdict_html", "")
            # Serve-time content gate: apply blacklist to cached verdicts
            if (_VERDICT_BLACKLIST and any(p in _cv_text.lower() for p in _VERDICT_BLACKLIST)) or _VERDICT_BLACKLIST_RE.search(_cv_text):
                log.info("VERDICT_BLACKLISTED_CACHED: %s, will regenerate", match_key)
                _use_cached_verdict = False
            elif _cv_text:
                # INV-VERDICT-CONSTRAINED-FLOOR-01: serve-time tier-aware length floor.
                # Defence in depth — reject cached verdicts written before the
                # generator-side floor landed (pre-2026-04-21 rows). Forces
                # regeneration via the live path, which now enforces the floor.
                from narrative_spec import MIN_VERDICT_CHARS_BY_TIER as _MIN_BY_TIER
                _cv_tier = (tip.get("edge_tier") or enriched.get("edge_tier") or "bronze").lower()
                _cv_floor = _MIN_BY_TIER.get(_cv_tier, _MIN_BY_TIER["bronze"])
                if len(_cv_text.strip()) < _cv_floor:
                    log.info(
                        "VERDICT_UNDER_FLOOR_CACHED: %s tier=%s len=%d floor=%d, will regenerate",
                        match_key, _cv_tier, len(_cv_text.strip()), _cv_floor,
                    )
                    _use_cached_verdict = False
                else:
                    # FIX-KICKOFF-RELATIVE-01/D2: re-cap on serve — stale cache entries
                    # from older codepaths may exceed _VERDICT_MAX_CHARS.
                    enriched["verdict"] = _cap_verdict(_cv_text, limit=_VERDICT_MAX_CHARS)
            else:
                _use_cached_verdict = False
        if not _use_cached_verdict:
            # FIX-CARD-VERDICT-RECOMMENDATION-ALIGNMENT-01 (2026-05-02):
            # Card image and verdict text MUST reference the same recommended
            # bet. When the cached verdict is stale (odds/bookmaker/EV/outcome
            # drifted from the current edge_results row that the card image is
            # rendering from), regenerate from the LIVE tip instead of falling
            # back to the stale cache text. The pre-fix fallback re-served the
            # same stale verdict_html and caused 8/25 cards in
            # QA-LIVE-CARDS-EVERY-ACTIVE-01 to show a different team / odds /
            # bookmaker in the verdict than the card image displayed
            # (Brentford-vs-WestHam: card showed Brentford 1.91 @ PlayaBets;
            # verdict said West Ham 3.87 @ PlayaBets).
            #
            # Generation contract: build a NarrativeSpec from the LIVE tip
            # via build_narrative_spec(...) — the same path
            # _generate_narrative_v2() and the W82 pregen pipeline use — so
            # tier-aware verdict_action/verdict_sizing classification matches
            # the rest of the surface. Then render via _render_verdict(spec).
            # Zero LLM, deterministic, < 50ms.
            enriched["verdict"] = ""
            try:
                from narrative_spec import (
                    build_narrative_spec as _bns_align,
                    _render_verdict as _ns_render_verdict,
                )
                _live_tip = dict(enriched)
                # Ensure tier carries through to _extract_edge_data so
                # build_narrative_spec()'s TONE-BANDS-FIX block elevates the
                # spec to the badge-matching posture (e.g. Gold → lean
                # minimum, Diamond → strong/confident).
                if not _live_tip.get("display_tier") and not _live_tip.get("edge_rating"):
                    _live_tip["display_tier"] = (
                        tip.get("display_tier")
                        or tip.get("edge_rating")
                        or tip.get("edge_tier")
                        or enriched.get("edge_tier")
                        or "bronze"
                    )
                _live_home = enriched.get("home_team") or tip.get("home_team") or ""
                _live_away = enriched.get("away_team") or tip.get("away_team") or ""
                _live_sport = (
                    tip.get("sport") or tip.get("sport_key")
                    or enriched.get("sport") or "soccer"
                ).lower()
                _live_edge_data = _extract_edge_data(
                    [_live_tip], _live_home, _live_away,
                )
                _live_spec = _bns_align({}, _live_edge_data, [_live_tip], _live_sport)
                _fresh = _ns_render_verdict(_live_spec)
                if _fresh:
                    if _VERDICT_BLACKLIST and any(p in _fresh.lower() for p in _VERDICT_BLACKLIST):
                        log.info("VERDICT_FRESH_BLACKLISTED: %s, dropping", match_key)
                    else:
                        enriched["verdict"] = _cap_verdict(_fresh, limit=_VERDICT_MAX_CHARS)
            except Exception as _vfe:
                log.warning("FIX-CARD-VERDICT-RECOMMENDATION-ALIGNMENT-01 fresh_render_failed: %s %s", match_key, _vfe)
            if not enriched["verdict"]:
                log.warning("contract_violation=verdict_empty match_key=%s", match_key)
            # Store for next view (best-effort, fire-and-forget) — overwrites
            # the stale narrative_cache.verdict_html so subsequent views serve
            # the aligned verdict without re-rendering.
            if enriched["verdict"] and match_key:
                try:
                    _store_verdict_cache_sync(match_key, enriched["verdict"], enriched)
                except Exception:
                    pass  # Best-effort — don't block card rendering

    # 11) Top tipsters — FIX 4 (CARD-REBUILD-03A): individual source rows for template
    _tipster_rows = tipster.get("_rows") or []
    if _tipster_rows:
        enriched["top_tipsters"] = [
            {
                "source": row.get("source", ""),
                "pick": row.get("predicted_winner") or "",
                "confidence": row.get("confidence"),
            }
            for row in _tipster_rows if row.get("source")
        ][:4]

    # 12) Key Stats — BUILD-MY-MATCHES-02: Home Record / Away Record / Avg Score / Fair Value
    # Wired for match_detail path (mm:match callbacks). build_match_detail_data() reads
    # enriched["stats"]; build_edge_detail_data() uses key_stats from card_pipeline separately.
    try:
        _stats_sport = (tip.get("sport_key") or tip.get("sport") or "soccer").lower()
        _stats_league_raw = (tip.get("league_key") or tip.get("league") or "").lower()
        _stats_league = _CONFIG_TO_DB_LEAGUE.get(_stats_league_raw, _stats_league_raw)
        enriched["stats"] = _compute_match_detail_stats(
            match_key, home_key, away_key, _stats_sport, _stats_league, verified
        )
    except Exception as _stats_exc:
        log.debug("_enrich_tip_for_card: _compute_match_detail_stats failed: %s", _stats_exc)
        enriched.setdefault("stats", [])

    return enriched


def _truncate_form_bullets(bullets: list[str], match_ctx: dict | None) -> list[str]:
    """Truncate form strings in narrative bullets to games_played (W30-FORM).

    Edge V2 narrative bullets may show 10-char form strings from match_results
    for teams that have only played 3-5 games this season. This post-processes
    bullets using the authoritative games_played from ESPN standings.
    """
    if not match_ctx or not bullets:
        return bullets
    home = match_ctx.get("home_team", {})
    away = match_ctx.get("away_team", {})
    home_gp = home.get("games_played") or home.get("matches_played")
    away_gp = away.get("games_played") or away.get("matches_played")
    if not home_gp and not away_gp:
        return bullets
    result = []
    for b in bullets:
        text = b
        if home_gp:
            text = re.sub(
                r'H: ([WDLT]+)',
                lambda m: f"H: {m.group(1)[:home_gp]}" if len(m.group(1)) > home_gp else m.group(0),
                text,
            )
        if away_gp:
            text = re.sub(
                r'A: ([WDLT]+)',
                lambda m: f"A: {m.group(1)[:away_gp]}" if len(m.group(1)) > away_gp else m.group(0),
                text,
            )
        result.append(text)
    return result


def _normalize_fixture_token(value: str) -> str:
    """Normalise team/league labels for loose fixture matching."""
    import re

    return re.sub(r"[^a-z0-9]+", " ", (value or "").lower()).strip()


def _derive_pref_targets(prefs: list) -> tuple[set[str], set[str]]:
    """Return (team_names, league_keys) from stored sport preferences."""
    user_teams: set[str] = set()
    league_keys: set[str] = set()

    for pref in prefs:
        if pref.team_name:
            user_teams.add(pref.team_name)
        if pref.league:
            league_keys.add(pref.league)
            continue
        if not pref.team_name:
            continue

        inferred = config.TEAM_TO_LEAGUES.get(pref.team_name, [])
        if not inferred:
            canonical = config.TEAM_ALIASES.get(pref.team_name.lower(), "")
            if canonical:
                inferred = config.TEAM_TO_LEAGUES.get(canonical, [])
        sport_key = pref.sport_key or ""
        for league_key in inferred:
            if not sport_key or config.LEAGUE_SPORT.get(league_key) == sport_key:
                league_keys.add(league_key)

    return user_teams, league_keys


def _format_fixture_broadcast(channel_short: str = "", dstv_number: str = "") -> str:
    """Channel display permanently removed (FIX-DSTV-CHANNEL-PERM-01)."""
    return ""


async def _get_user_fixture_preview(
    user_id: int,
    limit: int = 3,
    days_ahead: int = 7,
) -> list[dict]:
    """Return up to `limit` relevant upcoming fixtures for a user from broadcast_schedule."""
    prefs = await db.get_user_sport_prefs(user_id)
    user_teams, league_keys = _derive_pref_targets(prefs)
    if not user_teams and not league_keys:
        return []

    try:
        from datetime import datetime, timedelta
        from zoneinfo import ZoneInfo
        from db_connection import get_connection as _get_conn

        tz = ZoneInfo(config.TZ)
        today = datetime.now(tz).date()
        horizon = today + timedelta(days=max(days_ahead, 1))

        # INV-TIMEZONE-POST-SAST-UNIFY-REGRESSION-01: supersport_scraper-only;
        # DStv EPG re-airs can drift the displayed kickoff by ±1h.
        conn = _get_conn(str(ODDS_DB_PATH))
        rows = conn.execute(
            "SELECT programme_title, channel_short, dstv_number, broadcast_date, "
            "start_time, league, home_team, away_team "
            "FROM broadcast_schedule "
            "WHERE broadcast_date BETWEEN ? AND ? AND is_live = 1 "
            "  AND source = 'supersport_scraper' "
            "ORDER BY start_time ASC",
            (today.isoformat(), horizon.isoformat()),
        ).fetchall()
        conn.close()

        team_tokens = {_normalize_fixture_token(team) for team in user_teams if team}
        league_tokens: set[str] = set()
        for league_key in league_keys:
            league_tokens.add(_normalize_fixture_token(league_key))
            league_def = config.ALL_LEAGUES.get(league_key)
            if league_def:
                league_tokens.add(_normalize_fixture_token(league_def.label))

        fixtures: list[dict] = []
        seen: set[str] = set()
        for row in rows:
            home = row["home_team"] or ""
            away = row["away_team"] or ""
            title = row["programme_title"] or ""
            if not home or not away:
                continue

            home_norm = _normalize_fixture_token(home)
            away_norm = _normalize_fixture_token(away)
            title_norm = _normalize_fixture_token(title)
            league_raw = row["league"] or ""
            league_norm = _normalize_fixture_token(league_raw)

            team_match = any(
                token and (token in home_norm or token in away_norm or token in title_norm)
                for token in team_tokens
            )
            league_match = any(
                token and (token == league_norm or token in league_norm or league_norm in token)
                for token in league_tokens
            )
            if not (team_match or league_match):
                continue

            dedup_key = f"{home_norm}_{away_norm}_{(row['broadcast_date'] or '')}"
            if dedup_key in seen:
                continue
            seen.add(dedup_key)

            league_display = league_raw
            for league_def in config.ALL_LEAGUES.values():
                norm_key = _normalize_fixture_token(league_def.key)
                norm_label = _normalize_fixture_token(league_def.label)
                if league_norm in (norm_key, norm_label) or norm_label in league_norm:
                    league_display = league_def.label
                    break

            fixtures.append({
                "home": home,
                "away": away,
                "kickoff": _format_kickoff_display(row["start_time"] or ""),
                "league": league_display,
                "broadcast": _format_fixture_broadcast(
                    row["channel_short"] or "",
                    str(row["dstv_number"] or ""),
                ),
            })
            if len(fixtures) >= limit:
                break

        return fixtures
    except Exception:
        return []


def _format_fixture_preview_lines(fixtures: list[dict], heading: str) -> list[str]:
    """Render a compact fixture preview block."""
    lines = [f"🗓️ <b>{heading}</b>"]
    for fixture in fixtures[:3]:
        lines.append(f"• <b>{h(fixture.get('home', ''))} vs {h(fixture.get('away', ''))}</b>")
        meta: list[str] = []
        if fixture.get("kickoff"):
            meta.append(f"⏰ {h(fixture['kickoff'])}")
        if fixture.get("league"):
            meta.append(h(fixture["league"]))
        if meta:
            lines.append("  " + " · ".join(meta))
    return lines


def _get_broadcast_line(
    home_team: str = "",
    away_team: str = "",
    league_key: str = "",
    match_date: str = "",
) -> str:
    """Channel display permanently removed (FIX-DSTV-CHANNEL-PERM-01).

    Returns empty string. Kickoff times are obtained via _get_broadcast_details().
    """
    return ""


def _get_broadcast_details(
    home_team: str = "",
    away_team: str = "",
    league_key: str = "",
) -> dict:
    """Return broadcast display + kickoff time from DStv schedule.

    Queries broadcast_schedule table directly for full start_time data.

    Returns:
        {"broadcast": "📺 SS PSL (DStv 202)", "kickoff": "Sat 1 Mar · 17:30"}
        Empty strings when no data found.
    """
    result: dict[str, str] = {"broadcast": "", "kickoff": ""}
    try:
        from datetime import datetime, timedelta
        from zoneinfo import ZoneInfo
        from db_connection import get_connection as _get_conn
        from scrapers.broadcast_matcher import fuzzy_match_broadcast

        tz = ZoneInfo(config.TZ)
        now = datetime.now(tz)
        today = now.strftime("%Y-%m-%d")
        week_ahead = (now + timedelta(days=7)).strftime("%Y-%m-%d")

        # INV-TIMEZONE-POST-SAST-UNIFY-REGRESSION-01: supersport_scraper is the
        # sole authoritative kickoff source. DStv EPG rows (source=NULL) include
        # re-airs, pre-shows, and late-night repeats that fuzzy-match the same
        # teams but carry a broadcast time ±1h (or more) off the true kickoff.
        conn = _get_conn(str(ODDS_DB_PATH))
        rows = conn.execute(
            "SELECT * FROM broadcast_schedule "
            "WHERE broadcast_date BETWEEN ? AND ? AND is_live = 1 "
            "  AND source = 'supersport_scraper' "
            "ORDER BY start_time ASC",
            (today, week_ahead),
        ).fetchall()
        conn.close()

        matches = fuzzy_match_broadcast(rows, home_team, away_team)
        if matches:
            # fuzzy_match_broadcast returns results sorted by confidence descending
            # Convert sqlite3.Row → dict so .get() works correctly
            best = dict(matches[0])
            # Extract kickoff from start_time
            start_time_str = best.get("start_time", "")
            if start_time_str:
                result["kickoff"] = _format_kickoff_display(start_time_str)

            # Channel display permanently removed (FIX-DSTV-CHANNEL-PERM-01).
            # Only kickoff is returned; broadcast is always "".
            pass
    except Exception:
        pass
    return result


def _get_edge_result_match_date(match_key: str = "") -> str:
    # BYPASS-FIX-C: Final header fallback pulls match_date from edge_results.
    """Return edge_results.match_date for a match when header fallbacks exhaust."""
    if not match_key:
        return ""
    try:
        from db_connection import get_connection as _get_conn

        _conn = _get_conn(str(ODDS_DB_PATH), timeout_ms=3000)
        try:
            _row = _conn.execute(
                "SELECT match_date FROM edge_results WHERE match_key = ? LIMIT 1",
                (match_key,),
            ).fetchone()
        finally:
            _conn.close()
        if _row and _row[0]:
            return str(_row[0])
    except Exception:
        pass
    return ""


def _teams_from_vs_event_id(event_id: str) -> tuple[str, str]:
    """W84-Q7: Extract home/away display names from _vs_ match_id format.

    e.g. 'mamelodi_sundowns_vs_sekhukhune_united_2026-03-14'
          → ('Mamelodi Sundowns', 'Sekhukhune United')
    """
    parts = event_id.split("_vs_")
    if len(parts) != 2:
        return "Home", "Away"
    home_raw = parts[0]
    away_raw = re.sub(r"_\d{4}-\d{2}-\d{2}$", "", parts[1])
    home = _display_team_name(home_raw)
    away = _display_team_name(away_raw)
    return home, away


def _tip_matches_hot_key(tip: dict | None, match_key: str) -> bool:
    """Return True when a tip payload maps to the requested Hot Tips detail key."""
    if not tip or not match_key:
        return False
    if tip.get("match_key") == match_key:
        return True
    if tip.get("match_id") == match_key or tip.get("event_id") == match_key:
        return True
    edge_v2 = tip.get("edge_v2") or {}
    return edge_v2.get("match_key") == match_key


async def _serve_card_detail(
    query,
    match_key: str,
    tip_data: dict | None,
    user_id: int,
    user_tier: str,
    edge_tier: str,
    back_page: int = 0,
    include_analysis: bool = True,
    source: str = "edge_picks",
    back_cb_override: str | None = None,
    has_narrative: bool = False,
) -> bool:
    """P1P3-WIRE-DETAIL: Serve card_pipeline photo detail view.

    Builds a structured card via ``card_pipeline.render_card_bytes``, and sends
    as a Telegram photo with ≤1024-char HTML caption.

    Returns True on success.  Returns False on any failure so the caller can
    fall through to the old text-based rendering path.
    """
    try:
        from card_pipeline import render_card_bytes, CardPopulationError
        import io as _cd_io

        # Build buttons via existing function (handles tier gating, CTA, etc.)
        _cd_tips = [tip_data] if tip_data else [{"ev": 0, "match_id": match_key}]
        _cd_btns = _build_game_buttons(
            _cd_tips, match_key, user_id,
            source=source, user_tier=user_tier,
            edge_tier=edge_tier, back_page=back_page,
            back_cb_override=back_cb_override,
            has_narrative=has_narrative,
        )

        # render_card_bytes: build_card_data → CARD-GATE-INV-01 → DetailMessage.build_card_photo
        _cd_img, _, _cd_markup = await asyncio.wait_for(
            asyncio.to_thread(
                render_card_bytes,
                match_key,
                tip_data or {"ev": 0, "match_id": match_key},
                include_analysis=include_analysis,
                back_page=back_page,
                back_cb_override=back_cb_override,
                buttons=_cd_btns,
            ),
            timeout=10.0,
        )

        # Transition: delete text list message → send photo
        _cd_chat_id = query.message.chat_id
        try:
            await query.message.delete()
        except Exception:
            pass

        await query.get_bot().send_photo(
            chat_id=_cd_chat_id,
            photo=_cd_io.BytesIO(_cd_img),
            reply_markup=_cd_markup,
        )
        log.info("PERF: edge:detail CARD-PIPELINE served for %s", match_key)

        return True
    except CardPopulationError as _gate_err:
        log.info("CARD-GATE: suppressed empty detail card for %s (reason=%s)", match_key, _gate_err)
        return False
    except Exception as _cd_err:
        log.warning(
            "Card pipeline detail failed for %s: %s — falling back to old path",
            match_key, _cd_err,
        )
        return False


async def _resolve_hot_tip_header(
    match_key: str,
    user_id: int,
    seed_tip: dict | None = None,
) -> dict[str, str]:
    """Resolve Hot Tips detail header metadata across list, cache, and fallback sources."""
    candidates: list[dict] = []
    if seed_tip:
        candidates.append(seed_tip)

    snap_tip = next(
        (t for t in _ht_tips_snapshot.get(user_id, []) if _tip_matches_hot_key(t, match_key)),
        None,
    )
    if snap_tip and snap_tip is not seed_tip:
        candidates.append(snap_tip)

    hot_tip = next(
        (t for t in _hot_tips_cache.get("global", {}).get("tips", []) if _tip_matches_hot_key(t, match_key)),
        None,
    )
    if hot_tip and hot_tip is not seed_tip and hot_tip is not snap_tip:
        candidates.append(hot_tip)

    def _pick(key: str) -> str:
        for cand in candidates:
            value = cand.get(key)
            if value:
                return value
        return ""

    def _pick_edge_v2(key: str) -> str:
        for cand in candidates:
            edge_v2 = cand.get("edge_v2") or {}
            value = edge_v2.get(key)
            if value:
                return value
        return ""

    resolved_key = (
        _pick("match_key")
        or _pick("match_id")
        or _pick("event_id")
        or _pick_edge_v2("match_key")
        or match_key
    )
    home = _pick("home_team")
    away = _pick("away_team")
    if (not home or not away) and resolved_key:
        home, away = _teams_from_vs_event_id(resolved_key)

    league_key = _pick("league_key") or _pick_edge_v2("league")
    league_display = (
        _get_league_display(league_key, home, away)
        or _pick("league")
        or _pick("_bc_league")
    )

    kickoff = _pick("_bc_kickoff")
    commence_time = _pick("commence_time")
    if not kickoff and commence_time:
        kickoff = _format_kickoff_display(commence_time)

    broadcast = _pick("_bc_broadcast")
    if (not kickoff or not broadcast) and home and away:
        try:
            bc_data = await asyncio.to_thread(
                _get_broadcast_details,
                home, away, league_key or "",
            )
            if not kickoff:
                kickoff = bc_data.get("kickoff", "")
            if not broadcast:
                broadcast = bc_data.get("broadcast", "")
        except Exception:
            pass

    if not kickoff and resolved_key:
        date_match = re.search(r"(\d{4}-\d{2}-\d{2})$", resolved_key)
        if date_match:
            try:
                from datetime import datetime as _dt_ht, timedelta as _td_ht
                from zoneinfo import ZoneInfo as _ZI_ht
                match_dt = _dt_ht.strptime(date_match.group(1), "%Y-%m-%d")
                now_dt = _dt_ht.now(_ZI_ht(config.TZ))
                today = now_dt.date()
                if match_dt.date() == today:
                    kickoff = "Today"
                elif match_dt.date() == today + _td_ht(days=1):
                    kickoff = "Tomorrow"
                else:
                    kickoff = match_dt.strftime("%a %d %b")
            except Exception:
                pass

    return {
        "match_key": resolved_key,
        "home": home,
        "away": away,
        "kickoff": kickoff,
        "league_display": league_display,
        "broadcast": broadcast,
    }


def _resolve_hot_tip_model_state(
    match_key: str,
    user_id: int,
    seed_tip: dict | None = None,
    tips: list[dict] | None = None,
) -> dict[str, int | bool | str]:
    """Resolve authoritative Hot Tips model-only state for a detail surface."""
    candidates: list[dict] = []

    snap_tip = next(
        (t for t in _ht_tips_snapshot.get(user_id, []) if _tip_matches_hot_key(t, match_key)),
        None,
    )
    if snap_tip:
        candidates.append(snap_tip)

    hot_tip = next(
        (t for t in _hot_tips_cache.get("global", {}).get("tips", []) if _tip_matches_hot_key(t, match_key)),
        None,
    )
    if hot_tip and hot_tip is not snap_tip:
        candidates.append(hot_tip)

    if seed_tip and seed_tip is not snap_tip and seed_tip is not hot_tip:
        candidates.append(seed_tip)

    if tips:
        matched_tips = [t for t in tips if _tip_matches_hot_key(t, match_key)]
        if not matched_tips:
            matched_tips = list(tips)
        candidates.extend(
            t for t in matched_tips
            if t is not snap_tip and t is not hot_tip and t is not seed_tip
        )

    for cand in candidates:
        if "_ht_model_only" in cand:
            confirming = int(cand.get("_ht_confirming_signals") or 0)
            total = int(cand.get("_ht_total_signals") or 0)
            return {
                "model_only": bool(cand.get("_ht_model_only")),
                "confirming": confirming,
                "total_signals": total,
                "source": "hot_tips_render",
            }

    for cand in candidates:
        confirming, total, model_only = _edge_signal_meta(cand.get("edge_v2"))
        if model_only or total or cand.get("edge_v2"):
            return {
                "model_only": model_only,
                "confirming": confirming,
                "total_signals": total,
                "source": "edge_v2",
            }

    return {
        "model_only": False,
        "confirming": 0,
        "total_signals": 0,
        "source": "none",
    }


def _apply_hot_tip_model_state(
    tips: list[dict] | None,
    model_state: dict[str, int | bool | str],
) -> list[dict]:
    """Overlay authoritative Hot Tips model-only state onto the detail tips."""
    if not tips:
        return []

    aligned = list(tips)
    best_idx = max(range(len(aligned)), key=lambda i: aligned[i].get("ev", 0))
    best_tip = dict(aligned[best_idx])
    edge_v2 = dict(best_tip.get("edge_v2") or {})

    best_tip["_ht_model_only"] = bool(model_state.get("model_only"))
    best_tip["_ht_confirming_signals"] = int(model_state.get("confirming") or 0)
    best_tip["_ht_total_signals"] = int(model_state.get("total_signals") or 0)

    if best_tip["_ht_model_only"]:
        edge_v2["confirming_signals"] = 0
    elif "confirming_signals" not in edge_v2 and best_tip["_ht_confirming_signals"]:
        edge_v2["confirming_signals"] = best_tip["_ht_confirming_signals"]

    if not edge_v2.get("tier"):
        tier = best_tip.get("display_tier", best_tip.get("edge_rating", ""))
        if tier:
            edge_v2["tier"] = tier

    if edge_v2:
        best_tip["edge_v2"] = edge_v2

    aligned[best_idx] = best_tip
    return aligned


def _apply_hot_tip_detail_honesty(
    text: str,
    model_state: dict[str, int | bool | str],
    user_id: int = 0,
) -> str:
    """Keep Hot Tips detail truth cues aligned with authoritative model-only state."""
    if not text or not model_state.get("model_only"):
        return text

    text = re.sub(
        r"(🏆\s*(?:<b>)?Verdict(?:</b>)?)\s*—\s*[^\n]+",
        r"\1",
        text,
        count=1,
    )
    # R7-BUILD-02: P1-MODEL-ONLY — only show [MODEL ONLY] banner to admins
    if user_id not in config.ADMIN_IDS:
        return text
    banner = "<b>[MODEL ONLY]</b> No confirming signals behind this price."
    if "[MODEL ONLY]" in text:
        return text
    split_at = text.find("\n\n")
    if split_at >= 0:
        return f"{text[:split_at]}\n\n{banner}{text[split_at:]}"
    return f"{text}\n\n{banner}"


def _build_event_header(
    home_raw: str,
    away_raw: str,
    target_league: str,
    target_event: "dict | None",
) -> dict:
    """W84-Q7: Build fresh header dict for game detail cache-hit paths.

    Computes kickoff / league_display / broadcast_line from current data,
    so cache-hit paths never serve stale header info.

    Priority for kickoff:   commence_time → _mm_kickoff stored from list render
    Priority for broadcast: _mm_broadcast (list render) → _get_broadcast_details() → _get_broadcast_line()
    """
    from datetime import datetime as _dt
    from zoneinfo import ZoneInfo as _ZI

    commence = (target_event or {}).get("commence_time", "")

    # Kickoff from commence_time; reject 02:00 SAST (midnight-UTC PSL placeholder)
    kickoff = ""
    try:
        ct = _dt.fromisoformat(commence.replace("Z", "+00:00"))
        if ct.tzinfo is None:
            ct = assume_sast(ct)
        ct_sa = ct.astimezone(_ZI(config.TZ))
        if not (ct_sa.hour == 2 and ct_sa.minute == 0):
            kickoff = ct_sa.strftime("%a %-d %b, %H:%M") + " SAST"
    except Exception:
        pass
    if not kickoff:
        kickoff = (target_event or {}).get("_mm_kickoff") or ""

    # Broadcast — prefer stored list metadata (zero DB cost), then DB lookup
    broadcast_line = (target_event or {}).get("_mm_broadcast") or ""
    if not broadcast_line:
        try:
            bc = _get_broadcast_details(
                home_team=home_raw, away_team=away_raw,
                league_key=target_league or "",
            )
            broadcast_line = bc.get("broadcast", "")
            # BUILD-KICKOFF-RESTORE-02: use broadcast kickoff when kickoff is empty.
            # Before BUILD-KOTIME-FINAL-01, missing kickoffs were "TBC"; the old
            # guard `kickoff == "TBC"` was dead code after that change.  Fix:
            # accept the broadcast time whenever we have no kickoff yet.
            if bc.get("kickoff") and bc["kickoff"] != "TBC" and not kickoff:
                kickoff = bc["kickoff"]
        except Exception:
            pass
    if not broadcast_line:
        try:
            bc_date = commence[:10] if commence else ""
            broadcast_line = _get_broadcast_line(
                home_team=home_raw, away_team=away_raw,
                league_key=target_league or "", match_date=bc_date,
            )
        except Exception:
            pass

    return {
        "kickoff": kickoff,
        "league_display": _get_league_display(target_league or "", home_raw, away_raw),
        "broadcast_line": "",  # FIX-DSTV-CHANNEL-PERM-01: channel display permanently off
    }


def _inject_narrative_header(
    html: str,
    home_raw: str,
    away_raw: str,
    kickoff: str,
    league_display: str,
    broadcast_line: str,
) -> str:
    """W84-Q7: Replace stale header block in cached narrative HTML with fresh data.

    Finds the first narrative section marker (📋) and replaces everything
    before it with a freshly-built header.  Handles missing markers gracefully.
    """
    hf, af = _get_flag_prefixes(home_raw, away_raw)
    home_e = h(home_raw)
    away_e = h(away_raw)
    header_lines = [f"🎯 <b>{hf}{home_e} vs {af}{away_e}</b>"]
    if kickoff:
        header_lines.append(f"📅 {kickoff}")
    if league_display:
        header_lines.append(f"\U0001f3c6 {league_display}")
    # FIX-DSTV-CHANNEL-PERM-01: broadcast_line (channel info) permanently omitted
    header_lines.append("")
    header_text = "\n".join(header_lines)

    for marker in ("📋 <b>The Setup</b>", "📋 The Setup", "📋"):
        pos = html.find(marker)
        if pos >= 0:
            return header_text + html[pos:]
    # No section marker — prepend header to full content
    return header_text + "\n\n" + html


def _get_next_fixtures_for_teams(
    user_teams: set[str], limit: int = 3,
) -> list[dict]:
    """Find the next upcoming fixtures for any of the user's teams.

    Queries broadcast_schedule for upcoming live broadcasts matching user's teams.
    Returns list of {"home": str, "away": str, "kickoff": str, "league": str}
    sorted by start_time ascending.
    """
    if not user_teams:
        return []
    try:
        from datetime import datetime, timedelta
        from zoneinfo import ZoneInfo
        from db_connection import get_connection as _get_conn

        tz = ZoneInfo(config.TZ)
        now = datetime.now(tz)
        today = now.strftime("%Y-%m-%d")
        month_ahead = (now + timedelta(days=30)).strftime("%Y-%m-%d")

        # INV-TIMEZONE-POST-SAST-UNIFY-REGRESSION-01: supersport_scraper-only.
        conn = _get_conn(str(ODDS_DB_PATH))
        rows = conn.execute(
            "SELECT programme_title, home_team, away_team, start_time, league "
            "FROM broadcast_schedule "
            "WHERE broadcast_date BETWEEN ? AND ? AND is_live = 1 "
            "  AND source = 'supersport_scraper' "
            "ORDER BY start_time ASC",
            (today, month_ahead),
        ).fetchall()
        conn.close()

        # Match broadcasts to user's teams (case-insensitive)
        teams_lower = {t.lower() for t in user_teams}
        fixtures: list[dict] = []
        seen: set[str] = set()

        for row in rows:
            home = row["home_team"] or ""
            away = row["away_team"] or ""
            title = row["programme_title"] or ""

            # Check if any user team matches home or away
            matched = False
            for team_lower in teams_lower:
                if (team_lower in home.lower() or team_lower in away.lower()
                        or team_lower in title.lower()):
                    matched = True
                    break

            if not matched:
                continue

            # Deduplicate by home+away+date
            dedup_key = f"{home.lower()}_{away.lower()}_{(row['start_time'] or '')[:10]}"
            if dedup_key in seen:
                continue
            seen.add(dedup_key)

            # Format kickoff
            kickoff = ""
            if row["start_time"]:
                kickoff = _format_kickoff_display(row["start_time"])

            # League display — use full name from config if possible
            league_raw = row["league"] or ""
            league_display = league_raw
            for lg in config.ALL_LEAGUES.values():
                if lg.key == league_raw.lower().replace(" ", "_"):
                    league_display = lg.label
                    break

            if home and away:
                fixtures.append({
                    "home": home, "away": away,
                    "kickoff": kickoff, "league": league_display,
                })

            if len(fixtures) >= limit:
                break

        return fixtures
    except Exception:
        return []


def _get_flag_prefixes(home: str, away: str) -> tuple[str, str]:
    """Return (home_flag, away_flag) with both-or-nothing rule.

    If BOTH teams have a flag → return both flags (with trailing space).
    If EITHER team has no flag → return ('', '') for both.
    """
    hf = config.get_country_flag(home)
    af = config.get_country_flag(away)
    if hf and af:
        return (hf + " ", af + " ")
    return ("", "")


HOT_TIPS_PAGE_SIZE = 4
RESULT_PROOF_LAST_10_COUNT = 10
MIN_SAMPLE_FOR_STATS = 50
HOT_TIPS_RECENT_SETTLED_LIMIT = 3
HOT_TIPS_RECENT_SETTLED_HOURS = 36
DETAIL_TRACK_RECORD_MIN_SETTLED = 3
HIT_RATE_DISPLAY_THRESHOLD = 50  # Only show hit rate in header when >= this %



def _build_tip_narrative(tip: dict) -> str:
    """Build a compelling narrative explaining WHY this tip has value."""
    outcome = tip.get("predicted_outcome", "") or tip.get("outcome", "this team")
    # BUILD-CTA-FIX: Read bookmaker/odds from fresh odds_by_bookmaker when available
    # so narrative body is consistent with what the CTA button was built from.
    _odds_by_bk = tip.get("odds_by_bookmaker", {})
    if _odds_by_bk:
        # D-01 FIX: Use outcome-specific bookmaker selection (same algorithm as CTA button).
        # Old code: max(_odds_by_bk, key=_odds_by_bk.get) — compares nested dicts, not prices.
        _outcome_raw = tip.get("outcome", "home")
        _best_bk_key, _best_bk_price = _select_best_bookmaker_for_outcome(_odds_by_bk, _outcome_raw)
        if _best_bk_key is None:
            # Fallback: first bookmaker in dict (graceful empty-outcome handling)
            _best_bk_key = next(iter(_odds_by_bk), "")
            _bk_markets = _odds_by_bk.get(_best_bk_key, {})
            _best_bk_price = _bk_markets.get(_outcome_raw) if isinstance(_bk_markets, dict) else None
        best_bk = _display_bookmaker_name(_best_bk_key) if _best_bk_key else "the market"
        best_odds = _best_bk_price or 0
    else:
        best_bk = (
            tip.get("best_bookmaker_display", "")
            or tip.get("bookmaker", "")
            or _display_bookmaker_name(tip.get("best_bookmaker", ""))
            or "the best bookmaker"
        )
        best_odds = tip.get("best_odds", 0) or tip.get("odds", 0)
    ev = tip.get("ev_pct", 0) or tip.get("ev", 0)
    tier = tip.get("display_tier", tip.get("edge_rating", "GOLD"))
    odds_by_bk = tip.get("odds_by_bookmaker", {})
    # consensus_prob may be 0-1 or 0-100 (as "prob" percentage)
    consensus_prob = tip.get("consensus_prob", 0)
    if consensus_prob == 0 and tip.get("prob", 0) > 0:
        consensus_prob = tip["prob"] / 100.0

    # Calculate market average odds for the predicted outcome
    all_odds = [v for v in odds_by_bk.values() if v and v > 1]
    avg_odds = sum(all_odds) / len(all_odds) if all_odds else best_odds

    # Guard against zero/missing data
    if not best_odds or best_odds <= 1:
        return ""

    # How much above average is the best price?
    premium_pct = ((best_odds - avg_odds) / avg_odds * 100) if avg_odds > 0 else 0

    # How many bookmakers offer lower odds?
    cheaper_count = sum(1 for o in all_odds if o < best_odds)

    parts = []

    # Opening — unified "The Edge:" brand with tier-specific emoji (use dict for case safety)
    edge_emoji = EDGE_EMOJIS.get(tier, EDGE_EMOJIS.get(tier.lower() if isinstance(tier, str) else "", "🥉"))
    parts.append(f"{edge_emoji} <b>The Edge:</b>")

    # Core insight — why the odds are good
    if premium_pct > 5:
        parts.append(
            f"No other SA bookmaker has {outcome} at these odds. "
            f"{best_bk} is offering <b>{best_odds:.2f}</b>, "
            f"well above the market average of {avg_odds:.2f}."
        )
    elif premium_pct > 2:
        parts.append(
            f"{best_bk} has {outcome} at <b>{best_odds:.2f}</b>, "
            f"above the {avg_odds:.2f} market average."
        )
    else:
        parts.append(
            f"Best price on {outcome} is <b>{best_odds:.2f}</b> at {best_bk}."
        )

    # Probability insight
    if consensus_prob > 0:
        prob_pct = consensus_prob * 100
        parts.append(
            f"Our model gives this a {prob_pct:.0f}% chance — "
            f"at these odds, that's a <b>+{ev:.1f}% edge</b>."
        )

    # Social proof — other bookmakers
    if cheaper_count >= 3:
        parts.append(
            f"{cheaper_count} other bookmakers have already shortened their prices."
        )
    elif cheaper_count >= 1:
        parts.append(
            "Other bookmakers are pricing this tighter, "
            f"making the {best_bk} price stand out."
        )

    return " ".join(parts)


