def _format_confidence_badge(confidence: str, source: str = "") -> str:
    """Format a confidence badge for display.

    Returns a short inline badge, e.g. '🎯 Sharp Edge' or '📊 SA Consensus'.
    Returns '' for low confidence (omit from display).
    """
    if confidence == "high":
        source_name = _SHARP_SOURCE_DISPLAY.get(source, "Sharp benchmark")
        return f"🎯 <i>{source_name}</i>"
    elif confidence == "medium":
        return "📊 <i>SA bookmaker consensus</i>"
    return ""  # Low confidence — omit


def _format_freshness(minutes_ago: int, same_day_match: bool = False, odds_ts: str = "") -> str:
    """Smart freshness display — warns when odds are stale for same-day matches."""
    if minutes_ago <= 5:
        return "<i>⚡ Live odds</i>"
    elif minutes_ago <= 20:
        return f"<i>Odds updated {minutes_ago} min ago</i>"
    elif same_day_match and minutes_ago > 90:
        # ODDS-FRESHNESS-01: same-day match with odds >90 min old — show explicit warning
        if odds_ts:
            try:
                from datetime import datetime
                _ts = datetime.fromisoformat(odds_ts.replace("Z", "+00:00"))
                if _ts.tzinfo is None:
                    _ts = assume_utc(_ts)
                _sast = to_sast(_ts)
                _time_str = _sast.strftime("%H:%M")
                return f"<i>⚠️ Odds as of {_time_str} SAST — verify on bookmaker before placing</i>"
            except Exception:
                pass
        return "<i>⚠️ Odds may have moved — verify before placing</i>"
    else:
        return "<i>Live SA bookmaker odds</i>"


def _build_edge_snapshots_from_match(match: dict) -> list[dict]:
    """Convert odds_service match data into edge_rating odds_snapshots format.

    calculate_edge_rating() expects: [{bookmaker, outcome, odds, timestamp}, ...]
    get_best_odds() returns: {outcomes: {outcome_key: {all_bookmakers: {bk: odds}}}}
    """
    snapshots = []
    outcomes = match.get("outcomes", {})
    ts = match.get("last_updated", "")

    for outcome_key, outcome_data in outcomes.items():
        for bk_key, odds_val in outcome_data.get("all_bookmakers", {}).items():
            snapshots.append({
                "bookmaker": bk_key,
                "outcome": outcome_key,
                "odds": odds_val,
                "timestamp": ts,
            })

    return snapshots


def _build_model_from_consensus(match: dict) -> dict:
    """Build a model prediction from cross-bookmaker consensus.

    Without an external sharp line, average implied probabilities across
    bookmakers to create the reference model. The predicted outcome is
    the one with the highest consensus probability (the favourite).
    """
    outcomes = match.get("outcomes", {})
    if not outcomes:
        return {}

    # Calculate average implied probability for each outcome
    avg_probs: dict[str, float] = {}
    for outcome_key, outcome_data in outcomes.items():
        all_bk = outcome_data.get("all_bookmakers", {})
        probs = [1.0 / o for o in all_bk.values() if o and o > 1.0]
        if probs:
            avg_probs[outcome_key] = sum(probs) / len(probs)

    if not avg_probs:
        return {}

    # The favourite is the outcome with the highest implied probability
    best_outcome = max(avg_probs, key=avg_probs.get)
    best_prob = avg_probs[best_outcome]

    # Confidence based on number of bookmakers (5 = 100%)
    bk_count = match.get("bookmaker_count", 1)
    confidence = min(bk_count / 5.0, 1.0)

    return {
        "outcome": best_outcome,
        "confidence": confidence,
        "implied_prob": best_prob,
    }


# BUILD-4: _tier_from_composite() RETIRED. Use _get_fresh_tier_from_er() which calls
# assign_tier() from tier_engine — includes min_edge_pct gate that this function lacks.
def _tier_from_composite(composite: float) -> str:
    """DEPRECATED — kept for reference. Use _get_fresh_tier_from_er() instead."""
    if composite >= 52:
        return "diamond"
    if composite >= 40:
        return "gold"
    if composite >= 38:
        return "silver"
    return "bronze"


def _get_fresh_tier_from_er(match_key: str) -> str | None:
    """TIER-FIX B: Read edge_tier directly from edge_results.

    Returns None if no edge_results row found or on error.
    Called via asyncio.to_thread() in narrative_cache serving paths.
    The DB value is the authoritative result of the full pipeline
    (assign_tier + data_presence_gate + validate_tier). Re-deriving
    with empty red_flags caused RC-3 tier mismatches.
    """
    try:
        from scrapers.db_connect import connect_odds_db as _gft_fn
        from scrapers.edge.edge_config import DB_PATH as _gft_db
        _gft_conn = _gft_fn(_gft_db)
        _gft_conn.row_factory = lambda c, r: dict(zip([col[0] for col in c.description], r))
        try:
            _gft_row = _gft_conn.execute(
                "SELECT edge_tier "
                "FROM edge_results WHERE match_key = ? AND result IS NULL "
                "ORDER BY recommended_at DESC LIMIT 1",
                (match_key,),
            ).fetchone()
        finally:
            _gft_conn.close()
        if not _gft_row:
            return None
        _tier = (_gft_row.get("edge_tier") or "bronze").strip().lower()
        if _tier not in ("diamond", "gold", "silver", "bronze"):
            _tier = "bronze"
        return _tier
    except Exception:
        return None


def _get_recent_wins_from_edge_results(limit: int = 5) -> list[dict]:
    """Load recently settled winning edges for the home menu winners card."""
    try:
        from scrapers.db_connect import connect_odds_db as _conn_fn
        from scrapers.edge.edge_config import DB_PATH as _DB_PATH
        _conn = _conn_fn(_DB_PATH)
        _conn.row_factory = lambda cursor, row: dict(
            zip([col[0] for col in cursor.description], row)
        )
        rows = _conn.execute(
            "SELECT match_key, edge_tier, recommended_odds, actual_return, sport, bet_type "
            "FROM edge_results WHERE result='hit' "
            "ORDER BY CASE edge_tier WHEN 'diamond' THEN 1 WHEN 'gold' THEN 2 WHEN 'silver' THEN 3 ELSE 4 END, "
            "settled_at DESC LIMIT ?",
            (limit,)
        ).fetchall()
        _conn.close()
        return rows
    except Exception as exc:
        log.warning("_get_recent_wins_from_edge_results failed: %s", exc)
        return []


def _get_bru_daily_drop(limit: int = 5) -> list[dict]:
    """Return today's Diamond/Gold picks for the BRU Daily Drop welcome screen section.

    No result/outcome filter — shows all picks regardless of settlement status.
    Enriches each pick with kickoff time from broadcast_schedule where available.
    """
    try:
        import datetime
        from zoneinfo import ZoneInfo as _ZI
        from scrapers.db_connect import connect_odds_db as _conn_fn
        from scrapers.edge.edge_config import DB_PATH as _DB_PATH

        today = datetime.datetime.now(_ZI("Africa/Johannesburg")).date().isoformat()
        _conn = _conn_fn(_DB_PATH)
        _conn.row_factory = lambda cursor, row: dict(
            zip([col[0] for col in cursor.description], row)
        )
        picks = _conn.execute(
            "SELECT match_key, edge_tier, composite_score, bet_type, recommended_odds, "
            "bookmaker, sport, league "
            "FROM edge_results WHERE match_date = ? AND edge_tier IN ('diamond', 'gold') "
            "ORDER BY CASE edge_tier WHEN 'diamond' THEN 1 ELSE 2 END, "
            "composite_score DESC LIMIT ?",
            (today, limit),
        ).fetchall()
        for pick in picks:
            key = pick["match_key"]
            vs_part = key.rsplit("_", 1)[0]
            if "_vs_" in vs_part:
                home_slug = vs_part.split("_vs_")[0].split("_")[0]
                row = _conn.execute(
                    "SELECT start_time FROM broadcast_schedule "
                    "WHERE broadcast_date = ? AND source = 'supersport_scraper' "
                    "AND LOWER(home_team) LIKE ? LIMIT 1",
                    (today, f"%{home_slug}%"),
                ).fetchone()
                pick["kickoff"] = row["start_time"] if row else None
            else:
                pick["kickoff"] = None
        _conn.close()
        return picks
    except Exception as exc:
        log.warning("_get_bru_daily_drop failed: %s", exc)
        return []


def _format_bru_daily_drop(picks: list[dict]) -> str:
    """Format today's Diamond/Gold picks as the BRU Daily Drop welcome screen block."""
    _TIER_BADGES = {"diamond": "💎 DIAMOND EDGE", "gold": "🥇 GOLDEN EDGE"}
    _SPORT_EMOJI = {"soccer": "⚽", "rugby": "🏉", "cricket": "🏏", "mma": "🥊", "boxing": "🥊"}

    if not picks:
        return (
            "<b>📡 BRU Daily Drop</b>\n"
            "<i>No edges today — check back soon 🔍</i>"
        )

    lines = ["<b>📡 BRU Daily Drop — Today's Edges</b>"]
    for pick in picks:
        tier = pick.get("edge_tier", "gold")
        badge = _TIER_BADGES.get(tier, f"🥇 {tier.upper()} EDGE")
        sport_emoji = _SPORT_EMOJI.get(pick.get("sport", ""), "🏅")

        vs_part = pick["match_key"].rsplit("_", 1)[0]
        if "_vs_" in vs_part:
            home_raw, away_raw = vs_part.split("_vs_", 1)
            match_name = (
                f"{home_raw.replace('_', ' ').title()} vs "
                f"{away_raw.replace('_', ' ').title()}"
            )
        else:
            match_name = vs_part.replace("_", " ").title()

        kickoff_str = ""
        if pick.get("kickoff"):
            try:
                import datetime as _dt
                ko = _dt.datetime.fromisoformat(str(pick["kickoff"]))
                kickoff_str = f" · ⏰ {ko.strftime('%-H:%M')} SAST"
            except Exception:
                pass

        lines.append(f"\n{sport_emoji} <b>{match_name}</b>")
        lines.append(f"{badge}{kickoff_str}")
        lines.append(f"💰 {pick['bet_type']} @ {pick['recommended_odds']:.2f}")

    return "\n".join(lines)


def _load_tips_from_edge_results(limit: int = 10, skip_punt_filter: bool = False, with_clv: bool = False) -> list[dict]:
    """W84-P1: Fast serving path — read pre-computed edges from edge_results table.

    Called synchronously from asyncio.to_thread(). Single SQL query, ~5ms.
    No edge computation needed — edges were logged by calculate_edge_v2() on
    previous computation cycles.

    Args:
        limit: max tips to return
        skip_punt_filter: bypass zero-signal filter (for pregen)
        with_clv: AC-8 — optionally LEFT JOIN bet_recommendations_log to attach
                  CLV data (clv_pct, fair_odds, closing_odds) when available.
                  Graceful null if no CLV data — no card breakage.

    Returns tips in same dict format as _fetch_hot_tips_from_db() for drop-in
    use by _build_hot_tips_page(). Falls back gracefully on any error.
    """
    import re as _re_er
    from datetime import date as _date_cls, datetime as _dt_cls, timezone as _tz
    try:
        from scrapers.db_connect import connect_odds_db as _conn_fn
        from scrapers.edge.edge_config import (
            DB_PATH as _DB_PATH,
            MAX_PRODUCTION_EDGE_PCT as _MAX_PRODUCTION_EDGE_PCT,
            MAX_RECOMMENDED_ODDS as _MAX_RECOMMENDED_ODDS,
        )
        _conn = _conn_fn(_DB_PATH)
        _conn.row_factory = lambda cursor, row: dict(
            zip([col[0] for col in cursor.description], row)
        )
        _today = _date_cls.today().isoformat()
        # BUILD-STALE-PICKS-01: Exclude matches that have already kicked off.
        # LEFT JOIN fixture_mapping; where kickoff data exists and is in the past → exclude.
        # Conservative: matches without fixture_mapping entry are kept (date-only fallback).
        # Falls back to date-only query if fixture_mapping table doesn't exist (test envs).
        _now_utc = _dt_cls.now(_tz.utc).strftime("%Y-%m-%dT%H:%M:%S+00:00")
        _base_sql = """
            SELECT e.match_key, e.edge_id, e.edge_tier, e.composite_score, e.bet_type,
                   e.recommended_odds, e.bookmaker, e.predicted_ev, e.league, e.match_date,
                   e.confirming_signals
                   {extra_cols}
            FROM edge_results e
            {join}
            WHERE e.match_date >= ? AND e.result IS NULL
              {kickoff_filter}
              AND NOT EXISTS (
                  SELECT 1
                  FROM edge_results newer
                  WHERE newer.match_key = e.match_key
                    AND newer.result IS NULL
                    AND (
                        COALESCE(newer.recommended_at, '') > COALESCE(e.recommended_at, '')
                        OR (
                            COALESCE(newer.recommended_at, '') = COALESCE(e.recommended_at, '')
                            AND newer.id > e.id
                        )
                    )
              )
            ORDER BY e.composite_score DESC
            LIMIT ?
        """
        _limit_val = max(int(limit or 10), 1) * 2
        try:
            rows = _conn.execute(
                _base_sql.format(
                    extra_cols=", fm.kickoff AS fm_kickoff",
                    join="LEFT JOIN fixture_mapping fm ON fm.match_key = e.match_key",
                    kickoff_filter="AND (fm.kickoff IS NULL OR fm.kickoff > ?)",
                ),
                (_today, _now_utc, _limit_val),
            ).fetchall()
        except Exception:
            # fixture_mapping table absent (test environment) — date-only fallback
            rows = _conn.execute(
                _base_sql.format(extra_cols="", join="", kickoff_filter=""),
                (_today, _limit_val),
            ).fetchall()
    except Exception as _e:
        log.debug("_load_tips_from_edge_results DB read failed: %s", _e)
        return []

    tips: list[dict] = []
    _tier_sort = {"diamond": 0, "gold": 1, "silver": 2, "bronze": 3}
    for row in rows:
        mk = row["match_key"] or ""
        # Extract teams from match_key: "home_team_vs_away_team_2026-03-14"
        mk_no_date = _re_er.sub(r"_\d{4}-\d{2}-\d{2}$", "", mk)
        if "_vs_" in mk_no_date:
            _home_raw, _away_raw = mk_no_date.split("_vs_", 1)
        else:
            _home_raw = _away_raw = mk_no_date
        home_display = _display_team_name(_home_raw)
        away_display = _display_team_name(_away_raw)

        # TIER-FIX A: Trust edge_results.edge_tier directly. The DB value is the
        # authoritative result of the full pipeline (assign_tier + data_presence_gate
        # + validate_tier). Re-deriving here with empty red_flags and no gates caused
        # RC-1 tier mismatches (list badge != DB tier).
        edge_tier = (row.get("edge_tier") or "bronze").strip().lower()
        if edge_tier not in ("diamond", "gold", "silver", "bronze"):
            edge_tier = "bronze"
        _confirming_actual = row.get("confirming_signals")
        _confirming_est = int(_confirming_actual) if _confirming_actual is not None else 0

        # predicted_ev is stored as percentage (e.g. 5.2 = 5.2%)
        ev_pct = round(float(row["predicted_ev"] or 0), 1)
        if (
            ev_pct <= 0
            or ev_pct > _MAX_PRODUCTION_EDGE_PCT
            or float(row["recommended_odds"] or 0) > _MAX_RECOMMENDED_ODDS
        ):
            continue

        # BUILD-GATE-RELAX: Suppress zero-signal edges ONLY when EV < 3%.
        # Price difference alone IS a valid edge — Paul revised 1 April 2026.
        # skip_punt_filter=True bypasses this for pregen (generation-time concern, not display-time).
        if not skip_punt_filter:
            if _confirming_est == 0 and ev_pct < 3.0:
                continue

        league_key = (row["league"] or "").lower()
        outcome_label = row["bet_type"] or "home"
        # Normalise "Home Win"/"Away Win" back to outcome terms for sport_key lookup
        if outcome_label == "Home Win":
            outcome_raw = "home"
        elif outcome_label == "Away Win":
            outcome_raw = "away"
        else:
            outcome_raw = "draw"
        _outcome_labels = {"home": home_display, "away": away_display, "draw": "Draw"}
        outcome_display = _outcome_labels.get(outcome_raw, outcome_label)

        # ALGO-FIX-01 parity: hard-exclude draws from the fast serving path.
        # Matches the guard in _fetch_hot_tips_from_db_inner.
        if outcome_raw == "draw":
            continue

        _raw_bk_key = (row["bookmaker"] or "").strip().lower()
        _rec_odds = float(row["recommended_odds"] or 0)
        tips.append({
            "event_id": mk,
            "match_id": mk,
            "edge_id": row.get("edge_id") or "",
            "sport_key": _DB_LEAGUE_SPORT.get(league_key, config.LEAGUE_SPORT.get(league_key, "soccer")),
            "home_team": home_display,
            "away_team": away_display,
            "commence_time": row.get("fm_kickoff") or "",
            "outcome": outcome_display,
            "outcome_key": outcome_raw,
            "odds": _rec_odds,
            "bookmaker": _display_bookmaker_name(_raw_bk_key),
            "bookmaker_key": _raw_bk_key,
            "ev": ev_pct,
            "prob": round(((1 + ev_pct / 100.0) / _rec_odds) * 100) if ev_pct > 0 and _rec_odds > 1.0 else 0,
            "kelly": 0,
            "edge_rating": edge_tier,
            "display_tier": edge_tier,
            "edge_score": float(row["composite_score"] or 0),
            "league": _get_league_display(league_key, home_display, away_display),
            "league_key": league_key,
            # Populate with the recommended bookmaker so CTA buttons show
            # the correct bookmaker instead of falling back to Betway.
            "odds_by_bookmaker": {_raw_bk_key: _rec_odds} if _raw_bk_key and _rec_odds > 0 else {},
            "sharp_confidence": "low",
            "sharp_source": "edge_results",
            "edge_v2": {
                "composite_score": float(row.get("composite_score") or 0),
                "edge_pct": float(row.get("predicted_ev") or row.get("edge_pct") or 0),
                "outcome": row.get("bet_type", "home"),
                "confirming_signals": _confirming_est,
            },
        })
        # R10-BUILD-01: Multi-BK enrichment — populate odds_by_bookmaker from odds_snapshots
        _tip_market = "match_winner" if tips[-1]["sport_key"] in ("cricket", "combat") else "1x2"
        try:
            _snap_rows = _conn.execute("""
                SELECT bookmaker, home_odds, draw_odds, away_odds
                FROM odds_snapshots
                WHERE match_id = ? AND market_type = ?
                  AND scraped_at >= datetime('now', '-6 hours')
                ORDER BY scraped_at DESC
            """, (mk, _tip_market)).fetchall()
            if _snap_rows:
                _bk_dict: dict = {}
                for _sr in _snap_rows:
                    _bk = _sr.get("bookmaker") if isinstance(_sr, dict) else _sr[0]
                    if not _bk or _bk in _bk_dict:
                        continue
                    _h = _sr.get("home_odds") if isinstance(_sr, dict) else _sr[1]
                    _d = _sr.get("draw_odds") if isinstance(_sr, dict) else _sr[2]
                    _a = _sr.get("away_odds") if isinstance(_sr, dict) else _sr[3]
                    _o = _h if outcome_raw == "home" else (_a if outcome_raw == "away" else _d)
                    if _o and float(_o) > 1.0:
                        _bk_dict[_bk] = float(_o)
                if _bk_dict:
                    tips[-1]["odds_by_bookmaker"] = _bk_dict
                    # BUILD-CTA-FIX: Sync top-level fields with best fresh bookmaker so
                    # CTA button and narrative body read the same data source.
                    _best_bk_item = max(_bk_dict.items(), key=lambda x: x[1])
                    tips[-1]["bookmaker_key"] = _best_bk_item[0]
                    tips[-1]["bookmaker"] = _display_bookmaker_name(_best_bk_item[0])
                    tips[-1]["odds"] = _best_bk_item[1]
        except Exception:
            pass  # Keep single-BK fallback

    # AC-8: Optionally attach CLV from bet_recommendations_log when available
    if with_clv and tips:
        try:
            for _tip in tips:
                _clv_row = _conn.execute("""
                    SELECT clv_pct, fair_odds, closing_odds, market_efficiency,
                           kill_switch_triggered
                    FROM bet_recommendations_log
                    WHERE match_key = ? AND bet_type = ?
                      AND clv_pct IS NOT NULL
                    ORDER BY logged_at DESC LIMIT 1
                """, (_tip["match_id"], _tip.get("outcome_key", "home"))).fetchone()
                if _clv_row:
                    _tip["clv_pct"] = _clv_row.get("clv_pct") if isinstance(_clv_row, dict) else _clv_row[0]
                    _tip["fair_odds"] = _clv_row.get("fair_odds") if isinstance(_clv_row, dict) else _clv_row[1]
                    _tip["closing_odds"] = _clv_row.get("closing_odds") if isinstance(_clv_row, dict) else _clv_row[2]
                    _tip["market_efficiency"] = _clv_row.get("market_efficiency") if isinstance(_clv_row, dict) else _clv_row[3]
                    _tip["kill_switch_triggered"] = bool(
                        _clv_row.get("kill_switch_triggered") if isinstance(_clv_row, dict) else _clv_row[4]
                    )
                else:
                    # Graceful null — no CLV data yet, no card breakage
                    _tip["clv_pct"] = None
                    _tip["fair_odds"] = None
                    _tip["closing_odds"] = None
                    _tip["market_efficiency"] = None
                    _tip["kill_switch_triggered"] = None
        except Exception:
            # Table may not exist yet — graceful degradation
            for _tip in tips:
                _tip["clv_pct"] = None
                _tip["fair_odds"] = None
                _tip["closing_odds"] = None

    # R10-BUILD-01: Close connection now that enrichment loop is complete
    try:
        _conn.close()
    except Exception:
        pass

    # Sort: tier first, then EV descending
    tips.sort(key=lambda t: (
        _tier_sort.get(t["display_tier"], 9),
        -t["ev"],
    ))
    return tips[: max(int(limit or 10), 1)]


async def _refresh_tip_evs(tips: list[dict]) -> list[dict]:
    """BUILD-10: Compute live EV via calculate_edge_v2() before list render.

    Calls calculate_edge_v2() on current odds_latest data for each tip —
    the same path as the edge:detail handler. Filters tips where live EV ≤ 0
    and updates ev fields to reflect current values.
    Falls back to original list on timeout or any error (graceful degradation).
    """
    if not tips:
        return tips

    def _live_ev_for_tip(tip: dict) -> tuple[str, float | None]:
        """Compute live EV for one tip. Returns (match_key, ev_pct or None)."""
        mk = tip.get("match_id") or tip.get("event_id", "")
        if not mk:
            return ("", None)
        # Derive raw outcome from bet_type stored in edge_v2;
        # fall back to outcome_key for fast-path tips (edge_v2=None).
        _bet_type = (tip.get("edge_v2") or {}).get("outcome", "") or tip.get("outcome_key", "")
        if _bet_type == "Home Win":
            outcome_raw = "home"
        elif _bet_type == "Away Win":
            outcome_raw = "away"
        elif _bet_type in ("home", "draw", "away"):
            outcome_raw = _bet_type
        else:
            outcome_raw = "home"  # safe default
        sport = tip.get("sport_key", "soccer")
        league = tip.get("league_key", "")
        try:
            from scrapers.edge.edge_v2_helper import calculate_edge_v2
            result = calculate_edge_v2(
                mk,
                outcome=outcome_raw,
                sport=sport,
                league=league,
                _skip_log=True,  # W84-P0: user reads must not trigger DB writes
            )
            if result and result.get("predicted_ev") is not None:
                return (mk, float(result["predicted_ev"]))
            return (mk, None)
        except Exception as _e:
            log.warning("scraper_boundary_failure site=edge_v2_9479 err=%s", _e)
            if sentry_sdk:
                with sentry_sdk.push_scope() as scope:
                    scope.set_tag("contract_violation", "scraper_boundary")
                    scope.set_tag("boundary_site", "edge_v2_9479")
                    sentry_sdk.capture_exception(_e)
            return (mk, None)

    # BUILD-QA22-FIX P1-1: Use partial results on timeout instead of discarding all
    _tasks = [asyncio.create_task(asyncio.to_thread(_live_ev_for_tip, t)) for t in tips]
    try:
        _raw = await asyncio.wait_for(
            asyncio.gather(*_tasks, return_exceptions=True),
            timeout=2.0,
        )
    except asyncio.TimeoutError:
        _raw = []
        for _pt in _tasks:
            if _pt.done() and not _pt.cancelled():
                try:
                    _raw.append(_pt.result())
                except Exception:
                    pass
        log.warning("[BUILD-QA22] EV refresh partial timeout — %d/%d tips refreshed", len(_raw), len(tips))
    except Exception:
        return tips  # Non-timeout gather error — serve original list

    # Build match_key → live EV map
    live_evs: dict[str, float | None] = {}
    for r in _raw:
        if isinstance(r, Exception):
            continue
        mk, ev = r
        if mk:
            live_evs[mk] = ev

    if not live_evs:
        return tips

    result = []
    for t in tips:
        mk = t.get("match_id") or t.get("event_id", "")
        if mk and mk in live_evs:
            current_ev = live_evs[mk]
            if current_ev is None:
                # Could not compute live EV — keep tip (conservative), but log warning
                log.warning("[BUILD-STALE-EV] EV lookup returned None for %s — keeping stale value", mk)
                result.append(t)
                continue
            if current_ev <= 0:
                log.debug("[BUILD-10] Suppressing negative-EV tip %s (ev=%.1f%%)", mk, current_ev)
                continue  # Suppress — live EV is negative
            t = dict(t)  # Shallow copy — don't mutate shared cache dicts
            t["ev"] = round(current_ev, 1)
        result.append(t)
    return result


async def _fetch_hot_tips_from_db() -> list[dict]:
    """Fetch hot tips from Dataminer's odds.db — no external API needed.

    Uses cross-bookmaker consensus as the model, then scores with edge rating.
    Returns tips in the same dict format as _fetch_hot_tips_all_sports().
    """
    import time

    # Fast path: return cached if fresh (no lock needed — read-only check)
    cache_entry = _hot_tips_cache.get("global")
    if cache_entry and (time.time() - cache_entry["ts"]) < HOT_TIPS_CACHE_TTL:
        return cache_entry["tips"]

    # W84-P1: Prevent concurrent cold fetches — only ONE computation at a time.
    # If the precompute job is already running when a user taps Tips, the user's
    # call waits here. When the lock releases, the cache is populated → fast return.
    _lock = _hot_tips_fetch_lock
    if _lock is not None:
        async with _lock:
            # Re-check after acquiring: another compute may have just finished
            cache_entry = _hot_tips_cache.get("global")
            if cache_entry and (time.time() - cache_entry["ts"]) < HOT_TIPS_CACHE_TTL:
                return cache_entry["tips"]
            return await _fetch_hot_tips_from_db_inner()
    # Lock not yet initialised (called before _post_init) — compute directly
    return await _fetch_hot_tips_from_db_inner()


async def _fetch_hot_tips_from_db_inner() -> list[dict]:
    """Inner computation — called only when lock is held. One cold fetch at a time."""
    import time

    all_tips: list[dict] = []
    near_miss_tips: list[dict] = []
    seen_match_ids: set[str] = set()  # Deduplicate matches across leagues

    # W52-PERF: Collect all matches first, then calculate edges in parallel
    match_jobs: list[tuple[dict, str, str]] = []  # (match, league, market_type)
    for league in DB_LEAGUES:
        try:
            from services.odds_service import LEAGUE_MARKET_TYPE
            market_type = LEAGUE_MARKET_TYPE.get(league, "1x2")
            matches = await odds_svc.get_all_matches(market_type=market_type, league=league)

            for match in matches:
                if match["match_id"] in seen_match_ids:
                    continue
                seen_match_ids.add(match["match_id"])
                min_bk = 1 if league in ("ufc", "boxing") else 2
                if match.get("bookmaker_count", 0) < min_bk:
                    continue
                match_jobs.append((match, league, market_type))
        except Exception as exc:
            log.warning("Hot tips DB scan error for %s: %s", league, exc)
            continue

    from scrapers.edge.edge_config import (
        MAX_PRODUCTION_EDGE_PCT as _MAX_PRODUCTION_EDGE_PCT,
        MAX_RECOMMENDED_ODDS as _MAX_RECOMMENDED_ODDS,
    )

    # KO-TIME-INV-01: Batch-load kickoff times from fixture_mapping before edge loop.
    # odds_snapshots has no commence_time; fixture_mapping carries scheduled kickoffs.
    # RUNTIME-R2: sync SQLite must run in to_thread inside async context.
    _ht_match_ids = [m["match_id"] for m, _, _ in match_jobs]
    _fixture_kickoffs: dict = await asyncio.to_thread(_load_fixture_kickoffs, _ht_match_ids) if _ht_match_ids else {}

    # BUILD-STALE-PICKS-01: Filter out matches that have already kicked off.
    # Conservative: matches without kickoff data are kept (date-only filter is the fallback).
    from datetime import datetime as _sp_dt, timezone as _sp_tz
    _now_utc_str = _sp_dt.now(_sp_tz.utc).strftime("%Y-%m-%dT%H:%M:%S+00:00")
    _pre_filter_count = len(match_jobs)
    match_jobs = [
        (m, l, mt) for m, l, mt in match_jobs
        if not _fixture_kickoffs.get(m["match_id"])  # no kickoff data → keep (conservative)
        or _fixture_kickoffs[m["match_id"]] > _now_utc_str  # kickoff in future → keep
    ]
    if len(match_jobs) < _pre_filter_count:
        log.info("Kickoff filter: removed %d already-started matches", _pre_filter_count - len(match_jobs))

    # R12-BUILD-01 Fix 1: Batch-load authoritative outcomes from edge_results so the
    # display outcome matches what narratives were generated against. This eliminates
    # divergence between the list path (which used live V2 outcome) and the detail
    # path (which uses edge_results.bet_type for narrative cache lookup).
    _er_outcomes: dict[str, str] = {}  # match_key → "home"/"away"/"draw"
    if match_jobs:
        try:
            from scrapers.db_connect import connect_odds_db as _er_conn_fn
            from scrapers.edge.edge_config import DB_PATH as _ER_DB_PATH
            from datetime import date as _er_date_cls
            _er_conn = _er_conn_fn(_ER_DB_PATH)
            _er_conn.row_factory = lambda cursor, row: dict(
                zip([col[0] for col in cursor.description], row)
            )
            _er_today = _er_date_cls.today().isoformat()
            _er_rows = _er_conn.execute("""
                SELECT e.match_key, e.bet_type
                FROM edge_results e
                WHERE e.match_date >= ? AND e.result IS NULL
                  AND NOT EXISTS (
                      SELECT 1 FROM edge_results newer
                      WHERE newer.match_key = e.match_key
                        AND newer.result IS NULL
                        AND (
                            COALESCE(newer.recommended_at, '') > COALESCE(e.recommended_at, '')
                            OR (
                                COALESCE(newer.recommended_at, '') = COALESCE(e.recommended_at, '')
                                AND newer.id > e.id
                            )
                        )
                  )
            """, (_er_today,)).fetchall()
            for _er_row in _er_rows:
                _er_mk = _er_row["match_key"] or ""
                _er_bt = (_er_row["bet_type"] or "").strip()
                if _er_mk and _er_bt:
                    # Normalise "Home Win"/"Away Win" → "home"/"away"/"draw"
                    if _er_bt == "Home Win":
                        _er_outcomes[_er_mk] = "home"
                    elif _er_bt == "Away Win":
                        _er_outcomes[_er_mk] = "away"
                    elif _er_bt.lower() in ("home", "away", "draw"):
                        _er_outcomes[_er_mk] = _er_bt.lower()
                    else:
                        _er_outcomes[_er_mk] = "draw"
            _er_conn.close()
        except Exception as _er_exc:
            log.debug("R12-BUILD-01: edge_results outcome lookup failed: %s", _er_exc)

    # W52-PERF: Run all edge calculations concurrently (semaphore limits DB contention)
    _edge_sem = asyncio.Semaphore(4)

    async def _calc_one_edge(match_info):
        m, lg, mt = match_info
        async with _edge_sem:
            try:
                from scrapers.edge.edge_v2_helper import calculate_edge_v2
                return await asyncio.to_thread(
                    calculate_edge_v2, m["match_id"],
                    market_type=mt,
                    sport=_DB_LEAGUE_SPORT.get(lg, "soccer"),
                    league=lg,
                    _skip_log=False,
                )
            except Exception as exc:
                log.debug("Edge V2 failed for %s: %s", m["match_id"], exc)
                return None

    edge_results = await asyncio.gather(
        *[_calc_one_edge(job) for job in match_jobs],
        return_exceptions=True,
    )

    for (match, league, market_type), _v2_result in zip(match_jobs, edge_results):
        if isinstance(_v2_result, Exception):
            _v2_result = None

        hidden_candidate = False

        if _v2_result and _v2_result.get("tier"):
            # Use V2 results — but prefer authoritative outcome from edge_results
            # R12-BUILD-01 Fix 1: edge_results.bet_type is the same source the cold
            # path and narrative cache use. Live V2 may pick a different outcome as
            # odds shift, causing list↔detail divergence and false cache busts.
            predicted_outcome = _er_outcomes.get(match["match_id"])
            if not predicted_outcome:
                # HOT-TIPS-BUILD-01 Fix A: first-cycle gap — V2 just computed this
                # edge but edge_results hasn't been persisted yet. Populate _er_outcomes
                # inline so the gate doesn't skip this match on its first scan cycle.
                _v2_live_outcome = _v2_result.get("outcome", "")
                if _v2_live_outcome:
                    _er_outcomes[match["match_id"]] = _v2_live_outcome
                    predicted_outcome = _v2_live_outcome
                else:
                    continue  # V2 outcome also absent — skip (R15-BUILD-01 preserved)
            # Fix 1: Hard-exclude draws (ALGO-FIX-01 8 Apr 2026)
            # Draws: 13.6% win rate, -43.2% ROI on 22 bets — no draw-specific signal
            if predicted_outcome == "draw":
                continue
            edge_tier = _v2_result["tier"]
            composite_score = _v2_result["composite_score"]
            edge_pct = _v2_result["edge_pct"]
            sharp_confidence = _v2_result.get("confidence", "low")
            sharp_source = _v2_result.get("sharp_source", "sa_consensus")
            v2_best_bk = _v2_result.get("best_bookmaker", "")
            v2_best_odds = _v2_result.get("best_odds", 0)
            # Fix 4: CLV gate — exclude NEGATIVE CLV when data available (ALGO-FIX-01 8 Apr 2026)
            # 49% of CLV-tracked edges had negative CLV — closing line disagreed with model
            _clv_avg = _v2_result.get("clv_avg")
            if _clv_avg is not None and _clv_avg < 0:
                continue
        else:
            continue  # V2 result required — skip unscored matches (TIER-FIX-01)

        # Find best bookmaker for CTA
        outcome_data = match["outcomes"].get(predicted_outcome, {})
        odds_by_bk = outcome_data.get("all_bookmakers", {})
        best_odds = v2_best_odds or outcome_data.get("best_odds", 0)
        best_bk_key = v2_best_bk or outcome_data.get("best_bookmaker", "")
        if best_odds > _MAX_RECOMMENDED_ODDS:
            continue
        # Fix 3: Odds ceiling by tier (ALGO-FIX-01 8 Apr 2026)
        # 54% of bets at 3.0+ odds had only 28.6% win rate — longshots dressed as edges
        # Diamond/Gold capped at 3.5; Silver capped at 5.0; Bronze: no tier cap
        _TIER_ODDS_CAPS = {"diamond": 3.5, "gold": 3.5, "silver": 5.0}
        _odds_ceil = _TIER_ODDS_CAPS.get(edge_tier)
        if _odds_ceil is not None and best_odds > _odds_ceil:
            continue

        # BUILD-QA23-FIX: Initialise consensus_prob before V2/non-V2 branch
        consensus_prob = _v2_result.get("fair_probability", 0) if _v2_result else 0
        # Fix 5: EV Consistency — use V2 benchmark-calibrated edge_pct as primary;
        # fall back to naive consensus calculation only when V2 is unavailable.
        if _v2_result and _v2_result.get("tier"):
            ev_pct = edge_pct  # From _v2_result["edge_pct"] set above
        else:
            implied_probs = [1.0 / o for o in odds_by_bk.values() if o and o > 1]
            consensus_prob = sum(implied_probs) / len(implied_probs) if implied_probs else 0
            ev_pct = round((consensus_prob * best_odds - 1) * 100, 1) if best_odds > 0 and consensus_prob > 0 else 0

        event_id = match["match_id"]
        home_display = _display_team_name(match.get("home_team") or "TBD")
        away_display = _display_team_name(match.get("away_team") or "TBD")
        _outcome_labels = {"home": home_display, "away": away_display, "draw": "Draw"}
        outcome_label = _outcome_labels.get(predicted_outcome, predicted_outcome)
        base_tip = {
            "event_id": event_id,
            "match_id": match["match_id"],
            "sport_key": _DB_LEAGUE_SPORT.get(league, config.LEAGUE_SPORT.get(league, "soccer")),
            "home_team": home_display,
            "away_team": away_display,
            "commence_time": _fixture_kickoffs.get(match["match_id"], ""),
            "outcome": outcome_label,
            "outcome_key": predicted_outcome,
            "odds": best_odds,
            "bookmaker": _display_bookmaker_name(best_bk_key),
            "prob": round(consensus_prob * 100) if consensus_prob else 0,
            "kelly": 0,
            "league": _get_league_display(league, home_display, away_display),
            "league_key": league,
            "odds_by_bookmaker": odds_by_bk,
            "sharp_confidence": sharp_confidence,
            "sharp_source": sharp_source,
            "edge_v2": _v2_result,
            "best_odds": best_odds,
            "n_bookmakers": len(odds_by_bk) or int(match.get("bookmaker_count", 0) or 0),
            "composite_score": composite_score,
        }

        if hidden_candidate or (0 < ev_pct < 1.0):
            near_miss_tips.append({
                **base_tip,
                "ev": ev_pct,
                "edge_rating": edge_tier,
                "display_tier": edge_tier,
                "edge_score": composite_score,
            })
            continue

        if ev_pct < 1.0:
            continue  # Minimum EV threshold

        if ev_pct > _MAX_PRODUCTION_EDGE_PCT:
            near_miss_tips.append({
                **base_tip,
                "ev": ev_pct,
                "edge_rating": edge_tier,
                "display_tier": edge_tier,
                "edge_score": composite_score,
            })
            continue

        # Apply EV cap guardrails
        bk_count = match.get("bookmaker_count", 0)
        _tier_map = {"diamond": EdgeRating.DIAMOND, "gold": EdgeRating.GOLD,
                     "silver": EdgeRating.SILVER, "bronze": EdgeRating.BRONZE}
        edge_enum = _tier_map.get(edge_tier, EdgeRating.BRONZE)
        adj_tier, adj_ev, gr_reason = apply_guardrails(
            edge_enum, ev_pct / 100.0, bk_count,
        )
        if adj_ev is None:
            log.debug("Tip excluded by guardrails: %s (%s)", match["match_id"], gr_reason)
            near_miss_tips.append({
                **base_tip,
                "ev": ev_pct,
                "edge_rating": edge_tier,
                "display_tier": edge_tier,
                "edge_score": composite_score,
            })
            continue
        ev_pct = round(adj_ev * 100, 1)
        edge_tier = str(adj_tier)

        # BUILD-GATE-RELAX: Suppress zero-signal edges ONLY when EV < 3%.
        # Price difference alone IS a valid edge — Paul revised 1 April 2026.
        _gate_confirming = int((_v2_result or {}).get("confirming_signals", 0) or 0)
        if _gate_confirming == 0 and ev_pct < 3.0:
            log.info("BUILD-GATE-RELAX: suppressed zero-signal low-EV edge %s (tier=%s, ev=%.1f%%)",
                     match["match_id"], edge_tier, ev_pct)
            near_miss_tips.append({
                **base_tip,
                "ev": ev_pct,
                "edge_rating": edge_tier,
                "display_tier": edge_tier,
                "edge_score": composite_score,
            })
            continue

        all_tips.append({
            **base_tip,
            "ev": ev_pct,
            "edge_rating": edge_tier,
            "edge_score": composite_score,
        })

    # Sort by edge score descending, then allocate slots across non-empty tiers.
    all_tips.sort(key=lambda t: (-t.get("edge_score", 0), -t["ev"]))
    top_tips = _allocate_tips_by_tier(all_tips, min_per_tier=3)
    # W50-TIER: Use V2 computed tier as authoritative display_tier (not percentile override)
    for tip in top_tips:
        tip["display_tier"] = tip.get("edge_rating", "bronze")
        tip["edge_tier"] = tip.get("edge_tier") or tip["display_tier"]

    # Re-sort by tier (diamond first) then EV descending within each tier
    _tier_sort_order = {"diamond": 0, "gold": 1, "silver": 2, "bronze": 3}
    top_tips.sort(key=lambda t: (
        _tier_sort_order.get(t.get("display_tier", "bronze"), 9),
        -t.get("ev", 0),
    ))

    # W75-FIX: Tier mismatch warning log
    for tip in top_tips:
        v2_tier = (tip.get("edge_v2") or {}).get("tier")
        display = tip.get("display_tier")
        if v2_tier and display and v2_tier != display:
            log.warning("TIER MISMATCH: %s v2=%s display=%s", tip.get("match_id"), v2_tier, display)

    near_miss_tips.sort(key=lambda t: (-t.get("edge_score", 0), -t.get("ev", 0)))
    thin_state = {
        "state": "none" if top_tips else ("below_threshold" if near_miss_tips else "no_tips"),
        "candidate_count": len(near_miss_tips),
        "weaker_tip": near_miss_tips[0] if near_miss_tips else None,
    }
    # CARD-BUILD-01: Population gate
    from card_pipeline import verify_card_populates, _log_card_population_failure
    top_tips = [t for t in top_tips if verify_card_populates(t, t.get("match_id", ""))[0]]
    _hot_tips_cache["global"] = {"tips": top_tips, "ts": time.time(), "thin_slate": thin_state}
    return top_tips


def _expire_stale_edges() -> None:
    """BUILD-STALE-PICKS-01: Mark unsettled edges as 'expired' when their match has kicked off.

    Run once per hour from _edge_precompute_job. Uses result='expired' (not 'void')
    so stats queries (WHERE result IN ('hit','miss')) exclude them automatically.
    Two expiry paths:
      1. Has fixture_mapping entry with kickoff in the past → expired at kickoff
      2. match_date > 2 days ago with no fixture_mapping entry → date-stale fallback
    Never raises — best-effort DB write.
    """
    try:
        from scrapers.db_connect import connect_odds_db as _conn_fn
        from scrapers.edge.edge_config import DB_PATH as _DB_PATH
        from datetime import datetime as _dt, timezone as _tz
        _now_utc = _dt.now(_tz.utc).strftime("%Y-%m-%dT%H:%M:%S+00:00")
        _conn = _conn_fn(_DB_PATH)
        # Path 1: Has fixture_mapping + kickoff is past
        # FIX-CORE7-CRICKET-01: exclude cricket — kickoff-based expiry fires during the
        # match before results are in match_results, causing a settlement race. Cricket
        # uses the 7-day date-stale path below instead.
        _expired_ko = _conn.execute("""
            UPDATE edge_results
            SET result = 'expired'
            WHERE result IS NULL
              AND sport NOT IN ('cricket', 'mma', 'boxing')
              AND match_key IN (
                  SELECT e.match_key
                  FROM edge_results e
                  JOIN fixture_mapping fm ON fm.match_key = e.match_key
                  WHERE e.result IS NULL
                    AND e.sport NOT IN ('cricket', 'mma', 'boxing')
                    AND fm.kickoff < ?
              )
        """, (_now_utc,)).rowcount
        # Path 2a: No fixture_mapping + match_date > 2 days ago (non-cricket/combat)
        _expired_date = _conn.execute("""
            UPDATE edge_results
            SET result = 'expired'
            WHERE result IS NULL
              AND sport NOT IN ('cricket', 'mma', 'boxing')
              AND match_date < date('now', '-2 days')
        """).rowcount
        # Path 2b: Cricket/combat — 7-day grace period gives settler time to run
        # FIX-CORE7-CRICKET-01: extended from 2d → 7d to eliminate settlement race
        _expired_cricket = _conn.execute("""
            UPDATE edge_results
            SET result = 'expired'
            WHERE result IS NULL
              AND sport IN ('cricket', 'mma', 'boxing')
              AND match_date < date('now', '-7 days')
        """).rowcount
        _conn.commit()
        _conn.close()
        if _expired_ko or _expired_date or _expired_cricket:
            log.info(
                "Stale edge cleanup: expired %d kickoff-past + %d date-stale + %d cricket/combat-7d edges",
                _expired_ko, _expired_date, _expired_cricket,
            )
    except Exception as _e:
        log.debug("_expire_stale_edges failed: %s", _e)


def _load_fixture_kickoffs(match_ids: list) -> dict:
    """Batch-load kickoff ISO strings from fixture_mapping for the given match_ids.

    Returns {match_id: kickoff_str}. Never raises — returns {} on any error.
    KO-TIME-INV-01: odds.db has no commence_time; fixture_mapping carries the
    actual scheduled kickoff scraped from API-Football.
    """
    if not match_ids:
        return {}
    try:
        from scrapers.db_connect import connect_odds_db as _conn_fn
        from scrapers.edge.edge_config import DB_PATH as _DB_PATH
        _conn = _conn_fn(_DB_PATH)
        _ph = ",".join("?" * len(match_ids))
        _rows = _conn.execute(
            f"SELECT match_key, kickoff FROM fixture_mapping "
            f"WHERE match_key IN ({_ph}) AND kickoff IS NOT NULL AND kickoff != ''",
            list(match_ids),
        ).fetchall()
        _conn.close()
        return {row[0]: row[1] for row in _rows}
    except Exception:
        return {}


