def _get_supersport_channel(home: str, away: str, match_key: str, league: str = "") -> tuple[str, str]:
    """Resolve broadcast channel info from supersport_scraper rows.

    BUILD-KO-SUPERSPORT-PRIMARY-01: supersport_scraper is the PRIMARY and sole
    authoritative source for broadcast channels across all sports.
    BUILD-CHANNEL-LOGOS-01: also returns channel_logo_url from the DB row.

    Returns (channel_display_str, channel_logo_url). Both empty on no match.
    channel_display_str e.g. "SuperSport PSL (DStv 202)".
    channel_logo_url e.g. "https://mzansiedge.co.za/assets/channels/202.png".
    """
    if not home and not away:
        return "", ""

    _match_date = ""
    try:
        import re as _re
        _m = _re.search(r"(\d{4}-\d{2}-\d{2})$", match_key or "")
        if _m:
            _match_date = _m.group(1)
    except Exception:
        pass

    try:
        from scrapers.db_connect import connect_odds_db as _cfn
        from scrapers.edge.edge_config import DB_PATH as _DP
        from scrapers.broadcast_matcher import fuzzy_match_broadcast
        import sqlite3 as _sq

        _c = _cfn(_DP)
        _c.row_factory = _sq.Row
        try:
            if _match_date:
                _rows = _c.execute(
                    """
                    SELECT * FROM broadcast_schedule
                    WHERE source = 'supersport_scraper'
                      AND home_team IS NOT NULL AND away_team IS NOT NULL
                      AND start_time IS NOT NULL
                      AND DATE(start_time) = ?
                    ORDER BY match_confidence DESC, start_time ASC
                    """,
                    (_match_date,),
                ).fetchall()
            else:
                _rows = _c.execute(
                    """
                    SELECT * FROM broadcast_schedule
                    WHERE source = 'supersport_scraper'
                      AND home_team IS NOT NULL AND away_team IS NOT NULL
                      AND start_time IS NOT NULL
                    ORDER BY start_time DESC LIMIT 50
                    """,
                ).fetchall()

            _matches = fuzzy_match_broadcast(_rows, home, away) if _rows else []
            if not _matches:
                return "", ""
            _best = dict(_matches[0])
            _ch_name = (_best.get("channel_name") or "").strip()
            _ch_short = (_best.get("channel_short") or "").strip()
            _dstv = (_best.get("dstv_number") or "").strip()
            _logo_url = (_best.get("channel_logo_url") or "").strip()

            # BUILD-CHANNEL-LOGOS-01 — two-pass logo resolution:
            # Pass 1: supersport_scraper rows have accurate match data but often
            #   have channel_short='SS' with no dstv_number (RSC payload lacked
            #   squareIcon for this fixture).  If dstv_number is empty, do a second
            #   query across ALL sources — the legacy program-guide rows (source=NULL)
            #   carry specific dstv_number/channel info for the same match windows.
            if not _dstv:
                _window_rows = _c.execute(
                    """
                    SELECT * FROM broadcast_schedule
                    WHERE home_team IS NOT NULL AND away_team IS NOT NULL
                      AND start_time IS NOT NULL
                      AND (dstv_number IS NOT NULL AND dstv_number != '')
                      AND DATE(start_time) BETWEEN DATE(?,'-7 days') AND DATE(?,'+7 days')
                    ORDER BY match_confidence DESC, start_time ASC
                    LIMIT 200
                    """,
                    (_match_date or "now", _match_date or "now"),
                ).fetchall()
                _win_matches = fuzzy_match_broadcast(_window_rows, home, away) if _window_rows else []
                if _win_matches:
                    _wb = dict(_win_matches[0])
                    _ch_name = _ch_name or (_wb.get("channel_name") or "").strip()
                    _ch_short = _ch_short or (_wb.get("channel_short") or "").strip()
                    _dstv = (_wb.get("dstv_number") or "").strip()
                    _logo_url = (_wb.get("channel_logo_url") or "").strip()

            # Pass 2: if we now have a dstv_number but still no logo URL, derive it
            #   from the locally-downloaded asset (covers backfilled rows and any rows
            #   where channel_logo_url wasn't updated yet).
            if not _logo_url and _dstv:
                import os as _os
                if _os.path.exists(f"/home/paulsportsza/assets/channels/{_dstv}.png"):
                    _logo_url = f"https://mzansiedge.co.za/assets/channels/{_dstv}.png"

            # Pass 3: league-based default channel — final fallback when DB has no
            # dstv_number for this match (covers future EPL/UCL/PSL fixtures that
            # haven't been loaded into broadcast_schedule yet).
            if not _dstv and league:
                _lk = league.lower().strip()
                for _key, (_def_label, _def_dstv) in _LEAGUE_CHANNEL_DEFAULTS.items():
                    if _key in _lk or _lk in _key:
                        import os as _os2
                        if _os2.path.exists(f"/home/paulsportsza/assets/channels/{_def_dstv}.png"):
                            _ch_name = _ch_name or _def_label
                            _dstv = _def_dstv
                            _logo_url = f"https://mzansiedge.co.za/assets/channels/{_def_dstv}.png"
                        break

            # Prefer full channel_name (e.g. "SuperSport PSL"), append DStv number when present.
            _label = _ch_name or _ch_short
            if _label and _dstv:
                return f"{_label} (DStv {_dstv})", _logo_url
            return _label, _logo_url
        finally:
            _c.close()
    except Exception as exc:
        log.debug("_get_supersport_channel: lookup failed (%s, %s): %s", home, away, exc)
        return "", ""


def _resolve_kickoff_time(
    sport: str,
    match_key: str,
    home: str = "",
    away: str = "",
    commence_time: str = "",
    league: str = "",
) -> tuple[str, str]:
    """Resolve (date, time) for a match across all sports.

    BUILD-KO-TIME-FIX-01: eliminates 'KO time TBC' permanently by resolving
    kickoff from sport-specific fixture tables with a clear fallback chain.

    Args:
        sport: "soccer"/"football", "cricket", "rugby", "mma"/"boxing"/"combat"
        match_key: snake_case match key, typically suffixed with YYYY-MM-DD
        home: display name (e.g. "Chennai Super Kings") — used for cricket/rugby/mma
        away: display name — used for cricket/rugby/mma
        commence_time: ISO fallback (Odds API commence_time)
        league: league key (optional; reserved for future league-aware routing)

    Returns:
        (date_str, time_str) where:
        - date_str is a display-friendly date ("Today", "Tomorrow", "Wed 11 Apr")
        - time_str is SAST HH:MM ("19:30"); empty string when no time is available
          (rugby, mma, unknown) or when every fallback fails
        - Never returns "TBC" as either component.

    Fallback order (per sport):
        football:  fixture_mapping.kickoff → broadcast_schedule.start_time
                   → commence_time → match_key date suffix (date only)
        cricket:   sportmonks_fixtures.match_date (UTC) → broadcast_schedule.start_time
                   → commence_time → match_key date suffix
        rugby:     rugby_fixtures.match_date (date only) → broadcast_schedule.start_time
                   → commence_time → match_key date suffix
        mma:       mma_fixtures.fight_date (date only) → broadcast_schedule.start_time
                   → commence_time → match_key date suffix
    """
    from datetime import datetime as _dt, timedelta as _td, date as _date
    from zoneinfo import ZoneInfo as _ZI

    _SAST = _ZI(config.TZ)
    _sport = (sport or "").strip().lower()
    if _sport in ("football",):
        _sport = "soccer"
    if _sport in ("boxing", "combat"):
        _sport = "mma"

    def _fmt_sast_dt(dt_obj, from_utc_conversion=False) -> tuple[str, str]:
        """Format a tz-aware datetime into (date_label, HH:MM).
        
        Args:
            dt_obj: datetime object in SAST timezone
            from_utc_conversion: True if this came from UTC→SAST conversion (enables sentinel check)
        """
        now = _dt.now(_SAST)
        today = now.date()
        d = dt_obj.date()
        if d == today:
            date_str = "Today"
        elif d == today + _td(days=1):
            date_str = "Tomorrow"
        else:
            date_str = dt_obj.strftime("%a %d %b")
        time_str = dt_obj.strftime("%H:%M")
        # Midnight-UTC sentinel (00:00 UTC → 02:00 SAST) = placeholder, not real time
        # Only apply to times that came from UTC conversion, not local broadcast_schedule times
        if from_utc_conversion and time_str == "02:00":
            return (date_str, "")
        return (date_str, time_str)

    def _fmt_iso_utc(iso_str: str) -> tuple[str, str]:
        """Parse UTC ISO/space-separated datetime, convert to SAST, format."""
        try:
            s = (iso_str or "").strip()
            if not s:
                return ("", "")
            # Support both "2026-04-11T19:30:00+00:00" and "2026-04-11 19:30:00"
            if "T" not in s and " " in s:
                s = s.replace(" ", "T")
            if s.endswith("Z"):
                s = s[:-1] + "+00:00"
            dt_obj = _dt.fromisoformat(s)
            if dt_obj.tzinfo is None:
                # sportmonks_fixtures match_date is UTC
                dt_obj = assume_utc(dt_obj)
            return _fmt_sast_dt(dt_obj.astimezone(_SAST), from_utc_conversion=True)
        except Exception:
            return ("", "")

    def _fmt_iso_local(iso_str: str) -> tuple[str, str]:
        """Parse local/naive ISO datetime — treat as already SAST."""
        try:
            s = (iso_str or "").strip()
            if not s:
                return ("", "")
            if "T" not in s and " " in s:
                s = s.replace(" ", "T")
            dt_obj = _dt.fromisoformat(s)
            if dt_obj.tzinfo is None:
                dt_obj = assume_sast(dt_obj)
            return _fmt_sast_dt(dt_obj.astimezone(_SAST))
        except Exception:
            return ("", "")

    def _fmt_date_only(date_str: str) -> tuple[str, str]:
        """Parse a YYYY-MM-DD date string — return (label, '')."""
        try:
            s = (date_str or "").strip()[:10]
            if not s:
                return ("", "")
            d = _date.fromisoformat(s)
            today = _dt.now(_SAST).date()
            if d == today:
                return ("Today", "")
            if d == today + _td(days=1):
                return ("Tomorrow", "")
            return (d.strftime("%a %d %b"), "")
        except Exception:
            return ("", "")

    # Extract date from match_key suffix as last-resort date
    def _date_from_match_key() -> tuple[str, str]:
        try:
            import re as _re
            m = _re.search(r"(\d{4}-\d{2}-\d{2})$", match_key or "")
            if m:
                return _fmt_date_only(m.group(1))
        except Exception:
            pass
        return ("", "")

    # Broadcast schedule query — shared across sports
    # BUILD-MM-DETAIL-FIX-01 Fix 4: date-filtered two-attempt lookup.
    # 1) full-name LIKE + DATE(start_time)=match_date
    # 2) fallback to first-word LIKE + same date filter (guard: first token ≥6 chars)
    # Date filter prevents picking future rebroadcast rows. First-word fallback
    # catches PSL/cup rows stored with short team names (e.g. "Polokwane" vs
    # "Polokwane City" — won't match full-name LIKE).
    def _from_broadcast_schedule() -> tuple[str, str]:
        """Resolve (date, time) from broadcast_schedule using SuperSport only.

        BUILD-KO-SUPERSPORT-PRIMARY-01: supersport_scraper is the authoritative
        source for kickoff times across all sports (football, rugby, cricket).
        INV-TIMEZONE-POST-SAST-UNIFY-REGRESSION-01: removed the "any-source"
        fallback — DStv EPG rows (source=NULL) include re-airs, pre-shows, and
        late-night repeats that fuzzy-match the same teams but carry a
        broadcast time ±1h (or more) off the true kickoff. If SuperSport has
        no row for a fixture, fall through to the sport-specific fallback
        chain (fixture_mapping / sportmonks_fixtures / commence_time / date).
        """
        if not home and not away:
            return ("", "")

        _match_date = ""
        try:
            import re as _re
            _m = _re.search(r"(\d{4}-\d{2}-\d{2})$", match_key or "")
            if _m:
                _match_date = _m.group(1)
        except Exception:
            pass

        try:
            from scrapers.db_connect import connect_odds_db as _cfn
            from scrapers.edge.edge_config import DB_PATH as _DP
            from scrapers.broadcast_matcher import fuzzy_match_broadcast

            _c = _cfn(_DP)
            _c.row_factory = __import__("sqlite3").Row
            try:
                if _match_date:
                    _rows = _c.execute(
                        """
                        SELECT * FROM broadcast_schedule
                        WHERE source = 'supersport_scraper'
                          AND home_team IS NOT NULL AND away_team IS NOT NULL
                          AND start_time IS NOT NULL
                          AND DATE(start_time) = ?
                        ORDER BY match_confidence DESC, start_time ASC
                        """,
                        (_match_date,),
                    ).fetchall()
                else:
                    _rows = _c.execute(
                        """
                        SELECT * FROM broadcast_schedule
                        WHERE source = 'supersport_scraper'
                          AND home_team IS NOT NULL AND away_team IS NOT NULL
                          AND start_time IS NOT NULL
                        ORDER BY start_time DESC
                        LIMIT 50
                        """,
                    ).fetchall()

                _matches = fuzzy_match_broadcast(_rows, home, away) if _rows else []

                if _matches:
                    _best = dict(_matches[0])
                    _start_time = _best.get("start_time") or ""
                    if _start_time:
                        return _fmt_iso_local(_start_time)
            finally:
                _c.close()
        except Exception as exc:
            log.debug("_resolve_kickoff_time: broadcast_schedule lookup failed: %s", exc)
        return ("", "")


    # ── Football path ────────────────────────────────────────
    # BUILD-KO-SUPERSPORT-PRIMARY-01: broadcast_schedule (SuperSport-first) is
    # the PRIMARY source. fixture_mapping is now a fallback because API-Football
    # kickoffs can lag / drift for PSL; SuperSport guide is authoritative for SA.
    if _sport == "soccer":
        # 1) broadcast_schedule (SuperSport-first, authoritative for SA)
        d, t = _from_broadcast_schedule()
        if d:
            log.debug("_resolve_kickoff_time[soccer:broadcast] %s → %s %s", match_key, d, t)
            return (d, t)
        # 2) fixture_mapping (API-Football kickoffs, UTC ISO)
        if match_key:
            try:
                from scrapers.db_connect import connect_odds_db as _cfn
                from scrapers.edge.edge_config import DB_PATH as _DP
                _c = _cfn(_DP)
                try:
                    _row = _c.execute(
                        "SELECT kickoff FROM fixture_mapping WHERE match_key = ? "
                        "AND kickoff IS NOT NULL AND kickoff != '' LIMIT 1",
                        (match_key,),
                    ).fetchone()
                    if _row and _row[0]:
                        # FIX-REGRESS-D2-DATE-PILL-01: on-demand stale invalidation.
                        # If fixture_mapping.kickoff is >2h in the past, the cache is
                        # stale (fixture rescheduled or incorrect). Skip to next source.
                        _ko_stale = False
                        try:
                            _ko_raw = _row[0].strip().replace("Z", "+00:00")
                            if "T" not in _ko_raw and " " in _ko_raw:
                                _ko_raw = _ko_raw.replace(" ", "T")
                            _ko_dt = _dt.fromisoformat(_ko_raw)
                            if _ko_dt.tzinfo is None:
                                _ko_dt = assume_utc(_ko_dt)
                            if _ko_dt < _dt.now(_ZI("UTC")) - _td(hours=2):
                                log.warning(
                                    "_resolve_kickoff_time: fixture_mapping stale for %s "
                                    "(kickoff=%s) — skipping to commence_time",
                                    match_key, _row[0],
                                )
                                _ko_stale = True
                        except Exception:
                            pass  # parse failure → not stale, use value
                        if not _ko_stale:
                            d, t = _fmt_iso_utc(_row[0])
                            if d:
                                log.debug(
                                    "_resolve_kickoff_time[soccer:fixture_mapping] %s → %s %s",
                                    match_key, d, t,
                                )
                                return (d, t)
                finally:
                    _c.close()
            except Exception as exc:
                log.debug("_resolve_kickoff_time[soccer]: fixture_mapping failed: %s", exc)
        # 3) commence_time (Odds API / Sportmonks)
        d, t = _fmt_iso_utc(commence_time)
        if d:
            log.debug("_resolve_kickoff_time[soccer:commence_time] %s → %s %s", match_key, d, t)
            return (d, t)
        # 4) date from match_key
        return _date_from_match_key()

    # ── Cricket path ─────────────────────────────────────────
    # BUILD-KO-SUPERSPORT-PRIMARY-01: broadcast_schedule (SuperSport-first) is
    # the PRIMARY source. Sportmonks match_date is fallback only.
    if _sport == "cricket":
        # 1) broadcast_schedule (SuperSport-first, authoritative for SA)
        d, t = _from_broadcast_schedule()
        if d:
            log.debug("_resolve_kickoff_time[cricket:broadcast] %s → %s %s", match_key, d, t)
            return (d, t)
        # 2) sportmonks_fixtures (team names are display-style, match_date UTC)
        if home and away:
            try:
                from scrapers.db_connect import connect_odds_db as _cfn
                from scrapers.edge.edge_config import DB_PATH as _DP
                _c = _cfn(_DP)
                try:
                    _row = _c.execute(
                        """
                        SELECT match_date FROM sportmonks_fixtures
                        WHERE match_date IS NOT NULL AND match_date != ''
                          AND (home_team LIKE ? OR away_team LIKE ?)
                          AND (home_team LIKE ? OR away_team LIKE ?)
                        ORDER BY match_date DESC LIMIT 1
                        """,
                        (f"%{home}%", f"%{home}%", f"%{away}%", f"%{away}%"),
                    ).fetchone()
                    if _row and _row[0]:
                        d, t = _fmt_iso_utc(_row[0])
                        if d:
                            log.debug("_resolve_kickoff_time[cricket:sportmonks] %s → %s %s",
                                      match_key, d, t)
                            return (d, t)
                finally:
                    _c.close()
            except Exception as exc:
                log.debug("_resolve_kickoff_time[cricket]: sportmonks_fixtures failed: %s", exc)
        # 3) commence_time
        d, t = _fmt_iso_utc(commence_time)
        if d:
            log.debug("_resolve_kickoff_time[cricket:commence_time] %s → %s %s", match_key, d, t)
            return (d, t)
        # 4) date from match_key
        return _date_from_match_key()

    # ── Rugby path ───────────────────────────────────────────
    # BUILD-KO-SUPERSPORT-PRIMARY-01: broadcast_schedule (SuperSport-first) is
    # the PRIMARY source and is the ONLY path that provides a time component for
    # rugby. rugby_fixtures is date-only and remains as a date fallback.
    if _sport == "rugby":
        # 1) broadcast_schedule (SuperSport-first, authoritative for SA)
        d, t = _from_broadcast_schedule()
        if d:
            log.debug("_resolve_kickoff_time[rugby:broadcast] %s → %s %s", match_key, d, t)
            return (d, t)
        # 2) rugby_fixtures (date-only fallback)
        if home and away:
            try:
                from scrapers.db_connect import connect_odds_db as _cfn
                from scrapers.edge.edge_config import DB_PATH as _DP
                _c = _cfn(_DP)
                try:
                    _row = _c.execute(
                        """
                        SELECT match_date FROM rugby_fixtures
                        WHERE match_date IS NOT NULL AND match_date != ''
                          AND (home_team LIKE ? OR away_team LIKE ?)
                          AND (home_team LIKE ? OR away_team LIKE ?)
                        ORDER BY match_date DESC LIMIT 1
                        """,
                        (f"%{home}%", f"%{home}%", f"%{away}%", f"%{away}%"),
                    ).fetchone()
                    if _row and _row[0]:
                        d, t = _fmt_date_only(_row[0])
                        if d:
                            log.debug("_resolve_kickoff_time[rugby:rugby_fixtures] %s → %s (date-only)",
                                      match_key, d)
                            return (d, "")
                finally:
                    _c.close()
            except Exception as exc:
                log.debug("_resolve_kickoff_time[rugby]: rugby_fixtures failed: %s", exc)
        # 3) commence_time
        d, t = _fmt_iso_utc(commence_time)
        if d:
            return (d, t)
        # 4) date from match_key
        return _date_from_match_key()

    # ── MMA / boxing path ────────────────────────────────────
    if _sport == "mma":
        # 1) mma_fixtures (date-only)
        if home and away:
            try:
                from scrapers.db_connect import connect_odds_db as _cfn
                from scrapers.edge.edge_config import DB_PATH as _DP
                _c = _cfn(_DP)
                try:
                    _row = _c.execute(
                        """
                        SELECT fight_date FROM mma_fixtures
                        WHERE fight_date IS NOT NULL AND fight_date != ''
                          AND (fighter1_name LIKE ? OR fighter2_name LIKE ?)
                          AND (fighter1_name LIKE ? OR fighter2_name LIKE ?)
                        ORDER BY fight_date DESC LIMIT 1
                        """,
                        (f"%{home}%", f"%{home}%", f"%{away}%", f"%{away}%"),
                    ).fetchone()
                    if _row and _row[0]:
                        d, t = _fmt_date_only(_row[0])
                        if d:
                            log.debug("_resolve_kickoff_time[mma:mma_fixtures] %s → %s (date-only)",
                                      match_key, d)
                            return (d, "")
                finally:
                    _c.close()
            except Exception as exc:
                log.debug("_resolve_kickoff_time[mma]: mma_fixtures failed: %s", exc)
        # 2) broadcast_schedule
        d, t = _from_broadcast_schedule()
        if d:
            return (d, t)
        # 3) commence_time
        d, t = _fmt_iso_utc(commence_time)
        if d:
            return (d, t)
        # 4) date from match_key
        return _date_from_match_key()

    # ── Unknown sport fallback ───────────────────────────────
    # Try commence_time first, then match_key date
    d, t = _fmt_iso_utc(commence_time)
    if d:
        return (d, t)
    return _date_from_match_key()


def _format_kickoff_display(commence_time: str) -> str:
    """Format commence time as 'Today 19:30 SAST' or 'Wed 04 Mar, 15:00 SAST'.

    BUILD-KO-TIME-FIX-01: returns empty string (not "TBC") when parse fails.
    Callers should use _resolve_kickoff_time() for sport-aware resolution.
    """
    ct_sa = _parse_date(commence_time)
    if not ct_sa:
        return ""
    from datetime import datetime as dt_cls, timedelta
    from zoneinfo import ZoneInfo
    now = dt_cls.now(ZoneInfo(config.TZ))
    today = now.date()
    if ct_sa.date() == today:
        return f"Today {ct_sa.strftime('%H:%M')} SAST"
    if ct_sa.date() == today + timedelta(days=1):
        return f"Tomorrow {ct_sa.strftime('%H:%M')} SAST"
    return f"{ct_sa.strftime('%a %d %b, %H:%M')} SAST"


async def _fetch_hot_tips_all_sports() -> list[dict]:
    """Scan all major sports for value bets. Uses 15-min cache."""
    import time
    from scripts.odds_client import fetch_odds_cached, fair_probabilities, find_best_sa_odds, calculate_ev
    from scripts.odds_client import kelly_stake as calc_kelly

    cache_entry = _hot_tips_cache.get("global")
    if cache_entry and (time.time() - cache_entry["ts"]) < HOT_TIPS_CACHE_TTL:
        return cache_entry["tips"]

    all_tips: list[dict] = []
    near_miss_tips: list[dict] = []

    for sport_key in HOT_TIPS_SCAN_SPORTS:
        try:
            result = await fetch_odds_cached(sport_key, regions="eu,uk,au", markets="h2h")
            if not result["ok"] or not result.get("data"):
                continue

            for event in result["data"]:
                if not event.get("bookmakers"):
                    continue

                fair_probs = fair_probabilities(event)
                best_entries = find_best_sa_odds(event)

                for entry in best_entries:
                    prob = fair_probs.get(entry.outcome, 0)
                    if prob <= 0:
                        continue
                    ev_pct = calculate_ev(entry.price, prob)

                    # Build odds snapshots from all bookmakers for edge rating
                    odds_snaps = []
                    for bk in event.get("bookmakers", []):
                        for market in bk.get("markets", []):
                            if market.get("key") != "h2h":
                                continue
                            for oc in market.get("outcomes", []):
                                odds_snaps.append({
                                    "bookmaker": bk.get("key", ""),
                                    "outcome": oc.get("name", ""),
                                    "odds": oc.get("price"),
                                    "timestamp": event.get("commence_time", ""),
                                })

                    model_pred = {
                        "outcome": entry.outcome,
                        "confidence": min(prob, 0.95),
                        "implied_prob": prob,
                    }

                    edge = calculate_edge_rating(odds_snaps, model_pred)
                    tip = {
                        "event_id": event.get("id", ""),
                        "sport_key": sport_key,
                        "home_team": event.get("home_team") or "TBD",
                        "away_team": event.get("away_team") or "TBD",
                        "commence_time": event.get("commence_time", ""),
                        "outcome": entry.outcome,
                        "odds": entry.price,
                        "bookmaker": entry.bookmaker,
                        "ev": round(ev_pct, 1),
                        "prob": round(prob * 100),
                        "kelly": round(calc_kelly(entry.price, prob, fraction=0.5) * 100, 1),
                        "edge_rating": edge,
                    }
                    if edge == EdgeRating.HIDDEN or (0 < ev_pct < 2.0):
                        if ev_pct > 0:
                            near_miss_tips.append(tip | {"edge_rating": "bronze"})
                        continue  # Filter out low-confidence tips

                    all_tips.append(tip)
        except Exception as exc:
            log.warning("Hot tips scan error for %s: %s", sport_key, exc)
            continue

    # Sort by edge rating (diamond first), then EV descending
    _rating_order = {EdgeRating.DIAMOND: 0, EdgeRating.GOLD: 1, EdgeRating.SILVER: 2, EdgeRating.BRONZE: 3}
    all_tips.sort(key=lambda t: (_rating_order.get(t.get("edge_rating", ""), 9), -t["ev"]))
    top_tips = _allocate_tips_by_tier(all_tips, min_per_tier=3)

    near_miss_tips.sort(key=lambda t: (-t.get("ev", 0), -t.get("prob", 0)))
    thin_state = {
        "state": "none" if top_tips else ("below_threshold" if near_miss_tips else "no_tips"),
        "candidate_count": len(near_miss_tips),
        "weaker_tip": near_miss_tips[0] if near_miss_tips else None,
    }
    # CARD-BUILD-01: Population gate
    from card_pipeline import verify_card_populates, _log_card_population_failure
    top_tips = [t for t in top_tips if verify_card_populates(t, t.get("match_id", ""))[0]]
    _hot_tips_cache["global"] = {"tips": top_tips, "ts": time.time(), "thin_slate": thin_state}
    return top_tips


async def _show_hot_tips(update: Update, ctx: ContextTypes.DEFAULT_TYPE, user_id: int) -> None:
    """Entry point for Hot Tips from sticky keyboard."""
    await _do_hot_tips_flow(update.effective_chat.id, ctx.bot, user_id=user_id)


def _sort_tips_for_snapshot(tips: list[dict]) -> list[dict]:
    """Return a sorted+filtered copy of tips using the same order as _build_hot_tips_page.

    CARDWIRE-FIX: snapshot must match the displayed order so ep:pick:N / edge:detail:N
    look up the correct tip.  Applies the identical filter, zero-signal cap, and sort.
    """
    result = [t for t in tips if (t.get("ev") or 0) > 0 and (t.get("edge_score") or 0) >= 40]
    _tier_order = {"diamond": 0, "gold": 1, "silver": 2, "bronze": 3}
    result.sort(key=lambda t: (
        _tier_order.get(str(t.get("edge_tier") or t.get("display_tier") or "bronze").lower(), 9),
        -(t.get("ev") or 0),
    ))
    return _allocate_tips_by_tier(result, min_per_tier=3)


_EDGE_PICKS_INDEX_TIERS = ("diamond", "gold", "silver", "bronze")


def _hot_tip_tier_key(tip: dict | None) -> str:
    if not tip:
        return "bronze"
    raw = (
        tip.get("edge_tier")
        or tip.get("display_tier")
        or tip.get("edge_rating")
        or tip.get("tier")
        or "bronze"
    )
    key = str(raw).lower().strip()
    return key if key in _EDGE_PICKS_INDEX_TIERS else "bronze"


def _tier_counts_for_index(tips: list[dict]) -> dict[str, int]:
    counts = {key: 0 for key in _EDGE_PICKS_INDEX_TIERS}
    for tip in tips or []:
        counts[_hot_tip_tier_key(tip)] += 1
    return counts


def _filter_hot_tips_by_tier(tips: list[dict], tier_key: str) -> list[dict]:
    key = str(tier_key or "").lower().strip()
    if key not in _EDGE_PICKS_INDEX_TIERS:
        return []
    return [tip for tip in tips or [] if _hot_tip_tier_key(tip) == key]


def _build_index_markup(user_tier: str, tier_counts: dict[str, int]) -> InlineKeyboardMarkup:
    rows: list[list[InlineKeyboardButton]] = []
    counts = {key: int((tier_counts or {}).get(key, 0) or 0) for key in _EDGE_PICKS_INDEX_TIERS}
    for key in _EDGE_PICKS_INDEX_TIERS:
        locked = edge_picks_index_tier_locked(user_tier, key)
        label = EDGE_LABELS.get(key, key.upper()).replace(" EDGE", "").title()
        emoji = EDGE_EMOJIS.get(key, "")
        suffix = "Upgrade" if locked else f"{counts[key]} live"
        callback = f"hot:upgrade:tier:{key}" if locked else f"hot:tier:{key}"
        rows.append([InlineKeyboardButton(
            f"{emoji} {label} · {suffix}",
            callback_data=callback,
        )])
    return InlineKeyboardMarkup(rows)


async def _build_hot_tips_page(
    tips: list[dict], page: int = 0,
    user_tier: str = "diamond", remaining_views: int = 999,
    streak: dict | None = None,
    consecutive_misses: int = 0,
    hit_rate_7d: float = 0.0,
    resource_count: int = 0,
    user_id: int = 0,
    thin_slate_mode: str = "no_tips",
    thin_slate_fixtures: list[dict] | None = None,
    thin_slate_weaker_tip: dict | None = None,
    last_10_results: list[str] | None = None,
    roi_7d: float | None = None,
    recently_settled: list[dict] | None = None,
    yesterday_results: list[dict] | None = None,
    edge_tracker_summary: dict | None = None,
) -> tuple[str, InlineKeyboardMarkup, list]:
    """Build text + keyboard for a single page of hot tips (max 4 per page).

    Wave 27-UX: Header shows 7D hit rate, live edge count, resource count.
    Double blank lines between cards. Footer bold hierarchy + emoji CTAs.
    """
    from tier_gate import get_edge_access_level
    from renderers.edge_renderer import format_return as _fmt_ret

    last_10_results = [r for r in (last_10_results or []) if r in ("hit", "miss")]
    recently_settled = [
        edge for edge in (recently_settled or [])
        if edge.get("result") in ("hit", "miss")
    ][:HOT_TIPS_RECENT_SETTLED_LIMIT]
    yesterday_results = [
        edge for edge in (yesterday_results or [])
        if edge.get("result") in ("hit", "miss")
    ]

    # R12-BUILD-01 Fix 3: Filter negative EV BEFORE pagination so the count
    # in the header matches the number of rendered cards.
    # Fix 8: Also gate composite_score >= 40 (Bronze threshold) — sub-threshold cards never show.
    tips = [t for t in tips if (t.get("ev") or 0) > 0 and (t.get("edge_score") or 0) >= 40]
    # BUILD-TIER-ORDER: Diamond > Gold > Silver > Bronze, then EV descending within tier.
    _tier_order = {"diamond": 0, "gold": 1, "silver": 2, "bronze": 3}
    tips.sort(key=lambda t: (
        _tier_order.get(str(t.get("edge_tier") or t.get("display_tier") or "bronze").lower(), 9),
        -(t.get("ev") or 0),
    ))
    tips = _allocate_tips_by_tier(tips, min_per_tier=3)
    total = len(tips)
    total_pages = max((total + HOT_TIPS_PAGE_SIZE - 1) // HOT_TIPS_PAGE_SIZE, 1)
    page = max(0, min(page, total_pages - 1))
    start = page * HOT_TIPS_PAGE_SIZE
    end = start + HOT_TIPS_PAGE_SIZE
    page_tips = tips[start:end]

    if not page_tips:
        thin_slate_fixtures = thin_slate_fixtures or []
        lines = ["💎 <b>Top Edge Picks</b>"]
        if thin_slate_mode == "below_threshold":
            lines.extend([
                "",
                "No Gold or Diamond-grade edges have cleared our bar yet.",
                "A couple of early leans are forming, but nothing belongs on the main card yet.",
            ])
            if thin_slate_weaker_tip:
                weaker_odds = thin_slate_weaker_tip.get("odds", 0) or 0
                lines.extend([
                    "",
                    "👀 <b>Watchlist</b>",
                    (
                        f"{_get_sport_emoji_for_api_key(thin_slate_weaker_tip.get('sport_key', ''))} "
                        f"<b>{h(thin_slate_weaker_tip.get('home_team', ''))} vs "
                        f"{h(thin_slate_weaker_tip.get('away_team', ''))}</b> — "
                        f"{h(thin_slate_weaker_tip.get('outcome', 'Lean'))} @ {weaker_odds:.2f}"
                    ),
                    "<i>Worth monitoring, but not strong enough to post as a main edge yet.</i>",
                ])
        else:
            lines.extend([
                "",
                "It's a thin slate right now, so there is nothing premium to post yet.",
            ])
        if thin_slate_fixtures:
            lines.append("")
            lines.extend(_format_fixture_preview_lines(thin_slate_fixtures, "Up Next"))
        else:
            lines.extend([
                "",
                "A lighter board today, but we will keep tracking prices as markets open.",
            ])
        lines.extend(["", "<i>Scanning for edges - check again closer to kickoff.</i>"])
        return (
            "\n".join(lines),
            InlineKeyboardMarkup([
                [InlineKeyboardButton("⚽ My Matches", callback_data="yg:all:0")],
            ]),
            tips,
        )

    # Header — Wave 27-UX: hit rate + resource count + live edge count
    # Only show hit rate when >= threshold (avoids displaying poor early numbers)
    if hit_rate_7d >= HIT_RATE_DISPLAY_THRESHOLD:
        header = f"🔥 <b>Top Edge Picks — {hit_rate_7d:.0f}% Predicted Correctly (7D)</b>"
    else:
        header = f'🔥 <b>Top Edge Picks — {total} Live Edge{"s" if total != 1 else ""} Found</b>'

    _res_str = f"{resource_count:,}" if resource_count > 0 else "1,000+"
    subline = (
        f"<i>Scanned {len(DB_LEAGUES)} leagues, {_res_str} external resources"
        f" and all major SA bookmakers.</i>"
    )
    _banner = _qa_banner(user_id) if user_id else ""
    lines = [f"{_banner}{header}" if _banner else header, subline]

    _settled_total = (edge_tracker_summary or {}).get("total", 0)
    _stats_eligible = _settled_total >= MIN_SAMPLE_FOR_STATS

    if _stats_eligible:
        track_record_line = _format_hot_tips_track_record_line(last_10_results, roi_7d)
        if track_record_line:
            lines.append(track_record_line)
        else:
            fallback_track_record_line = _format_edge_tracker_record_line(
                edge_tracker_summary,
                label="📊 7D",
                include_roi=False,
            )
            if fallback_track_record_line:
                lines.append(fallback_track_record_line)

    # Third header line: live edge count (Wave 27-UX replaces streak badge)
    _edge_s = "s" if total != 1 else ""
    lines.append(f"<b>✅ {total} Live Edge{_edge_s} Found</b>")

    lines.append("")

    if _stats_eligible:
        yesterday_lines = _build_hot_tips_yesterday_lines(yesterday_results)
        if yesterday_lines:
            lines.extend(yesterday_lines)
            lines.append("")

    # P0-2 FIX: Batch-check narrative_cache for ESPN evidence to determine true MODEL ONLY status.
    # confirming_signals==0 does not mean no ESPN data — standings/form/H2H can exist at sub-0.65
    # signal strength. Only show [MODEL ONLY] when the cached narrative has NO ESPN data at all.
    _nc_espn_match_ids: set[str] = set()
    try:
        from scrapers.db_connect import connect_odds_db as _nc_conn_fn
        from scrapers.edge.edge_config import DB_PATH as _nc_db_path
        import json as _nc_json
        _page_match_ids = [
            tip.get("match_id") or tip.get("event_id") or ""
            for tip in page_tips
        ]
        _page_match_ids = [mid for mid in _page_match_ids if mid]
        if _page_match_ids:
            _nc_conn = _nc_conn_fn(_nc_db_path)
            _nc_placeholders = ",".join("?" * len(_page_match_ids))
            _nc_rows = _nc_conn.execute(
                f"SELECT match_id, evidence_json FROM narrative_cache "
                f"WHERE match_id IN ({_nc_placeholders})",
                _page_match_ids,
            ).fetchall()
            _nc_conn.close()
            for _nc_row in _nc_rows:
                _nc_mid = _nc_row[0]
                _nc_ejson = _nc_row[1]
                if not _nc_ejson:
                    continue
                try:
                    _nc_cm = _nc_json.loads(_nc_ejson).get("coverage_metrics", {})
                    if (
                        _nc_cm.get("standings_available")
                        or (_nc_cm.get("form_games_count") or 0) > 0
                        or (_nc_cm.get("h2h_games_count") or 0) > 0
                    ):
                        _nc_espn_match_ids.add(_nc_mid)
                except (ValueError, TypeError):
                    pass
    except Exception:
        pass  # Graceful fallback — MODEL ONLY logic unchanged if cache unavailable

    # BUILD-12 / TIER-FIX: Batch-fetch authoritative tiers from edge_results.
    # Reads edge_tier directly — same trust-DB principle as Fix A/B.
    _fresh_tiers: dict[str, str] = {}
    try:
        _pt_keys = [t.get("match_id") or t.get("event_id") or "" for t in page_tips]
        _pt_keys = [k for k in _pt_keys if k]
        if _pt_keys:
            from scrapers.db_connect import connect_odds_db as _b12_conn_fn
            from scrapers.edge.edge_config import DB_PATH as _b12_db_path
            _b12_conn = _b12_conn_fn(_b12_db_path)
            _b12_conn.row_factory = lambda c, r: dict(zip([col[0] for col in c.description], r))
            _b12_ph = ",".join("?" * len(_pt_keys))
            _b12_rows = _b12_conn.execute(
                f"SELECT match_key, edge_tier "
                f"FROM edge_results "
                f"WHERE match_key IN ({_b12_ph}) AND result IS NULL "
                f"ORDER BY recommended_at DESC",
                _pt_keys,
            ).fetchall()
            _b12_conn.close()
            _b12_seen: set[str] = set()
            for _b12_r in _b12_rows:
                _b12_mk = _b12_r["match_key"]
                if _b12_mk in _b12_seen:
                    continue
                _b12_seen.add(_b12_mk)
                _b12_tier = (_b12_r.get("edge_tier") or "bronze").strip().lower()
                if _b12_tier not in ("diamond", "gold", "silver", "bronze"):
                    _b12_tier = "bronze"
                _fresh_tiers[_b12_mk] = _b12_tier
    except Exception:
        pass  # Graceful fallback — stale display_tier used if edge_results unavailable

    # BUILD-CTA-FIX Fix 3+4: Pre-fetch broadcast details in parallel before render loop.
    # Uses asyncio.to_thread() with 3s timeout — matches My Matches pattern at line ~5040.
    # Passes display-format names (e.g. "Arsenal") so fuzzy_match_broadcast matches correctly.
    # DB-sourced tips carry normalized keys (e.g. "arsenal") — _display_team_name converts them.
    _ht_bc_raw = await asyncio.gather(*[
        asyncio.wait_for(
            asyncio.to_thread(
                _get_broadcast_details,
                home_team=_display_team_name(tip.get("home_team") or ""),
                away_team=_display_team_name(tip.get("away_team") or ""),
                league_key=tip.get("league_key", ""),
            ),
            timeout=3.0,
        )
        for tip in page_tips
    ], return_exceptions=True)
    _ht_bc_infos: list[dict] = [
        bc if isinstance(bc, dict) else {"broadcast": "", "kickoff": ""}
        for bc in _ht_bc_raw
    ]

    # Track buttons per tip + locked counts for footer
    tip_buttons: list[tuple[int, str, str]] = []  # (index, match_key, access_level)
    diamond_locked = 0
    gold_locked = 0
    page_tier_counts: dict[str, int] = {}
    for tip in page_tips:
        _pt_mk = tip.get("match_id") or tip.get("event_id") or ""
        tier_key = _fresh_tiers.get(_pt_mk) or str(tip.get("display_tier", tip.get("edge_rating", EdgeRating.BRONZE))).lower().strip()
        page_tier_counts[tier_key] = page_tier_counts.get(tier_key, 0) + 1
    last_section_tier = ""

    for i, tip in enumerate(page_tips, start + 1):
        _tip_mk_for_tier = tip.get("match_id") or tip.get("event_id") or ""
        edge_tier = _fresh_tiers.get(_tip_mk_for_tier) or str(tip.get("display_tier", tip.get("edge_rating", "bronze"))).lower().strip()
        access = get_edge_access_level(user_tier, edge_tier)

        if edge_tier != last_section_tier:
            lines.append(_format_hot_tips_section_header(edge_tier, page_tier_counts.get(edge_tier, 0)))
            lines.append("")
            last_section_tier = edge_tier

        # Count locked/blurred for footer
        if access == "locked" and edge_tier == "diamond":
            diamond_locked += 1
        elif access in ("locked", "blurred") and edge_tier == "gold":
            gold_locked += 1

        tier_emoji = EDGE_EMOJIS.get(edge_tier, "🥉")
        sport_emoji = _get_sport_emoji_for_api_key(tip.get("sport_key", ""))
        _confirming, _total_signals, _model_only = _edge_signal_meta(tip.get("edge_v2"))
        # P0-2: Suppress [MODEL ONLY] if narrative_cache has any ESPN data for this match
        _tip_mid = tip.get("match_id") or tip.get("event_id") or ""
        if _model_only and _tip_mid and _tip_mid in _nc_espn_match_ids:
            _model_only = False
        tip["_ht_model_only"] = _model_only
        tip["_ht_confirming_signals"] = _confirming
        tip["_ht_total_signals"] = _total_signals
        # R7-BUILD-02: P1-MODEL-ONLY — only visible to admins
        _model_tag = " [MODEL ONLY]" if (_model_only and user_id in config.ADMIN_IDS) else ""
        home_raw = tip.get("home_team") or ""
        away_raw = tip.get("away_team") or ""
        home = h(home_raw)
        away = h(away_raw)
        league_display = tip.get("league", "")

        # Broadcast details — use pre-fetched result (BUILD-CTA-FIX Fix 3+4)
        # BUILD-DATE-KICKOFF-PRIORITY-01: commence_time is authoritative; bc_data is fallback
        bc_data = _ht_bc_infos[i - start - 1]
        kickoff = ""
        if tip.get("commence_time"):
            kickoff = _format_kickoff_display(tip["commence_time"])
        if not kickoff:
            kickoff = bc_data.get("kickoff", "")
        # Fallback: extract date from match_id (e.g. "...vs_team_2026-03-05")
        if not kickoff:
            import re as _re_mid
            _date_m = _re_mid.search(r"(\d{4}-\d{2}-\d{2})$", tip.get("match_id") or tip.get("event_id") or "")
            if _date_m:
                try:
                    from datetime import datetime as _dt_cls
                    from zoneinfo import ZoneInfo as _ZI
                    _md = _dt_cls.strptime(_date_m.group(1), "%Y-%m-%d")
                    _now = _dt_cls.now(_ZI(config.TZ))
                    _today = _now.date()
                    if _md.date() == _today:
                        kickoff = "Today"
                    elif _md.date() == _today + __import__("datetime").timedelta(days=1):
                        kickoff = "Tomorrow"
                    else:
                        kickoff = _md.strftime("%a %d %b")
                except Exception:
                    pass
        broadcast_raw = bc_data.get("broadcast", "")
        # W84-Q5/Q11: Store computed broadcast + league metadata in tip for detail-view header
        # inheritance. edge:detail instant baseline path reads these back to complete the header.
        tip["_bc_kickoff"] = kickoff
        tip["_bc_broadcast"] = ""  # FIX-DSTV-CHANNEL-PERM-01: channel display permanently off
        tip["_bc_league"] = league_display
        # BUILD-CARDWIRE: lightweight summary card enrichment — no DB call
        if not tip.get("pick"):
            tip["pick"] = tip.get("outcome") or tip.get("home_team") or ""
        tip["all_odds_count"] = len(tip.get("odds_by_bookmaker") or {})

        # Line 2: league · 📅 kickoff
        # BUILD-PREGEN-FIX Fix 5: 📅 prefix on kickoff for visibility
        info_parts = [league_display]
        if kickoff and kickoff != "TBC":
            info_parts.append(f"📅 {kickoff}")
        info_line = " · ".join(info_parts)

        match_key = tip.get("match_id") or tip.get("event_id", "")
        _remember_hot_tip_origin(user_id, match_key, page)

        _signal_hint = _format_signal_count_hint(_confirming, _total_signals, _model_only)
        _signal_rows = _extract_signal_rows(tip.get("edge_v2"), home_raw, away_raw)
        _premium_hook = _format_hot_tips_premium_hook(
            tip,
            edge_tier=edge_tier,
            access_level=access,
            confirming=_confirming,
            total=_total_signals,
            model_only=_model_only,
            signal_rows=_signal_rows,
        )
        _premium_signal_hint = _format_hot_tips_signal_hint(
            _confirming,
            _total_signals,
            _model_only,
            edge_tier=edge_tier,
            signal_rows=_signal_rows,
        )
        _signal_hint_suffix = ""
        if not _premium_hook:
            _signal_hint = _premium_signal_hint or _signal_hint
            _signal_hint_suffix = f" · {_signal_hint}" if _signal_hint else ""

        if access == "full":
            # 3-line card: sport emoji + match + tier badge, info, outcome @ odds → return
            outcome = h(tip.get("outcome", ""))
            # Normalise from outcome_key for consistency (positional key → display name)
            _ok = (tip.get("outcome_key") or "").lower()
            if _ok == "draw":
                outcome = "Draw"
            elif _ok == "home":
                _home = h(tip.get("home_team", ""))
                if _home:
                    outcome = _home
            elif _ok == "away":
                _away = h(tip.get("away_team", ""))
                if _away:
                    outcome = _away
            odds_val = tip.get("odds", 0)
            ret_amount = odds_val * 300 if odds_val else 0
            ret_str = f"R{ret_amount:,.0f}" if ret_amount else ""
            odds_str = f"{odds_val:.2f}" if odds_val else ""
            line3 = (
                f"    {outcome} @ {odds_str} → {ret_str} on R300{_signal_hint_suffix}"
                if odds_val else
                f"    {outcome}{_signal_hint_suffix}"
            )
            card_lines = [
                f"<b>[{i}]</b> {sport_emoji} <b>{home} vs {away}</b> {tier_emoji}{_model_tag}",
                f"    {info_line}",
            ]
            if _premium_hook:
                card_lines.append(f"    {_premium_hook}")
            card_lines.append(line3)
            lines.append("\n".join(card_lines))
        elif access == "partial":
            # TIER-GATE-IMPL-01: PARTIAL — return amount visible, NO odds/EV/bookmaker
            odds_val = tip.get("odds", 0)
            ret_amount = odds_val * 300 if odds_val else 0
            ret_str = f"R{ret_amount:,.0f}" if ret_amount else "R?"
            card_lines = [
                f"<b>[{i}]</b> {sport_emoji} <b>{home} vs {away}</b> {tier_emoji}{_model_tag}",
                f"    {info_line}",
            ]
            card_lines.append(f"    💰 {ret_str} return on R300 — upgrade for full details")
            lines.append("\n".join(card_lines))
        elif access == "blurred":
            # 3-line card: sport emoji + match + tier badge, info, return only
            odds_val = tip.get("odds", 0)
            ret_amount = odds_val * 300 if odds_val else 0
            ret_str = f"R{ret_amount:,.0f}" if ret_amount else "R?"
            card_lines = [
                f"<b>[{i}]</b> {sport_emoji} <b>{home} vs {away}</b> {tier_emoji}{_model_tag}",
                f"    {info_line}",
            ]
            if _premium_hook:
                card_lines.append(f"    {_premium_hook}")
            card_lines.append(f"    💰 {ret_str} return on R300{_signal_hint_suffix}")
            lines.append("\n".join(card_lines))
        else:
            # Locked: sport emoji + match + tier badge, info, lock message
            card_lines = [
                f"<b>[{i}]</b> {sport_emoji} <b>{home} vs {away}</b> {tier_emoji}{_model_tag}",
                f"    {info_line}",
            ]
            if _premium_hook:
                card_lines.append(f"    {_premium_hook}")
            card_lines.append("    Our highest-conviction pick.")
            lines.append("\n".join(card_lines))

        tip_buttons.append((i, match_key, access))
        # SPACING LAW (locked 5 March 2026):
        # - Between cards: exactly \n\n (one visible blank line)
        # - Between sections: exactly \n\n
        # - Within footer CTA block: \n only (no blank lines)
        # - NEVER more than \n\n anywhere in Hot Tips output
        lines.append("")  # → produces \n\n via join (one blank line between cards)

    if recently_settled:
        lines.append("━━━ <b>Recent Results</b>")
        lines.append("")
        lines.extend(_build_recently_settled_lines(recently_settled))

    # ── Footer CTA (W27-UX-FIX: tight spacing, bold hierarchy) ──
    locked_total = diamond_locked + gold_locked
    footer_proof_line = _format_edge_tracker_record_line(edge_tracker_summary)
    if user_tier == "bronze" and locked_total > 0:
        if consecutive_misses >= 3:
            # Card loop already left one "" → \n\n before divider
            lines.append("━━━")
            lines.append("")  # one blank line after divider
            lines.append("The market has been tight recently.\nCheck back for fresh edges.")
        else:
            tier_breakdown = []
            if diamond_locked:
                tier_breakdown.append(f"{diamond_locked} 💎")
            if gold_locked:
                tier_breakdown.append(f"{gold_locked} 🥇")
            lock_detail = " — " + " · ".join(tier_breakdown) if tier_breakdown else ""

            portfolio = _get_portfolio_line()

            # Card loop already left one "" → \n\n before divider
            lines.append("━━━")
            lines.append("")  # one blank line after divider
            # Footer CTA lines: consecutive, no gaps
            lines.append(f"🔒 <b>{locked_total} edges locked</b>{lock_detail}")
            if portfolio:
                lines.append(portfolio)
            if footer_proof_line:
                lines.append(footer_proof_line)
            lines.append("🔑 Unlock all → /subscribe")
            fd = _founding_days_left()
            if fd > 0:
                lines.append(f"🎁 <b>Founding Member:</b> R699/yr Diamond — {fd} days left")
    elif user_tier == "gold" and diamond_locked > 0:
        # Card loop already left one "" → \n\n before divider
        lines.append("━━━")
        lines.append("")  # one blank line after divider
        lines.append(
            f'💎 <b>{diamond_locked} Diamond pick{"s" if diamond_locked != 1 else ""} locked</b>'
        )
        if footer_proof_line:
            lines.append(footer_proof_line)
        lines.append("🔑 Upgrade → /subscribe")
    # Diamond: no footer

    text = "\n".join(lines)

    # Build buttons — 1 per row: [N] {sport} {home} vs {away} {tier/lock}
    buttons: list[list[InlineKeyboardButton]] = []
    for idx, match_key, access in tip_buttons:
        tip = page_tips[idx - start - 1]
        _btn_sport = _get_sport_emoji_for_api_key(tip.get("sport_key", ""))
        h_name = tip.get("home_team") or "TBD"
        a_name = tip.get("away_team") or "TBD"
        if access in ("full", "partial"):
            # BUILD-PREGEN-FIX-2 AC-5: Use display_tier (already zero-signal-capped in the
            # card loop at line 8413-8415) as single source of truth for tier badge.
            # Previous code read _fresh_tiers first which bypassed the zero-signal cap.
            _btn_fresh = tip.get("display_tier", tip.get("edge_rating", "bronze"))
            _btn_tier = EDGE_EMOJIS.get(_btn_fresh, "🥉")
            cb = f"ep:pick:{idx - 1}"
        else:
            _btn_tier = "🔒"
            cb = f"hot:upgrade:{_shorten_cb_key(match_key)}"
        label = f"[{idx}] {_btn_sport} {_abbreviate_btn(h_name)} vs {_abbreviate_btn(a_name)} {_btn_tier}"
        buttons.append([InlineKeyboardButton(label, callback_data=cb)])

    # Navigation row — only row allowed to have 2 buttons side-by-side
    has_prev = page > 0
    has_next = page < total_pages - 1
    if has_prev and has_next:
        buttons.append([
            InlineKeyboardButton("← Previous", callback_data=f"hot:page:{page - 1}"),
            InlineKeyboardButton("Next →", callback_data=f"hot:page:{page + 1}"),
        ])
    elif has_prev:
        buttons.append([InlineKeyboardButton("← Previous", callback_data=f"hot:page:{page - 1}")])
    elif has_next:
        buttons.append([
            InlineKeyboardButton("↩️ Back", callback_data="nav:main"),
            InlineKeyboardButton("Next →", callback_data=f"hot:page:{page + 1}"),
        ])
    else:
        buttons.append([InlineKeyboardButton("↩️ Back", callback_data="nav:main")])

    return (text, InlineKeyboardMarkup(buttons), tips)


# ---------------------------------------------------------------------------
# P4-07 — CLV bet_log_writer wiring
# ---------------------------------------------------------------------------

def _blw_get_edge_id(match_key: str, db_path: str) -> str | None:
    """Return edge_id from edge_results for the live edge on match_key.

    Runs in a thread (called via asyncio.to_thread).  Uses connect_odds_db
    so WAL mode and busy_timeout rules are satisfied.
    """
    try:
        from scrapers.db_connect import connect_odds_db as _blw_conn_fn
        _blw_c = _blw_conn_fn(db_path)
        import sqlite3 as _blw_sqlite
        _blw_c.row_factory = _blw_sqlite.Row
        _blw_row = _blw_c.execute(
            "SELECT edge_id FROM edge_results "
            "WHERE match_key = ? AND result IS NULL "
            "ORDER BY id DESC LIMIT 1",
            (match_key,),
        ).fetchone()
        _blw_c.close()
        return _blw_row["edge_id"] if _blw_row else None
    except Exception:
        return None


async def _blw_log_tip(tip: dict, user_id_str: str) -> None:
    """Async coroutine: log one tip to bet_recommendations_log (non-blocking).

    Looks up edge_id from edge_results, then fires log_recommendation().
    Errors are swallowed — CLV logging must never block or crash serving.
    """
    try:
        from scrapers.sharp.bet_log_writer import log_recommendation as _blw_rec
        from scrapers.edge.edge_config import DB_PATH as _BLW_DB

        match_key = tip.get("match_id") or tip.get("event_id") or ""
        if not match_key:
            return

        edge_id = tip.get("edge_id") or await asyncio.to_thread(
            _blw_get_edge_id, match_key, _BLW_DB
        )
        if not edge_id:
            return  # No live edge_results row — skip

        bet_type = tip.get("outcome_key") or "home"
        raw_bk = tip.get("bookmaker_key") or "unknown"
        _v2 = tip.get("edge_v2") or {}
        model_prob_raw = tip.get("prob")  # stored as 0-100 integer
        model_prob = float(model_prob_raw) / 100.0 if model_prob_raw else None

        # BUG-CLV-01: Extract kickoff from tip or fixture_mapping
        _blw_kickoff = tip.get("commence_time") or tip.get("_bc_kickoff") or None
        if not _blw_kickoff:
            # Look up kickoff from fixture_mapping
            try:
                _blw_fm = await asyncio.to_thread(
                    lambda: (lambda c: (
                        c.execute(
                            "SELECT kickoff FROM fixture_mapping WHERE match_key = ? LIMIT 1",
                            (match_key,),
                        ).fetchone(),
                        c.close(),
                    )[0])(__import__("scrapers.db_connect", fromlist=["connect_odds_db"]).connect_odds_db(_BLW_DB))
                )
                if _blw_fm:
                    _blw_kickoff = _blw_fm[0]
            except Exception:
                pass
        # EDGE-FIX-01: last-resort — extract date from match_key suffix (YYYY-MM-DD)
        if not _blw_kickoff and match_key:
            import re as _blw_re
            _blw_dm = _blw_re.search(r"(\d{4}-\d{2}-\d{2})$", match_key)
            if _blw_dm:
                _blw_kickoff = _blw_dm.group(1) + "T00:00:00+00:00"

        # BUG-CLV-02: Extract fair_odds from model probability (Shin devigged)
        _blw_fair_odds = None
        if model_prob and model_prob > 0.01 and model_prob < 1.0:
            _blw_fair_odds = round(1.0 / model_prob, 4)

        # EDGE-FIX-05: DB dedup guard — only log once per (match_key, bet_type) per 24h
        _blw_exists = await asyncio.to_thread(
            lambda: (lambda c: (
                c.execute(
                    "SELECT 1 FROM bet_recommendations_log "
                    "WHERE match_key = ? AND bet_type = ? "
                    "AND logged_at > datetime('now', '-24 hours') LIMIT 1",
                    (match_key, bet_type),
                ).fetchone(),
                c.close(),
            )[0])(__import__("scrapers.db_connect", fromlist=["connect_odds_db"]).connect_odds_db(_BLW_DB))
        )
        if _blw_exists:
            return  # Already logged — skip duplicate

        await _blw_rec(
            edge_id=edge_id,
            match_key=match_key,
            sport=tip.get("sport_key") or "soccer",
            league=tip.get("league_key") or "",
            edge_tier=tip.get("display_tier") or tip.get("edge_rating") or "bronze",
            bet_type=bet_type,
            recommended_odds=float(tip.get("odds") or 0),
            bookmaker=raw_bk,
            predicted_ev=float(tip.get("ev") or 0),
            model_prob=model_prob,
            composite_score=tip.get("edge_score") or tip.get("composite_score"),
            confirming_signals=(
                _v2.get("confirming_signals") if isinstance(_v2, dict) else None
            ),
            kickoff=_blw_kickoff,
            fair_odds=_blw_fair_odds,
        )
        log.debug("P4-07: logged edge_id=%s match=%s user=%s", edge_id, match_key, user_id_str)
    except Exception as _blw_exc:
        log.debug("P4-07 _blw_log_tip failed: %s", _blw_exc)


def _blw_fire_tips(tips: list[dict], user_id_str: str) -> None:
    """Schedule fire-and-forget bet_log_writer tasks for each tip.

    Deduplicates by (match_key, bet_type, user_id, today) so refreshes
    and re-renders don't produce duplicate rows.  Broadcast paths pass
    user_id_str='channel'.
    """
    from datetime import date as _blw_date
    _today = _blw_date.today().isoformat()
    for tip in tips:
        mk = tip.get("match_id") or tip.get("event_id") or ""
        bt = tip.get("outcome_key") or "home"
        key = f"{mk}:{bt}:{user_id_str}:{_today}"
        if mk and key not in _bet_log_seen:
            _bet_log_seen.add(key)
            asyncio.create_task(_blw_log_tip(tip, user_id_str))


async def _do_hot_tips_flow(chat_id: int, bot, user_id: int | None = None) -> None:
    """Core Hot Tips — fetch ALL tips, show tiered display (Wave 21)."""
    HOT_TIPS_INDEX_ENABLED = os.getenv("HOT_TIPS_INDEX_ENABLED", "0") == "1"
    if user_id:
        _sentry_user(user_id)
    _ht_cache_state = "warm" if _hot_tips_cache.get("global", {}).get("tips") else "cold"
    _sentry_tags(flow="hot_tips", route="_do_hot_tips_flow", cache_state=_ht_cache_state)
    # W84-P0: Warm path — serve from cache instantly, no spinner
    _cached_tips = _hot_tips_cache.get("global", {}).get("tips", [])
    if _cached_tips:
        _wm_tier = "bronze"
        _wm_rv = 999
        if user_id:
            _wm_tier = await get_effective_tier(user_id)
            try:
                from db_connection import get_connection as _get_conn
                _wm_conn = _get_conn()
                _, _wm_rv, _ = gate_edges(_cached_tips, user_id, _wm_tier, _wm_conn)
                _wm_conn.close()
            except Exception as _wm_err:
                log.warning("Warm tips gate failed: %s", _wm_err)
        _wm_consec = 0
        if user_id:
            try:
                _wm_user = await db.get_user(user_id)
                _wm_consec = getattr(_wm_user, "consecutive_misses", 0) or 0
            except Exception:
                pass
        _wm_proof, _wm_summary = await asyncio.gather(
            _get_hot_tips_result_proof(),
            _get_edge_tracker_summary(7),
        )
        # BUILD-STALE-EV: Age-gated EV refresh — if cache > 10 min old, re-check live EVs
        # to suppress tips whose EV has gone negative since last precompute cycle.
        import time as _stale_ev_t
        _stale_ev_entry = _hot_tips_cache.get("global", {})
        _stale_ev_age = _stale_ev_t.time() - _stale_ev_entry.get("ts", 0)
        if _stale_ev_age > 600:  # > 10 minutes old → refresh EVs before serving
            log.debug("[BUILD-STALE-EV] Cache age %.0fs > 600s — refreshing tip EVs on warm path", _stale_ev_age)
            _cached_tips = await _refresh_tip_evs(_cached_tips)
        _wm_text, _wm_markup, _wm_rendered = await _build_hot_tips_page(
            _cached_tips, page=0, user_tier=_wm_tier,
            remaining_views=_wm_rv, consecutive_misses=_wm_consec,
            hit_rate_7d=((_wm_proof.get("stats_7d", {}).get("hit_rate", 0) or 0) * 100),
            user_id=user_id or 0,
            last_10_results=_wm_proof.get("last_10_results"),
            roi_7d=_wm_proof.get("roi_7d"),
            recently_settled=_wm_proof.get("recently_settled"),
            yesterday_results=_wm_proof.get("yesterday_results"),
            edge_tracker_summary=_wm_summary,
        )
        # BUILD-W3: send Edge Picks image card (falls back to text on render failure)
        # P0-FIX-02: use _wm_rendered (filtered+sorted) — NOT raw _cached_tips.
        # Raw cache may contain ev<=0 or edge_score<40 tips that buttons exclude.
        # FIX-HOT-TIPS-EMPTY-CARD-01: skip card when no renderable tips.
        if HOT_TIPS_INDEX_ENABLED:
            _wm_tier_counts = _tier_counts_for_index(_wm_rendered)
            _wm_card_data = build_edge_picks_index_data(_wm_tier, _wm_tier_counts)
            await send_card_or_fallback(
                bot=bot, chat_id=chat_id,
                template="edge_picks_index.html", data=_wm_card_data,  # A2-INDEX-SWAP
                text_fallback=_wm_text, markup=_build_index_markup(_wm_tier, _wm_tier_counts),
            )
        elif _wm_rendered:
            _wm_card_data = build_edge_picks_data(_wm_rendered, page=1, per_page=HOT_TIPS_PAGE_SIZE, user_tier=_wm_tier)
            await send_card_or_fallback(
                bot=bot, chat_id=chat_id,
                template="edge_picks.html", data=_wm_card_data,
                text_fallback=_wm_text, markup=_wm_markup,
            )
        else:
            await bot.send_message(chat_id, _wm_text, parse_mode=ParseMode.HTML, reply_markup=_wm_markup)
        # W84-HT2: freeze page identity at render time
        if user_id:
            _ht_page_state[user_id] = 0
            _ht_tips_snapshot[user_id] = _wm_rendered
        # P4-07: log recommendations to bet_recommendations_log (non-blocking)
        _blw_fire_tips(_cached_tips, str(user_id or "channel"))
        return

    # W84-P1: Fast serving path — read pre-computed edges from edge_results table.
    # This is a pure SQL SELECT (~5ms), zero edge computation, zero contention.
    # Populated by previous precompute cycles that survive scraper writes.
    _fast_tips = await asyncio.to_thread(_load_tips_from_edge_results, 20)
    if _fast_tips:
        log.info("Cold path: serving %d tips from edge_results (fast path)", len(_fast_tips))
        # Populate game_tips_cache for tap detail
        for _ft in _fast_tips:
            _fid = _ft.get("match_id", "")
            if _fid:
                _game_tips_cache[_fid] = [_ft]
        # Populate in-memory cache (marked slightly stale so precompute replaces soon)
        import time as _t_fast
        _hot_tips_cache["global"] = {"tips": _fast_tips, "ts": _t_fast.time() - HOT_TIPS_CACHE_TTL + 120}

        # Get user tier + remaining views for display
        _fast_tier = "bronze"
        _fast_rv = 999
        if user_id:
            _fast_tier = await get_effective_tier(user_id)
            try:
                from db_connection import get_connection as _get_conn
                _fast_conn = _get_conn()
                _, _fast_rv, _ = gate_edges(_fast_tips, user_id, _fast_tier, _fast_conn)
                _fast_conn.close()
            except Exception:
                pass
        _fast_consec = 0
        if user_id:
            try:
                _fast_user = await db.get_user(user_id)
                _fast_consec = getattr(_fast_user, "consecutive_misses", 0) or 0
            except Exception:
                pass
        _fast_proof, _fast_summary = await asyncio.gather(
            _get_hot_tips_result_proof(),
            _get_edge_tracker_summary(7),
        )
        # BUILD-14a: Refresh EV values — filter stale negative-EV tips from fast path
        try:
            _fast_tips = await _refresh_tip_evs(_fast_tips)
        except Exception as _b14a_err:
            log.debug("BUILD-14a EV refresh failed (graceful fallback): %s", _b14a_err)
        _fast_text, _fast_markup, _fast_rendered = await _build_hot_tips_page(
            _fast_tips, page=0, user_tier=_fast_tier,
            remaining_views=_fast_rv, consecutive_misses=_fast_consec,
            hit_rate_7d=((_fast_proof.get("stats_7d", {}).get("hit_rate", 0) or 0) * 100),
            user_id=user_id or 0,
            last_10_results=_fast_proof.get("last_10_results"),
            roi_7d=_fast_proof.get("roi_7d"),
            recently_settled=_fast_proof.get("recently_settled"),
            yesterday_results=_fast_proof.get("yesterday_results"),
            edge_tracker_summary=_fast_summary,
        )
        # BUILD-W3: send Edge Picks image card (falls back to text on render failure)
        # P0-FIX-02: use _fast_rendered (filtered+sorted) — NOT raw _fast_tips.
        # FIX-HOT-TIPS-EMPTY-CARD-01: skip card when no renderable tips.
        if HOT_TIPS_INDEX_ENABLED:
            _fast_tier_counts = _tier_counts_for_index(_fast_rendered)
            _fast_card_data = build_edge_picks_index_data(_fast_tier, _fast_tier_counts)
            await send_card_or_fallback(
                bot=bot, chat_id=chat_id,
                template="edge_picks_index.html", data=_fast_card_data,  # A2-INDEX-SWAP
                text_fallback=_fast_text, markup=_build_index_markup(_fast_tier, _fast_tier_counts),
            )
        elif _fast_rendered:
            _fast_card_data = build_edge_picks_data(_fast_rendered, page=1, per_page=HOT_TIPS_PAGE_SIZE, user_tier=_fast_tier)
            await send_card_or_fallback(
                bot=bot, chat_id=chat_id,
                template="edge_picks.html", data=_fast_card_data,
                text_fallback=_fast_text, markup=_fast_markup,
            )
        else:
            await bot.send_message(chat_id, _fast_text, parse_mode=ParseMode.HTML, reply_markup=_fast_markup)
        # W84-HT2: freeze page identity at render time
        if user_id:
            _ht_page_state[user_id] = 0
            _ht_tips_snapshot[user_id] = _fast_rendered
        # P4-07: log recommendations to bet_recommendations_log (non-blocking)
        _blw_fire_tips(_fast_tips, str(user_id or "channel"))
        # Trigger background refresh so next tap gets freshly computed tips
        asyncio.create_task(_fetch_hot_tips_from_db())
        return

    # Cold path: no edge_results available (very first run, new install) — show brief spinner
    loading = await bot.send_message(
        chat_id,
        "⚽ Scanning odds across all bookmakers.",
        parse_mode=ParseMode.HTML,
    )
    stop_spinner = asyncio.Event()
    spinner_task = asyncio.create_task(
        _run_spinner(loading, "Scanning odds across all bookmakers", stop_spinner),
    )

    try:
        # Primary: our own scraped data from odds.db (free, fast, always available)
        tips = await _fetch_hot_tips_from_db()

        # Fallback: Odds API if odds.db returned nothing
        if not tips:
            try:
                tips = await _fetch_hot_tips_all_sports()
            except Exception as exc:
                log.warning("Odds API fallback also failed: %s", exc)
                tips = []

        # Store tips in game_tips_cache so tip detail can find them
        for tip in tips:
            eid = tip.get("event_id", "")
            if eid:
                _game_tips_cache[eid] = [tip]

        # Get user tier + remaining views (for display only — no filtering)
        user_tier = "bronze"
        remaining_views = 999
        if user_id:
            user_tier = await get_effective_tier(user_id)
            try:
                from db_connection import get_connection as _get_conn
                _odds_conn = _get_conn()
                _, remaining_views, _ = gate_edges(tips, user_id, user_tier, _odds_conn)
                _odds_conn.close()
            except Exception as _gate_err:
                log.warning("Tier gating check failed: %s", _gate_err)
    finally:
        stop_spinner.set()
        await spinner_task

    try:
        await loading.delete()
    except Exception:
        pass

    # W75-FIX: Cache coverage logging (checks memory first, DB as fallback)
    if tips:
        _cached_count = 0
        _uncached_keys = []
        for _tip in tips:
            _mk = _tip.get("match_id", "")
            if _mk:
                if _mk in _analysis_cache:
                    _cached_count += 1
                else:
                    _uncached_keys.append(_mk)
        # Check DB for any not in memory (async batch)
        if _uncached_keys:
            async def _count_db_hits():
                _n = 0
                for _k in _uncached_keys:
                    try:
                        if await _get_cached_narrative(_k):
                            _n += 1
                    except Exception:
                        pass
                return _n
            _db_hits = await _count_db_hits()
            _cached_count += _db_hits
        log.info("CACHE COVERAGE: %d/%d edges have cached narratives", _cached_count, len(tips))

    _result_proof, _edge_tracker_summary = await asyncio.gather(
        _get_hot_tips_result_proof(),
        _get_edge_tracker_summary(7),
    )
    _hit_rate = (_result_proof.get("stats_7d", {}).get("hit_rate", 0) or 0) * 100

    # Fetch resource count (total odds snapshots) for header (Wave 27-UX)
    _res_count = 0
    try:
        from services.odds_service import get_db_stats as _get_db_stats
        _db_stats = await _get_db_stats()
        _res_count = _db_stats.get("total_rows", 0)
    except Exception:
        pass

    # Fetch consecutive_misses for footer CTA gating (Wave 26A)
    _consec_misses = 0
    if user_id:
        try:
            _cm_user = await db.get_user(user_id)
            _consec_misses = getattr(_cm_user, "consecutive_misses", 0) or 0
        except Exception:
            pass

    # BUILD-14a: Refresh EV values — filter stale negative-EV tips from cold path
    try:
        tips = await _refresh_tip_evs(tips)
    except Exception as _b14a_err:
        log.debug("BUILD-14a EV refresh failed (graceful fallback): %s", _b14a_err)

    # Show ALL tips with tiered display — thin-slate fallback adds fixtures when no edge clears the bar
    thin_slate = (_hot_tips_cache.get("global") or {}).get("thin_slate", {})
    thin_slate_fixtures = []
    if not tips and user_id:
        thin_slate_fixtures = await _get_user_fixture_preview(user_id, limit=3, days_ahead=7)
    text, markup, _rendered_tips = await _build_hot_tips_page(
        tips, page=0, user_tier=user_tier, remaining_views=remaining_views,
        consecutive_misses=_consec_misses,
        hit_rate_7d=_hit_rate, resource_count=_res_count,
        user_id=user_id or 0,
        thin_slate_mode=thin_slate.get("state", "no_tips"),
        thin_slate_fixtures=thin_slate_fixtures,
        thin_slate_weaker_tip=thin_slate.get("weaker_tip"),
        last_10_results=_result_proof.get("last_10_results"),
        roi_7d=_result_proof.get("roi_7d"),
        recently_settled=_result_proof.get("recently_settled"),
        yesterday_results=_result_proof.get("yesterday_results"),
        edge_tracker_summary=_edge_tracker_summary,
    )
    # BUILD-W3: send Edge Picks image card (falls back to text on render failure)
    # P0-FIX-02: use _rendered_tips (filtered+sorted) — NOT raw tips.
    # FIX-HOT-TIPS-EMPTY-CARD-01: skip card when no renderable tips.
    if HOT_TIPS_INDEX_ENABLED:
        _cold_tier_counts = _tier_counts_for_index(_rendered_tips)
        _cold_card_data = build_edge_picks_index_data(user_tier, _cold_tier_counts)
        await send_card_or_fallback(
            bot=bot, chat_id=chat_id,
            template="edge_picks_index.html", data=_cold_card_data,  # A2-INDEX-SWAP
            text_fallback=text, markup=_build_index_markup(user_tier, _cold_tier_counts),
        )
    elif _rendered_tips:
        _cold_card_data = build_edge_picks_data(_rendered_tips, page=1, per_page=HOT_TIPS_PAGE_SIZE, user_tier=user_tier)
        await send_card_or_fallback(
            bot=bot, chat_id=chat_id,
            template="edge_picks.html", data=_cold_card_data,
            text_fallback=text, markup=markup,
        )
    else:
        await bot.send_message(chat_id, text, parse_mode=ParseMode.HTML, reply_markup=markup)
    # W84-HT2: freeze page identity at render time (cold path)
    if user_id:
        _ht_page_state[user_id] = 0
        _ht_tips_snapshot[user_id] = _rendered_tips
    # P4-07: log recommendations to bet_recommendations_log (non-blocking)
    _blw_fire_tips(tips, str(user_id or "channel"))

    # Wave 25C: log edge views for all visible tips
    if user_id and tips:
        for tip in tips[:HOT_TIPS_PAGE_SIZE]:
            eid = tip.get("match_id") or tip.get("event_id", "")
            etier = tip.get("display_tier", tip.get("edge_rating", "bronze"))
            if eid:
                try:
                    await db.log_edge_view(user_id, eid, etier)
                except Exception:
                    pass


async def freetext_handler(update: Update, ctx: ContextTypes.DEFAULT_TYPE) -> None:
    """Handle free text — team input during onboarding OR AI chat."""
    user = update.effective_user
    raw_text = update.message.text or ""
    ob = _onboarding_state.get(user.id)

    # Subscription email capture (plan selected, awaiting email)
    if user.id in _subscribe_state and _subscribe_state[user.id].get("awaiting_email"):
        handled = await _handle_sub_email(update, user.id)
        if handled:
            return

    # Settings team edit (check before onboarding)
    if user.id in _team_edit_state:
        handled = await _handle_settings_team_edit(update, ctx)
        if handled:
            return

    # Custom bankroll input during onboarding
    if ob and ob.get("_bankroll_custom"):
        raw = update.message.text.strip().replace("R", "").replace("r", "").replace(",", "").replace(" ", "")
        try:
            amount = float(raw)
            if amount < 50:
                await update.message.reply_text(
                    "⚠️ Minimum R50. Try again or tap Back to use a preset.",
                    parse_mode=ParseMode.HTML,
                )
                return
            ob["bankroll"] = amount
            ob.pop("_bankroll_custom", None)
            # REMOVED: Daily Alerts step — go directly to summary (FIX-ONBOARDING-OB-NAV-01)
            ob["step"] = "summary"
            await send_card_or_fallback(
                bot=_g_bot, chat_id=update.message.chat_id,
                template="onboarding_summary.html",
                data=build_onboarding_summary_data(ob),
                text_fallback="<b>Step 4/5: Your profile summary</b>\n\nAll set! Tap Next to choose your plan.",
                markup=InlineKeyboardMarkup([
                    [InlineKeyboardButton("➡️ Next — Choose Plan", callback_data="ob_nav:plan")],
                    [InlineKeyboardButton("✏️ Edit Sports & Teams", callback_data="ob_edit:sports")],
                ]),
            )
        except ValueError:
            await update.message.reply_text(
                "Please enter a number, e.g. <b>750</b> or <b>3000</b>.",
                parse_mode=ParseMode.HTML,
            )
        return

    # Text-based team input (comma-separated)
    if ob and ob.get("_team_input_sport"):
        await _handle_team_text_input(update, ctx, ob)
        return

    # Legacy manual favourite input mode (single name)
    if ob and ob.get("_fav_manual") and ob.get("_fav_manual_sport"):
        sport_key = ob["_fav_manual_sport"]
        text_input = update.message.text.strip()
        match, suggestions = fuzzy_match_team(text_input, sport_key)

        if match:
            if sport_key not in ob["favourites"]:
                ob["favourites"][sport_key] = []
            if match not in ob["favourites"][sport_key]:
                ob["favourites"][sport_key].append(match)
            ob["_fav_manual"] = False
            ob["_fav_manual_sport"] = None
            await update.message.reply_text(
                f"✅ Added <b>{match}</b>!",
                parse_mode=ParseMode.HTML,
            )
        elif suggestions:
            ob["_suggestions"] = suggestions
            rows = []
            for i, s in enumerate(suggestions):
                rows.append([InlineKeyboardButton(s, callback_data=f"ob_fav_suggest:{sport_key}:{i}")])
            rows.append([InlineKeyboardButton("❌ None of these", callback_data=f"ob_fav_manual:{sport_key}")])
            _sug_sport = config.ALL_SPORTS.get(sport_key)
            _sug_dicts = [{"label": s, "confidence": 75} for s in suggestions]
            await send_card_or_fallback(
                bot=_g_bot, chat_id=update.effective_chat.id,
                template="onboarding_fuzzy_suggest.html",
                data=build_onboarding_fuzzy_suggest_data(
                    sport_key,
                    _sug_sport.label if _sug_sport else sport_key,
                    _sug_sport.emoji if _sug_sport else "🏅",
                    input_text=text_input,
                    suggestions=_sug_dicts,
                ),
                text_fallback="🤔 Did you mean one of these?",
                markup=InlineKeyboardMarkup(rows),
                message_to_edit=None,
            )
        else:
            if sport_key not in ob["favourites"]:
                ob["favourites"][sport_key] = []
            ob["favourites"][sport_key].append(text_input)
            ob["_fav_manual"] = False
            ob["_fav_manual_sport"] = None
            await update.message.reply_text(
                f"✅ Added <b>{h(text_input)}</b>!",
                parse_mode=ParseMode.HTML,
            )
        return

    # Normal AI chat
    user_msg = update.message.text
    thinking_msg = await update.message.reply_text("🤖 <i>Thinking…</i>", parse_mode=ParseMode.HTML)

    try:
        resp = await claude.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=SYSTEM_PROMPT,
            messages=[{"role": "user", "content": user_msg}],
        )
        reply = resp.content[0].text
    except Exception as exc:
        log.warning("Claude chat error: %s", exc)
        reply = "⚠️ Couldn't process that. Try again or use the menu buttons."

    # Edit the "Thinking..." message in-place with the response (no stale message)
    try:
        await thinking_msg.edit_text(reply, parse_mode=ParseMode.HTML, reply_markup=kb_nav())
    except Exception:
        # Fallback: delete thinking and send new if edit fails
        try:
            await thinking_msg.delete()
        except Exception:
            pass
        await update.message.reply_text(reply, parse_mode=ParseMode.HTML, reply_markup=kb_nav())


