async def cmd_today(update: Update, ctx: ContextTypes.DEFAULT_TYPE) -> None:
    """P3-02: /today — send a DigestMessage of today's top picks.

    Each pick is a compact 2-line card (tier + teams + kickoff + confidence).
    Tapping a pick edits the message in-place to show the full DetailMessage.
    Tapping ← Back edits back to the DigestMessage (today:back callback).
    """
    user_id = update.effective_user.id if update.effective_user else 0
    chat_id = update.effective_message.chat_id if update.effective_message else 0

    tips: list[dict] = []
    # Primary: in-memory hot tips cache (fastest, already computed)
    _cached = _hot_tips_cache.get("global", {}).get("tips", [])
    if _cached:
        tips = list(_cached)
    else:
        # Cold path: load from DB
        try:
            tips = await _fetch_hot_tips_from_db()
        except Exception as _e:
            log.warning("/today cold fetch failed: %s", _e)

    # Filter out zero/negative EV and build cb_keys
    tips = [t for t in tips if (t.get("ev") or 0) > 0]

    # P3-06: Apply user's tier and sport filters
    if user_id:
        try:
            import user_settings as _us_today  # noqa: PLC0415
            _pref = await asyncio.to_thread(_us_today.get_settings, user_id)
            _active_tiers = set(_pref["tier_filter"].split(","))
            _active_sports = set(_pref["sport_filter"].split(","))
            tips = [
                t for t in tips
                if (t.get("edge_tier") or "bronze") in _active_tiers
                and (
                    t.get("sport_key", "soccer") in _active_sports
                    or (t.get("sport_key") == "combat"
                        and ("mma" in _active_sports or "boxing" in _active_sports))
                )
            ]
        except Exception as _pf_err:
            log.debug("/today pref filter error (fail-open): %s", _pf_err)

    for t in tips:
        mk = t.get("match_id") or t.get("match_key") or ""
        if mk:
            t["cb_key"] = _shorten_cb_key(mk)
        # Populate sport_emoji if missing
        if not t.get("sport_emoji"):
            t["sport_emoji"] = _get_sport_emoji_for_api_key(t.get("sport_key", ""))

    _msg = update.message or update.effective_message
    try:
        _png, _caption, markup = DigestMessage.build_photo(tips)
        if _msg:
            await _msg.reply_photo(
                photo=io.BytesIO(_png),
                caption=_caption,
                parse_mode=ParseMode.HTML,
                reply_markup=markup,
            )
    except RuntimeError as _img_err:
        log.warning("/today image card failed, falling back to text: %s", _img_err)
        text, markup = DigestMessage.build(tips)
        if _msg:
            await _msg.reply_text(text, parse_mode=ParseMode.HTML, reply_markup=markup)

    # Freeze snapshot for today:back
    if user_id:
        _today_digest_snapshot[user_id] = list(tips)


async def _do_picks_flow(chat_id: int, bot, user_id: int) -> None:
    """Core picks logic — fetch cached odds, compute EV, display pick cards."""
    # Load user profile
    user = await db.get_user(user_id)
    risk_key = (user.risk_profile if user else None) or "moderate"
    profile = config.RISK_PROFILES.get(risk_key, config.RISK_PROFILES["moderate"])
    experience = (user.experience_level if user else None) or "casual"

    # Get user's preferred leagues (fall back to all mapped leagues)
    prefs = await db.get_user_sport_prefs(user_id)
    if prefs:
        league_keys = list({p.league for p in prefs if p.league})
    else:
        league_keys = list(config.SPORTS_MAP.keys())

    if not league_keys:
        await bot.send_message(
            chat_id,
            "🏟️ You haven't selected any leagues yet!\n\n"
            "Tap below to set up your sports.",
            parse_mode=ParseMode.HTML,
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("⚽ Set Up Sports", callback_data="settings:sports")],
            ]),
        )
        return

    # Send loading message with animated spinner
    loading_msg = await bot.send_message(
        chat_id,
        "⚽ Running Edge-AI analysis.",
        parse_mode=ParseMode.HTML,
    )
    stop_spinner = asyncio.Event()
    spinner_task = asyncio.create_task(
        _run_spinner(loading_msg, "Running Edge-AI analysis", stop_spinner),
    )

    # Fetch picks via the engine
    user_bankroll = getattr(user, "bankroll", None) if user else None
    try:
        result = await get_picks_for_user(
            league_keys=league_keys,
            risk_profile=risk_key,
            max_picks=5,
            bankroll=user_bankroll,
        )
    except Exception as exc:
        log.error("Picks engine error: %s", exc)
        result = {"ok": False, "picks": [], "total_events": 0, "total_markets": 0,
                  "quota_remaining": "?", "errors": [str(exc)]}
    finally:
        stop_spinner.set()
        await spinner_task

    # Delete loading message
    try:
        await loading_msg.delete()
    except Exception:
        pass

    # Handle quota exhausted
    if result.get("errors") and any("quota_exhausted" in str(e) for e in result["errors"]):
        await bot.send_message(
            chat_id,
            "⚠️ <b>We've hit our daily data limit.</b>\n\n"
            "Picks will refresh tomorrow. Your bankroll is safe — "
            "no bets placed automatically.",
            parse_mode=ParseMode.HTML,
            reply_markup=kb_nav(),
        )
        return

    # No picks found
    if not result["ok"] or not result["picks"]:
        risk_label = profile["label"]
        if experience == "newbie":
            text = (
                "📭 <b>No value bets found right now</b>\n\n"
                f"Scanned {result['total_events']} events across your leagues.\n\n"
                "Nothing cleared the board yet.\n"
                "Check back later - we keep scanning through the day."
            )
        else:
            text = (
                "📭 <b>No value bets found right now</b>\n\n"
                f"Scanned {result['total_events']} events | "
                f"{result['total_markets']} markets\n\n"
                f"Nothing clears your {risk_label} profile right now.\n"
                "Check back when more markets open or adjust your risk in /settings."
            )
        await bot.send_message(
            chat_id, text, parse_mode=ParseMode.HTML,
            reply_markup=kb_nav(),
        )
        return

    picks = result["picks"]

    # Send header
    await bot.send_message(
        chat_id,
        f"💰 <b>Found {len(picks)} value bet{'s' if len(picks) != 1 else ''}!</b>\n\n"
        f"📊 Scanned {result['total_events']} events | "
        f"{result['total_markets']} markets",
        parse_mode=ParseMode.HTML,
    )

    # Send individual pick cards
    for i, pick in enumerate(picks, 1):
        card = format_engine_pick_card(pick, i, experience)
        await bot.send_message(
            chat_id, card, parse_mode=ParseMode.HTML,
        )

    # Final footer with navigation
    await bot.send_message(
        chat_id,
        f"<i>{len(picks)} tips found.</i>",
        parse_mode=ParseMode.HTML,
        reply_markup=kb_nav(),
    )


