def _build_edge_only_section(tips: list[dict]) -> str:
    """W84-P1E: Concrete edge-only fallback when full narrative is unavailable.

    Used when _generate_narrative_v2 fails or returns "No current edge data".
    Always produces all 4 sections with real tip data — never empty boilerplate.
    """
    if not tips:
        return (
            "📋 <b>The Setup</b>\nThis fixture is still waiting for enough verified detail to take on a fuller shape.\n\n"
            "🎯 <b>The Edge</b>\nCheck SA Bookmaker Odds below for the latest lines.\n\n"
            "⚠️ <b>The Risk</b>\nNo signals available. Size conservatively.\n\n"
            "🏆 <b>Verdict</b>\nVerify odds before committing."
        )
    best = max(tips, key=lambda t: t.get("ev", 0))
    ev = best.get("ev", 0)
    odds = best.get("odds", 0)
    bk = best.get("bookmaker", best.get("bookie", "the market")) or "the market"
    outcome = best.get("outcome", "")
    # BUILD-11: Translate positional keys to team display names (same as BUILD-7 in _build_game_buttons).
    _home_disp = best.get("home_team") or ""
    _away_disp = best.get("away_team") or ""
    if outcome == "home" and _home_disp:
        outcome = _home_disp
    elif outcome == "away" and _away_disp:
        outcome = _away_disp
    elif outcome == "draw":
        outcome = "Draw"
    prob = best.get("prob", 0)
    ev_str = f"+{ev:.1f}%" if ev > 0 else f"{ev:.1f}%"
    edge_score = best.get("edge_score", 0) or 0
    if edge_score >= 70:
        edge_desc = (
            f"Strong edge detected — {ev_str} expected value on {h(outcome)}. "
            f"Fair probability at {prob}% vs {odds:.2f} at {h(bk)}. "
            f"Multiple indicators align here."
        )
        verdict = f"Back {h(outcome)} at {odds:.2f} with {h(bk)}."
    elif edge_score >= 55:
        edge_desc = (
            f"Solid edge on {h(outcome)} — {ev_str} expected value. "
            f"Fair probability at {prob}% vs {odds:.2f} at {h(bk)}."
        )
        verdict = f"Back {h(outcome)} at {odds:.2f} with {h(bk)}."
    elif edge_score >= 40:
        edge_desc = (
            f"Some value on {h(outcome)} — {ev_str} expected value. "
            f"Price of {odds:.2f} at {h(bk)} vs our {prob}% fair probability estimate."
        )
        verdict = f"Lean on {h(outcome)} at {odds:.2f}. Size conservatively."
    else:
        edge_desc = (
            f"A pricing edge — {ev_str} expected value on {h(outcome)} at {odds:.2f} ({h(bk)}). "
            f"No supporting signals; this is a model-only play."
        )
        verdict = "Small punt only if the price appeals — treat as speculative."
    # D-06 FIX: Include competition name, match date, and odds structure in Setup.
    # Tip data has all three: league key, match_id date suffix, odds+bookmaker.
    _d06_league_key = best.get("league", "")
    _d06_league_name = LEAGUE_DISPLAY_NAMES.get(
        _d06_league_key, _d06_league_key.replace("_", " ").title() if _d06_league_key else ""
    )
    _d06_mid = best.get("match_id", "")
    _d06_date = ""
    if _d06_mid:
        _d06_ds = _d06_mid.rsplit("_", 1)[-1]
        if len(_d06_ds) == 10:
            try:
                from datetime import date as _d06_dt
                _d06_date = _d06_dt.fromisoformat(_d06_ds).strftime("%d %b %Y")
            except ValueError:
                pass
    _d06_ctx = " · ".join(p for p in [_d06_league_name, _d06_date] if p)
    _d06_odds_ctx = ""
    _d06_prefix = (_d06_ctx + " — " if _d06_ctx else "")

    # Edge-score-aware setup text
    if edge_score >= 55:
        setup = _d06_prefix + "This fixture looks like one that will declare its character early rather than hand it over before kickoff."
    elif edge_score >= 40:
        setup = _d06_prefix + "The opening phase should matter here, because the contest still has to establish its own rhythm."
    else:
        setup = _d06_prefix + "This shapes up as the sort of fixture where the game itself has to set the tone before anything else."
    return (
        f"📋 <b>The Setup</b>\n{setup}\n\n"
        f"🎯 <b>The Edge</b>\n{edge_desc}\n\n"
        f"⚠️ <b>The Risk</b>\nNo verified context to cross-check against. Size for uncertainty.\n\n"
        f"🏆 <b>Verdict</b>\n{verdict}"
    )

# W79: Callback key shortening — Telegram limits callback_data to 64 bytes.
# edge:detail:{key} = 13 + len(key). Max key length = 51 chars.
_CB_MAX_KEY = 51
_cb_key_map: dict[str, str] = {}  # short_hash → full_match_key


def _shorten_cb_key(match_key: str, max_len: int = _CB_MAX_KEY) -> str:
    """Return a callback-safe key. Long keys get a 10-char MD5 hash stored in _cb_key_map.

    max_len defaults to _CB_MAX_KEY (calibrated for the shortest prefix, edge:detail:).
    For longer prefixes (e.g. edge:breakdown: = 15 chars) pass max_len explicitly so
    the total callback_data stays within Telegram's 64-byte hard limit.
    """
    if len(match_key) <= max_len:
        return match_key
    import hashlib
    short = hashlib.md5(match_key.encode()).hexdigest()[:10]
    _cb_key_map[short] = match_key
    return short


def _resolve_cb_key(key: str) -> str:
    """Resolve a callback key back to the full match_key."""
    return _cb_key_map.get(key, key)


def _remember_hot_tip_origin(user_id: int, match_key: str, page: int) -> None:
    """Remember which Hot Tips page rendered a given match for this user."""
    if user_id and match_key:
        _ht_detail_origin[(user_id, match_key)] = max(page, 0)


def _resolve_hot_tips_back_page(
    user_id: int, match_key: str = "", fallback_page: int | None = None,
) -> int:
    """Resolve the exact Hot Tips list page to return to for a detail surface."""
    if user_id and match_key:
        stored_page = _ht_detail_origin.get((user_id, match_key))
        if stored_page is not None:
            return stored_page
    if fallback_page is not None:
        return max(fallback_page, 0)
    return max(_ht_page_state.get(user_id, 0), 0)


def _build_hot_tips_detail_rows(
    user_id: int,
    match_key: str = "",
    primary_button: InlineKeyboardButton | None = None,
    extra_rows: list[list[InlineKeyboardButton]] | None = None,
    fallback_page: int | None = None,
    user_tier: str | None = None,
    has_narrative: bool = False,
) -> list[list[InlineKeyboardButton]]:
    """Build the normalized Hot Tips detail action surface."""
    back_page = _resolve_hot_tips_back_page(user_id, match_key, fallback_page)
    rows: list[list[InlineKeyboardButton]] = []
    if primary_button is not None:
        rows.append([primary_button])
    # BUILD-VERDICT-ONLY-STRIP-AI-BREAKDOWN-01 — AI Breakdown surface stripped.
    # Verdict on the card image is now the only narrative surface. has_narrative
    # / user_tier / match_key params retained for callsite compatibility.
    rows.append([InlineKeyboardButton(
        "↩️ Back", callback_data=f"hot:back:{back_page}",
    )])
    return rows


def _remember_odds_compare_origin(
    user_id: int,
    event_id: str,
    source: str,
    *,
    match_key: str = "",
    back_page: int | None = None,
) -> None:
    """Remember where an odds-comparison screen should route back to."""
    if not user_id or not event_id:
        return
    _odds_compare_origin[(user_id, event_id)] = {
        "source": source,
        "match_key": match_key,
        "back_page": back_page,
    }


def _build_odds_compare_back_button(user_id: int, event_id: str) -> InlineKeyboardButton:
    """Return the correct back button for an odds-comparison surface."""
    origin = _odds_compare_origin.get((user_id, event_id), {})
    if origin.get("source") == "edge_picks":
        match_key = str(origin.get("match_key") or event_id)
        fallback_page = origin.get("back_page")
        back_page = _resolve_hot_tips_back_page(
            user_id,
            match_key,
            fallback_page if isinstance(fallback_page, int) else None,
        )
        return InlineKeyboardButton(
            "↩️ Back", callback_data=f"hot:back:{back_page}",
        )
    return InlineKeyboardButton("↩️ Back", callback_data=f"yg:game:{event_id}")

# ── W60-CACHE: Persistent narrative cache in odds.db ──────────
_NARRATIVE_CACHE_TTL = 43200  # 12 hours
_NARRATIVE_DB_PATH = str(ODDS_DB_PATH)
# FIX-DROP-SONNET-POLISH-W82-CANONICAL-01: _NARRATIVE_MODEL deleted. The
# narrative is now deterministic (narrative_spec._render_baseline) — no LLM.


def _ensure_narrative_cache_table() -> None:
    """Create narrative_cache table if it doesn't exist."""
    from db_connection import get_connection
    conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
    try:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS narrative_cache (
                match_id TEXT PRIMARY KEY,
                narrative_html TEXT NOT NULL,
                model TEXT NOT NULL,
                edge_tier TEXT NOT NULL,
                tips_json TEXT NOT NULL,
                odds_hash TEXT NOT NULL,
                evidence_json TEXT,
                narrative_source TEXT NOT NULL DEFAULT 'w82',
                created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
                expires_at TIMESTAMP NOT NULL,
                verdict_html TEXT CHECK (verdict_html IS NULL OR (LENGTH(verdict_html) BETWEEN 1 AND 260))
            )
        """)
        cols = {
            row[1]
            for row in conn.execute("PRAGMA table_info(narrative_cache)").fetchall()
        }
        if "evidence_json" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN evidence_json TEXT")
        if "narrative_source" not in cols:
            conn.execute(
                "ALTER TABLE narrative_cache "
                "ADD COLUMN narrative_source TEXT NOT NULL DEFAULT 'w82'"
            )
        if "coverage_json" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN coverage_json TEXT")
        # AC-1 (P1P3-BUILD): structured card data stored per match
        if "structured_card_json" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN structured_card_json TEXT")
        # PIPELINE-BUILD-01: new columns for pre-computed verdict pipeline
        if "verdict_html" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN verdict_html TEXT")
        if "evidence_class" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN evidence_class TEXT")
        if "tone_band" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN tone_band TEXT")
        if "spec_json" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN spec_json TEXT")
        if "context_json" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN context_json TEXT")
        if "generation_ms" not in cols:
            conn.execute("ALTER TABLE narrative_cache ADD COLUMN generation_ms INTEGER")
        # PIPELINE-BUILD-01: indexes for staleness + tier queries
        conn.execute("CREATE INDEX IF NOT EXISTS idx_nc_expires ON narrative_cache(expires_at)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_nc_tier ON narrative_cache(edge_tier)")
        # BUILD-VERDICT-CAP-01 / BUILD-EDGE-CARD-INJURY-TO-MYMATCHES-01: Purge cached verdicts
        # that exceed the 300-char cap. Will regenerate on next view.
        try:
            _pv_result = conn.execute(
                "DELETE FROM narrative_cache WHERE LENGTH(verdict_html) > 300"
            )
            if _pv_result.rowcount:
                log.info(
                    "VERDICT_CAP_PURGE: Deleted %d overlong verdict_html rows",
                    _pv_result.rowcount,
                )
        except Exception as _pv_exc:
            log.warning("VERDICT_CAP_PURGE failed: %s", _pv_exc)
        # BUILD-VERDICT-QUALITY-GATE-01: quality_status column + tables
        if "quality_status" not in cols:
            conn.execute(
                "ALTER TABLE narrative_cache ADD COLUMN quality_status TEXT"
            )
        # NARRATIVE-ACCURACY-01: validation metadata columns
        if "setup_validated" not in cols:
            conn.execute(
                "ALTER TABLE narrative_cache ADD COLUMN setup_validated INTEGER DEFAULT 1"
            )
        if "verdict_validated" not in cols:
            conn.execute(
                "ALTER TABLE narrative_cache ADD COLUMN verdict_validated INTEGER DEFAULT 1"
            )
        if "setup_attempts" not in cols:
            conn.execute(
                "ALTER TABLE narrative_cache ADD COLUMN setup_attempts INTEGER DEFAULT 1"
            )
        if "verdict_attempts" not in cols:
            conn.execute(
                "ALTER TABLE narrative_cache ADD COLUMN verdict_attempts INTEGER DEFAULT 1"
            )
        # FIX-NARRATIVE-CACHE-DEATH-01: quarantine-on-reject columns
        try:
            if "status" not in cols:
                conn.execute("ALTER TABLE narrative_cache ADD COLUMN status TEXT DEFAULT NULL")
            if "quarantine_reason" not in cols:
                conn.execute("ALTER TABLE narrative_cache ADD COLUMN quarantine_reason TEXT DEFAULT NULL")
        except sqlite3.OperationalError:
            pass  # Column already exists — safe to ignore
        # FIX-NARRATIVE-CACHE-SCHEMA-200-260: widen verdict_html CHECK from 200 to 260
        # on any DB where the column was added under the old 200-char schema.
        try:
            _nc_raw = conn.execute(
                "SELECT sql FROM sqlite_master WHERE type='table' AND name='narrative_cache'"
            ).fetchone()
            if _nc_raw and "BETWEEN 1 AND 200" in _nc_raw[0]:
                log.info("FIX-NARRATIVE-CACHE-SCHEMA-200-260: widening verdict_html CHECK 200→260")
                _old_ddl = _nc_raw[0]
                _new_ddl = _old_ddl.replace("BETWEEN 1 AND 200", "BETWEEN 1 AND 260").replace(
                    "narrative_cache", "narrative_cache_new200260", 1
                )
                _idx_sqls = [
                    _r[0] for _r in conn.execute(
                        "SELECT sql FROM sqlite_master WHERE type='index' AND tbl_name='narrative_cache' AND sql IS NOT NULL"
                    ).fetchall()
                ]
                conn.execute("BEGIN EXCLUSIVE TRANSACTION")
                conn.execute(_new_ddl)
                conn.execute("INSERT INTO narrative_cache_new200260 SELECT * FROM narrative_cache")
                conn.execute("DROP TABLE narrative_cache")
                conn.execute("ALTER TABLE narrative_cache_new200260 RENAME TO narrative_cache")
                for _isql in _idx_sqls:
                    conn.execute(_isql.replace("narrative_cache_new200260", "narrative_cache"))
                conn.execute("COMMIT")
                log.info("FIX-NARRATIVE-CACHE-SCHEMA-200-260: migration committed")
        except Exception as _schema_exc:
            log.warning("FIX-NARRATIVE-CACHE-SCHEMA-200-260: migration failed: %s", _schema_exc)
        # FIX-PREMIUM-POSTWRITE-PROTECTION-01 AC-3 — drop shadow table.
        # `gold_verdict_failed_edges` was historically created here in odds.db
        # (= _NARRATIVE_DB_PATH) but the canonical table lives in
        # `bot/data/mzansiedge.db` — every production reader and writer points
        # there: card_data._check_premium_defer (line 1140), pregenerate_narratives
        # ._record_premium_defer / _clear_premium_defer (lines 2078 / 2135), and
        # monitor_narrative_integrity (line 720). The odds.db shadow is unused —
        # it was missing the consecutive_count column and silently caused the
        # AC-3 corpus invariant test to read an empty table on the wrong DB.
        # Drop the shadow only when empty (defensive — never destroy real data).
        try:
            _shadow_count = conn.execute(
                "SELECT COUNT(*) FROM gold_verdict_failed_edges"
            ).fetchone()
            if _shadow_count and _shadow_count[0] == 0:
                conn.execute("DROP TABLE IF EXISTS gold_verdict_failed_edges")
                log.info(
                    "FIX-PREMIUM-POSTWRITE-PROTECTION-01: dropped empty "
                    "gold_verdict_failed_edges shadow from %s — canonical "
                    "table lives in bot/data/mzansiedge.db",
                    _NARRATIVE_DB_PATH,
                )
        except sqlite3.OperationalError:
            pass  # Table doesn't exist (already dropped or fresh DB) — fine.
        conn.execute("""
            CREATE TABLE IF NOT EXISTS regen_queue (
                match_key TEXT PRIMARY KEY,
                edge_tier TEXT NOT NULL,
                invalidated_reason TEXT NOT NULL,
                queued_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
                status TEXT NOT NULL DEFAULT 'pending'
            )
        """)
        conn.execute("""
            CREATE TABLE IF NOT EXISTS narrative_integrity_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                signal TEXT NOT NULL,
                value INTEGER NOT NULL,
                recorded_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
            )
        """)
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_nil_signal_time "
            "ON narrative_integrity_log(signal, recorded_at)"
        )
        conn.commit()
    finally:
        conn.close()


