def _cleanup_expired_narrative_cache_rows(limit: int | None = None) -> int:
    """Delete expired narrative cache rows in one narrow hygiene sweep.

    BUILD-PREGEN-FIX-2 PRE-3 gap fix: w84 rows are preserved (not deleted) on
    expiry so that PRE-3 can find them during refresh sweeps and avoid overwriting
    with w82. Only non-w84 expired rows are deleted.
    """
    from datetime import datetime, timezone
    from db_connection import get_connection

    conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
    try:
        rows = conn.execute(
            "SELECT match_id, expires_at, narrative_source FROM narrative_cache ORDER BY expires_at ASC"
        ).fetchall()
        now = datetime.now(timezone.utc)
        expired_ids: list[str] = []
        for row in rows:
            match_id = row[0]
            expires_at = row[1]
            narrative_source = row[2] if len(row) > 2 else "w82"
            # PRE-3 gap fix: never delete w84 rows — PRE-3 needs them to
            # prevent w82 overwrites on refresh sweeps.
            if narrative_source == "w84":
                continue
            try:
                exp = datetime.fromisoformat(expires_at)
                if exp.tzinfo is None:
                    exp = assume_utc(exp)
            except (TypeError, ValueError):
                expired_ids.append(match_id)
                continue
            if exp < now:
                expired_ids.append(match_id)

        if limit is not None:
            expired_ids = expired_ids[:int(limit)]

        if not expired_ids:
            return 0

        placeholders = ",".join("?" for _ in expired_ids)
        cur = conn.execute(
            f"DELETE FROM narrative_cache WHERE match_id IN ({placeholders})",
            expired_ids,
        )
        conn.commit()
        return cur.rowcount if cur.rowcount is not None else len(expired_ids)
    finally:
        conn.close()


def _compute_odds_hash(match_id: str) -> str:
    """Compute MD5 hash of current odds snapshot for staleness detection.

    W84-RT3: Uses 3s timeout — called from background persist thread, not critical path.
    """
    import hashlib
    from db_connection import get_connection
    conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
    try:
        rows = conn.execute(
            "SELECT bookmaker, home_odds, draw_odds, away_odds "
            "FROM odds_latest WHERE match_id = ? ORDER BY bookmaker",
            (match_id,),
        ).fetchall()
        if not rows:
            return ""
        return hashlib.md5(str(rows).encode()).hexdigest()
    finally:
        conn.close()


# ── TIER-FIX C: Tier drift + EV coherence helpers ───────────────────────────

_TIER_LEVEL = {"bronze": 0, "silver": 1, "gold": 2, "diamond": 3}


def _tier_drift_exceeds_threshold(cached_tier: str, current_tier: str, threshold: int = 1) -> bool:
    """Return True if tier level distance > threshold."""
    a = _TIER_LEVEL.get((cached_tier or "").lower(), 0)
    b = _TIER_LEVEL.get((current_tier or "").lower(), 0)
    return abs(a - b) > threshold


def _ev_coherence_broken(cached_ev: float, live_ev: float, delta_threshold: float = 5.0) -> bool:
    """Return True if EV sign flipped OR absolute delta exceeds threshold (5pp).

    predicted_ev is stored as percentage points (e.g. 5.2 = 5.2%), so
    delta_threshold=5.0 means >5 percentage points, matching AC-3.
    """
    sign_flip = (cached_ev >= 0) != (live_ev >= 0)
    large_delta = abs(live_ev - cached_ev) > delta_threshold
    return sign_flip or large_delta


def _quick_edge_tier_lookup(match_id: str) -> str | None:
    """Single SELECT on edge_results for current edge_tier. Read-only."""
    try:
        from scrapers.db_connect import connect_odds_db as _qetl_fn
        from scrapers.edge.edge_config import DB_PATH as _qetl_db
        _qetl_conn = _qetl_fn(_qetl_db)
        try:
            row = _qetl_conn.execute(
                "SELECT edge_tier FROM edge_results "
                "WHERE match_key = ? AND result IS NULL "
                "ORDER BY recommended_at DESC LIMIT 1",
                (match_id,),
            ).fetchone()
        finally:
            _qetl_conn.close()
        if row and row[0]:
            return row[0].strip().lower()
        return None
    except Exception as _e:
        log.warning("scraper_boundary_failure site=edge_tracker_12808 err=%s", _e)
        if sentry_sdk:
            with sentry_sdk.push_scope() as scope:
                scope.set_tag("contract_violation", "scraper_boundary")
                scope.set_tag("boundary_site", "edge_tracker_12808")
                sentry_sdk.capture_exception(_e)
        return None


def _quick_ev_lookup(match_id: str) -> float | None:
    """Single SELECT on edge_results for current predicted_ev. Read-only.

    INV-EV-COHERENCE-01: Only returns EV for recommendations made within the last
    4 hours. Stale edge_results rows (from when the edge was first logged as positive)
    cannot be used as a live EV reference — odds may have drifted significantly since
    recommendation, and log_edge_recommendation() only writes positive edges, so no
    fresh row is ever written once EV goes negative. Comparing narrative tips_json EV
    (computed from current odds) against a stale recommendation EV causes a permanent
    sign-flip that can never resolve until settlement.
    """
    try:
        from scrapers.db_connect import connect_odds_db as _qev_fn
        from scrapers.edge.edge_config import DB_PATH as _qev_db
        _qev_conn = _qev_fn(_qev_db)
        try:
            row = _qev_conn.execute(
                "SELECT predicted_ev FROM edge_results "
                "WHERE match_key = ? AND result IS NULL "
                "AND recommended_at > datetime('now', '-4 hours') "
                "ORDER BY recommended_at DESC LIMIT 1",
                (match_id,),
            ).fetchone()
        finally:
            _qev_conn.close()
        if row and row[0] is not None:
            return float(row[0])
        return None
    except Exception:
        return None


def _has_w84_narrative(match_id: str) -> bool:
    """Return True when a non-expired w84 narrative row exists for match_id.

    Lightweight check — does NOT run stale-pattern or ESPN rejection logic.
    Used to gate the AI Breakdown button in ep:pick:N and mm:match:N paths.
    """
    if not match_id:
        return False
    try:
        import sqlite3 as _sl
        from datetime import datetime as _dt, timezone as _tz
        from db_connection import get_connection as _gc
        conn = _gc(_NARRATIVE_DB_PATH, timeout_ms=1500)
        try:
            row = conn.execute(
                "SELECT expires_at FROM narrative_cache "
                "WHERE match_id = ? AND narrative_source = 'w84' "
                "AND COALESCE(quarantined, 0) = 0 LIMIT 1",
                (match_id,),
            ).fetchone()
        finally:
            conn.close()
        if not row:
            return False
        exp_dt = _dt.fromisoformat(row[0])
        if exp_dt.tzinfo is None:
            exp_dt = assume_utc(exp_dt)
        return _dt.now(_tz.utc) < exp_dt
    except Exception:
        return False


def _has_any_cached_narrative(match_id: str) -> bool:
    """Return True when an AI Breakdown can be rendered for this match.

    FIX-NARRATIVE-AIBREAKDOWN-REGRESSION-01: Gates the AI Breakdown button.

    FIX-AI-BREAKDOWN-BUTTON-GATE-COVERAGE-01 (locked 2026-04-28): the gate now
    returns True when EITHER (a) a non-expired, non-quarantined narrative_cache
    row with non-empty narrative_html exists OR (b) edge_results has any row
    for this match (so the breakdown handler's baseline-synthesis fallback at
    card_data.py::_synthesize_breakdown_row_from_baseline can produce content).

    This is the bulletproof contract: edge_results row exists ⇔ button shows ⇔
    content renders. The button-gate predicate is mechanically consistent with
    the synthesis predicate — no scenario where the gate says yes but the
    handler returns blank, and no scenario where the gate hides the button on
    a match that has a live edge.

    Independent DB check — must not rely on render-path state.
    """
    if not match_id:
        return False
    try:
        from datetime import datetime as _dt, timezone as _tz
        from db_connection import get_connection as _gc
        conn = _gc(_NARRATIVE_DB_PATH, timeout_ms=1500)
        try:
            # Path A — existing pregen / cached narrative with non-empty HTML.
            row = conn.execute(
                "SELECT expires_at FROM narrative_cache "
                "WHERE match_id = ? "
                "AND COALESCE(quarantined, 0) = 0 "
                "AND (status IS NULL OR status != 'quarantined') "
                "AND narrative_html IS NOT NULL "
                "AND LENGTH(TRIM(COALESCE(narrative_html,''))) > 0 "
                "LIMIT 1",
                (match_id,),
            ).fetchone()
            if row:
                exp_dt = _dt.fromisoformat(row[0])
                if exp_dt.tzinfo is None:
                    exp_dt = assume_utc(exp_dt)
                if _dt.now(_tz.utc) < exp_dt:
                    return True
            # Path B — synthesis fallback can produce content from edge_results.
            # FIX-AI-BREAKDOWN-BUTTON-GATE-COVERAGE-01: predicate must match
            # _synthesize_breakdown_row_from_baseline()'s own SELECT predicate
            # (any edge_results row, prefer-unsettled order) so gate-and-synthesis
            # are mechanically guaranteed to agree.
            try:
                er_row = conn.execute(
                    "SELECT 1 FROM edge_results WHERE match_key = ? LIMIT 1",
                    (match_id,),
                ).fetchone()
                if er_row:
                    return True
            except Exception:
                # edge_results table missing or transient lock — fall through.
                pass
            return False
        finally:
            conn.close()
    except Exception:
        return False


def _breakdown_button_visible(match_id: str) -> bool:
    """BUILD-VERDICT-ONLY-STRIP-AI-BREAKDOWN-01 — surface stripped.

    The AI Breakdown button surface was retired in this wave. The verdict
    on the card image is now the only narrative surface. This function is
    retained as defence-in-depth: any leftover callsite that still consults
    it gets False, so no breakdown button can ever spawn.
    """
    return False


async def _get_cached_narrative(match_id: str) -> dict | None:
    """Fetch cached narrative from persistent DB cache. Returns None if stale/expired."""
    import json
    import sqlite3
    from datetime import datetime, timezone
    from db_connection import get_connection

    def _fetch():
        conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
        try:
            # INV-VERDICT-COACH-FABRICATION-01 + FIX-NARRATIVE-CACHE-DEATH-01: exclude quarantined rows.
            # FIX-AI-BREAKDOWN-EMPTY-NARRATIVE-FILTER-01: also exclude rows with empty
            # narrative_html so the breakdown surface treats verdict-cache rows
            # (narrative_html='' by design) as cache-miss and falls through to live
            # generation rather than serving four blank prose sections.
            try:
                row = conn.execute(
                    "SELECT narrative_html, model, edge_tier, tips_json, odds_hash, expires_at, "
                    "evidence_json, narrative_source, coverage_json, created_at "
                    "FROM narrative_cache WHERE match_id = ? "
                    "AND (status IS NULL OR status != 'quarantined') "
                    "AND narrative_html IS NOT NULL "
                    "AND LENGTH(TRIM(COALESCE(narrative_html, ''))) > 0",
                    (match_id,),
                ).fetchone()
            except sqlite3.OperationalError:
                # quarantined/status columns may not exist in older DBs
                row = conn.execute(
                    "SELECT narrative_html, model, edge_tier, tips_json, odds_hash, expires_at, "
                    "evidence_json, narrative_source, coverage_json, created_at "
                    "FROM narrative_cache WHERE match_id = ? "
                    "AND narrative_html IS NOT NULL "
                    "AND LENGTH(TRIM(COALESCE(narrative_html, ''))) > 0",
                    (match_id,),
                ).fetchone()
            if not row:
                return None
            html, model, tier, tips_json, stored_hash, expires_at, evidence_json, narrative_source, coverage_json, created_at_raw = row
            # Check TTL
            try:
                exp = datetime.fromisoformat(expires_at)
                if exp.tzinfo is None:
                    exp = assume_utc(exp)
                if datetime.now(timezone.utc) > exp:
                    return None  # Expired
            except (ValueError, TypeError):
                return None
            cleaned = _final_polish(_sanitise_jargon(_strip_preamble(html)))
            parsed_tips = json.loads(tips_json)
            # BUILD-NARRATIVE-WATERTIGHT-01 B.5: apply stale-Setup pattern check to ALL sources,
            # not just non-w82. w82 baseline can still carry generic "take on" / "limited context"
            # residue from older caches — rejecting here forces regen with fresh templates.
            if True:  # All narrative sources subject to stale-Setup patterns
                stale_setup_reasons = _find_stale_setup_patterns(cleaned)
                if stale_setup_reasons:
                    log.warning(
                        "Rejecting cached narrative for %s — stale Setup cache: %s",
                        match_id,
                        ", ".join(stale_setup_reasons),
                    )
                    try:
                        conn.execute(
                            "DELETE FROM narrative_cache WHERE match_id = ?",
                            (match_id,),
                        )
                        conn.commit()
                    except sqlite3.OperationalError as exc:
                        log.debug("Deferred stale Setup cache delete for %s: %s", match_id, exc)
                    return None
                if _has_stale_setup_context_claims(cleaned, evidence_json):
                    log.warning(
                        "Rejecting cached narrative for %s — stale Setup context claims",
                        match_id,
                    )
                    try:
                        conn.execute(
                            "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                            "WHERE match_id = ?",
                            ("stale_setup_context_claims", match_id),
                        )
                        conn.commit()
                    except sqlite3.OperationalError as exc:
                        log.debug("Deferred stale context cache quarantine for %s: %s", match_id, exc)
                    return None
            # R12-OVERNIGHT: Reject cached narratives missing ESPN data for ESPN-covered leagues
            # when the match is within 7 days (ESPN has data for near-term matches).
            # Far-future matches (>7 days) legitimately lack ESPN data — don't reject those.
            _ESPN_COVERED_LEAGUES = {"psl", "epl", "champions_league", "la_liga", "serie_a", "bundesliga", "ligue_1"}
            if evidence_json:
                try:
                    _ej = json.loads(evidence_json) if isinstance(evidence_json, str) else evidence_json
                    _espn_ctx = _ej.get("espn_context", {})
                    _espn_avail = _espn_ctx.get("data_available", False)
                    _ej_league = _ej.get("league", "")
                    if not _espn_avail and _ej_league in _ESPN_COVERED_LEAGUES:
                        # Only reject if the match is within 7 days (ESPN should have data)
                        _reject_espn = False
                        try:
                            _date_suffix = match_id.rsplit("_", 1)[-1]
                            if len(_date_suffix) == 10:
                                from datetime import date as _dt_date
                                _match_dt = _dt_date.fromisoformat(_date_suffix)
                                _days_out = (_match_dt - _dt_date.today()).days
                                _reject_espn = _days_out <= 7
                        except (ValueError, IndexError):
                            _reject_espn = True  # Can't parse date → reject conservatively
                        if _reject_espn:
                            log.warning(
                                "Rejecting cached narrative for %s — ESPN data unavailable for ESPN-covered league %s",
                                match_id, _ej_league,
                            )
                            try:
                                conn.execute(
                                    "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                                    "WHERE match_id = ?",
                                    (f"espn_unavailable:{_ej_league}", match_id),
                                )
                                conn.commit()
                            except sqlite3.OperationalError as exc:
                                log.debug("Deferred ESPN cache quarantine for %s: %s", match_id, exc)
                            return None
                except (json.JSONDecodeError, TypeError, AttributeError):
                    pass

            # FIX-PREGEN-COVERAGE-DIAMOND-01 (locked 2026-04-28): w82_for_tier
            # serve-time gate LIFTED for Gold/Diamond. Previously rejected w82 /
            # baseline_no_edge for premium tiers on the rationale that "Gold/Diamond
            # must never serve thin w82/baseline narratives". Locked Rules 12, 14,
            # 17, 18 now ensure w82 is editorial-quality. The previous behaviour
            # combined with Stream4 refusal at the writer side produced ~17/21
            # unsettled Gold/Diamond edges with NO eligible cache row — the
            # missing-breakdown symptom Paul reported on launch day +1. Now we
            # serve w82 baselines for premium tiers when w84 polish was unavailable;
            # subsequent pregen cycles upgrade the row to w84 via INSERT OR REPLACE.
            # Surface the premium-tier baseline serve as INFO so polish-failure
            # rates remain monitorable in journalctl.
            if narrative_source in ("w82", "baseline_no_edge") and tier in ("gold", "diamond"):
                log.info(
                    "FIX-PREGEN-COVERAGE-DIAMOND-01 PremiumW82Serve match_id=%s "
                    "tier=%s narrative_source=%s — serving w82 baseline as safety-net "
                    "(Rules 12/14/17/18 ensure editorial quality)",
                    match_id, tier, narrative_source,
                )
                # Continue serving — do not return None, do not quarantine.

            # MY-MATCHES-RELIABILITY-FIX: Reject w82 entries for ESPN-covered leagues
            # within 7 days. w82 is the deterministic baseline — if ESPN data is available
            # (or should be), force regeneration so pregen can produce a richer w84 entry.
            if narrative_source == "w82":
                _w82_league = None
                # Try evidence_json first
                if evidence_json:
                    try:
                        _w82_ej = json.loads(evidence_json) if isinstance(evidence_json, str) else evidence_json
                        _w82_league = _w82_ej.get("league", "")
                    except (json.JSONDecodeError, TypeError, AttributeError):
                        pass
                # Fallback: look up league from edge_results
                if not _w82_league:
                    try:
                        _lr = conn.execute(
                            "SELECT league FROM edge_results WHERE match_key = ? LIMIT 1",
                            (match_id,),
                        ).fetchone()
                        if _lr:
                            _w82_league = _lr[0]
                    except Exception:
                        pass
                if _w82_league and _w82_league in _ESPN_COVERED_LEAGUES:
                    _w82_reject = False
                    try:
                        _w82_ds = match_id.rsplit("_", 1)[-1]
                        if len(_w82_ds) == 10:
                            from datetime import date as _dt_date2
                            _w82_md = _dt_date2.fromisoformat(_w82_ds)
                            _w82_reject = (_w82_md - _dt_date2.today()).days <= 7
                    except (ValueError, IndexError):
                        _w82_reject = True
                    if _w82_reject:
                        log.warning(
                            "Rejecting w82 cached narrative for %s — ESPN-covered league %s, forcing w84 regeneration",
                            match_id, _w82_league,
                        )
                        try:
                            conn.execute(
                                "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                                "WHERE match_id = ?",
                                (f"w82_espn_freshness:{_w82_league}", match_id),
                            )
                            conn.commit()
                        except sqlite3.OperationalError as exc:
                            log.debug("Deferred w82 freshness cache quarantine for %s: %s", match_id, exc)
                        return None

            # W84-Q3: Reject cached narratives containing legacy banned phrases
            if _has_banned_patterns(cleaned):
                log.warning("Rejecting cached narrative for %s — contains banned phrases", match_id)
                try:
                    conn.execute(
                        "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                        "WHERE match_id = ?",
                        ("banned_patterns", match_id),
                    )
                    conn.commit()
                except sqlite3.OperationalError as exc:
                    log.debug("Deferred banned cache quarantine for %s: %s", match_id, exc)
                return None

            # BUILD-NARRATIVE-WATERTIGHT-01 C.1: serve-time min_verdict_quality gate.
            # Reject cached rows whose embedded narrative verdict OR stored verdict_html fails
            # the unified quality floor (≥ tier floor, ≤ 260 chars, terminal punctuation, no
            # banned phrases, no markdown, ≥3 analytical words). Cached rejections get DELETE'd
            # so pregen regenerates them instead of serving thin 42–65 char stubs.
            # BUILD-C1-OPTIONA-PHASE1-BREAKDOWN-01 AC-1: C.1 gate now evaluates ONLY the
            # standalone verdict_html column. The embedded verdict inside narrative_html is
            # no longer part of the gate — the card image reads verdict_html exclusively
            # (Narrative Wiring Bible v1 §2 Q1). The AI Breakdown fallback (AC-2 in
            # card_data.py) handles thin embedded verdicts at serve time.
            try:
                from narrative_spec import min_verdict_quality as _mvq
                _row_verdict_html: str | None = None
                try:
                    _row_verdict_html = conn.execute(
                        "SELECT verdict_html FROM narrative_cache WHERE match_id = ?",
                        (match_id,),
                    ).fetchone()
                    _row_verdict_html = _row_verdict_html[0] if _row_verdict_html else None
                except sqlite3.OperationalError:
                    _row_verdict_html = None
                _tier_for_gate = (tier or "bronze").lower()
                _standalone_ok = True
                if _row_verdict_html:
                    _standalone_plain = re.sub(r"<[^>]+>", "", _row_verdict_html).strip()
                    if _standalone_plain:
                        _standalone_ok = _mvq(
                            _standalone_plain, tier=_tier_for_gate, evidence_pack=None
                        )
                if not _standalone_ok:
                    log.warning(
                        "BUILD-NARRATIVE-WATERTIGHT-01 C.1: rejecting cached narrative for %s "
                        "— verdict_html quality gate failed (standalone_ok=%s, tier=%s)",
                        match_id, _standalone_ok, _tier_for_gate,
                    )
                    try:
                        conn.execute(
                            "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                            "WHERE match_id = ?",
                            (f"verdict_quality:standalone_ok={_standalone_ok}", match_id),
                        )
                        conn.commit()
                    except sqlite3.OperationalError as _del_err:
                        log.debug(
                            "Deferred serve-time verdict-gate quarantine for %s: %s",
                            match_id, _del_err,
                        )
                    return None
            except Exception as _gate_err:
                # Fail-open: do not block serves on gate-setup errors, but log for monitoring.
                log.debug("Serve-time verdict quality gate error for %s: %s", match_id, _gate_err)
            # P0-FIX-33: Reject non-w82 entries that lack W84-Q1 HTML section headers.
            # Narratives generated before W82-WIRE (old 3-stage AI rewrite path) used
            # markdown bold (**) or plain text headers — they never contain "<b>The Setup</b>".
            # New W84 pipeline always produces bold HTML headers via _render_baseline().
            # Any w84 entry without these headers is an old-format narrative that may
            # contain hallucinated tactical content — force re-generation.
            if narrative_source not in ("w82", "baseline_no_edge", "verdict-cache"):
                _has_html_headers = (
                    "<b>The Setup</b>" in cleaned
                    or "<b>The Edge</b>" in cleaned
                    or "<b>The Risk</b>" in cleaned
                )
                if not _has_html_headers:
                    log.warning(
                        "Rejecting cached narrative for %s — old-format entry missing W84-Q1 HTML headers (source=%s)",
                        match_id, narrative_source,
                    )
                    try:
                        conn.execute(
                            "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                            "WHERE match_id = ?",
                            (f"old_format_headers:{narrative_source}", match_id),
                        )
                        conn.commit()
                    except sqlite3.OperationalError as exc:
                        log.debug("Deferred old-format cache quarantine for %s: %s", match_id, exc)
                    return None
            if _has_empty_sections(cleaned):
                log.warning("Rejecting cached narrative for %s — contains empty section", match_id)
                try:
                    conn.execute(
                        "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                        "WHERE match_id = ?",
                        ("empty_sections", match_id),
                    )
                    conn.commit()
                except sqlite3.OperationalError as exc:
                    log.debug("Deferred empty-section cache quarantine for %s: %s", match_id, exc)
                return None
            # R11-BUILD-01 Fix A (Option B): Freshness guard — skip H2H validation
            # when evidence_json is present. The narrative already passed the TTL
            # check above, so it was generated within the last 6 hours. H2H data is
            # historical — it cannot change between generation and read. When evidence
            # was stored with the narrative, the H2H line was built from that evidence
            # at generation time and is authoritative.
            _skip_h2h = bool(evidence_json)
            if not _skip_h2h and _has_stale_h2h_summary(cleaned, parsed_tips, evidence_json):
                log.warning("Rejecting cached narrative for %s — stale H2H summary mismatch", match_id)
                try:
                    conn.execute(
                        "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                        "WHERE match_id = ?",
                        ("stale_h2h_summary", match_id),
                    )
                    conn.commit()
                except sqlite3.OperationalError as exc:
                    log.debug("Deferred stale H2H cache quarantine for %s: %s", match_id, exc)
                return None
            # TIER-FIX C: Reject cache when tier drifts >1 level or EV is incoherent
            _current_er_tier = _quick_edge_tier_lookup(match_id)
            if _current_er_tier and _tier_drift_exceeds_threshold(tier, _current_er_tier):
                log.warning(
                    "Cache rejected for %s — tier drift: cache=%s current=%s — quarantining stale row",
                    match_id, tier, _current_er_tier,
                )
                # FIX-PREGEN-TIER-DRIFT-01 (2026-04-25): quarantine the stale row so
                # _count_warm_narratives() does not count it as warm and the next
                # pregen sweep can regenerate it. Without quarantine, the row sat in
                # cache permanently — every sweep saw it as fresh and skipped re-pregen,
                # leaving Gold/Diamond cards button-less indefinitely after tier promotion.
                # Mirrors the EV-incoherent quarantine path immediately below.
                try:
                    conn.execute(
                        "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                        "WHERE match_id = ?",
                        (f"tier_drift:cache={tier},live={_current_er_tier}", match_id),
                    )
                    conn.commit()
                except sqlite3.OperationalError as exc:
                    log.debug("Deferred tier-drift cache quarantine for %s: %s", match_id, exc)
                return None

            # Extract cached EV from tips_json (first tip's predicted_ev or ev)
            _cached_ev = None
            if parsed_tips and isinstance(parsed_tips, list) and len(parsed_tips) > 0:
                _first_tip = parsed_tips[0] if isinstance(parsed_tips[0], dict) else {}
                _cached_ev_raw = _first_tip.get("predicted_ev") or _first_tip.get("ev")
                if _cached_ev_raw is not None:
                    try:
                        _cached_ev = float(_cached_ev_raw)
                    except (ValueError, TypeError):
                        pass

            _current_er_ev = _quick_ev_lookup(match_id)
            if _current_er_ev is not None and _cached_ev is not None:
                # D-02 FIX: Tighten threshold to 1.0pp so narrative EV stays coherent
                # with footer EV. Old threshold was 5.0pp — allowed visible divergence.
                if _ev_coherence_broken(_cached_ev, _current_er_ev, delta_threshold=1.0):
                    log.warning(
                        "Cache rejected for %s — EV incoherent: cached=%.3f live=%.3f — deleting stale row",
                        match_id, _cached_ev, _current_er_ev,
                    )
                    # INV-EV-COHERENCE-01: Delete the incoherent row so _count_warm_narratives()
                    # does not count it as warm and the pregen "refresh" sweep can regenerate it.
                    # Without this delete, the rejected row persists in DB, the warm-cache guard
                    # sees N >= threshold, skips the pregen, and the loop repeats every 15 minutes.
                    try:
                        conn.execute(
                            "UPDATE narrative_cache SET status = 'quarantined', quarantine_reason = ? "
                            "WHERE match_id = ?",
                            (f"ev_incoherent:cached={_cached_ev},live={_current_er_ev}", match_id),
                        )
                        conn.commit()
                    except sqlite3.OperationalError as _del_exc:
                        log.debug("Deferred incoherent cache quarantine for %s: %s", match_id, _del_exc)
                    return None

            return {
                "html": cleaned,
                "tips": parsed_tips,
                "edge_tier": tier,
                "model": model,
                "narrative_source": narrative_source or "w82",
                "coverage_json": coverage_json,
                "evidence_json": evidence_json,  # BUILD-6: expose for display
                "created_at": created_at_raw,  # BUILD-16c: staleness check
            }
        finally:
            conn.close()

    return await asyncio.to_thread(_fetch)


async def _store_narrative_cache(
    match_id: str,
    html: str,
    tips: list,
    edge_tier: str,
    model: str,
    evidence_json: str | None = None,
    narrative_source: str = "w82",
    coverage_json: str | None = None,
    structured_card_json: str | None = None,
    verdict_html: str | None = None,
    evidence_class: str | None = None,
    tone_band: str | None = None,
    spec_json: str | None = None,
    context_json: str | None = None,
    generation_ms: int | None = None,
    setup_validated: int | None = None,
    verdict_validated: int | None = None,
    setup_attempts: int | None = None,
    verdict_attempts: int | None = None,
) -> None:
    """Persist narrative to DB cache with 6hr TTL.

    W84-RT3: Best-effort, single-attempt with 3s timeout. The in-memory _analysis_cache
    already holds the narrative for immediate serving. Persistent DB cache is for
    cross-restart resilience only — missing one write is acceptable. No retry loop:
    old retry with 30s busy_timeout + time.sleep(1.0/2.0) produced lock WARNINGs during
    scraper write windows. With 3s timeout + no retry, contention is silent (DEBUG) and
    the event loop is never blocked (runs in asyncio.to_thread).
    """
    import json
    import sqlite3
    from datetime import datetime, timedelta, timezone
    from db_connection import get_connection

    # FIX-DROP-SONNET-POLISH-W82-CANONICAL-01: Rule 24 premium-W82 refusal lifted.
    # W82 baseline is now the canonical narrative for ALL tiers (Diamond + Gold +
    # Silver + Bronze). The Sonnet polish path that the refusal was protecting no
    # longer exists. Rules 23/24 are obsolete; the verdict-only validator gates
    # below (banned phrases, venue leak, manager hallucination, closure rule,
    # char range, tone-band) fire on every W82 write and refuse rows that violate
    # the contract — regardless of tier.
    _wg_src = (narrative_source or "").lower()
    # FIX-NARRATIVE-CACHE-SILENT-DROP-01 B.1: Default edge_tier to 'bronze' when pregen
    # produces an empty/None tier. Observed silent drop: arsenal_vs_fulham generated with
    # tier='' triggered sqlite3.IntegrityError (NOT NULL constraint failed) which was
    # caught by the existing handler with only a log.warning. Default here so the legitimate
    # baseline row lands instead of being swallowed by the NOT NULL constraint.
    if not edge_tier:
        log.info(
            "FIX-NARRATIVE-CACHE-SILENT-DROP-01 TierDefault match_id=%s edge_tier empty → 'bronze'",
            match_id,
        )
        edge_tier = "bronze"
    # FIX-NARRATIVE-CACHE-SCHEMA-200-260: schema CHECK constraint enforces
    # verdict_html IS NULL OR LENGTH BETWEEN 1 AND 260 (HARD_MAX = 260 per policy).
    # If a verdict exceeds 260 chars, truncate at the last sentence boundary rather
    # than silently nulling — the column is source of truth for Narrative Integrity Monitor.
    if verdict_html is not None and len(verdict_html) > 260:
        log.warning(
            "FIX-NARRATIVE-CACHE-SCHEMA-200-260 VerdictTruncated match_id=%s "
            "verdict_html_len=%d > 260 (HARD_MAX) → truncating at last sentence boundary",
            match_id, len(verdict_html),
        )
        verdict_html = _trim_to_last_sentence(verdict_html, max_chars=260) or None
    # FIX-NARRATIVE-CACHE-SILENT-DROP-01 A.1: log the happy path so silent drops are
    # diagnosable by absence. If we see "Stream4Accepted" for a match but no row
    # lands, the OperationalError path is the culprit (not Stream 4 F1-F2).
    log.info(
        "FIX-NARRATIVE-CACHE-SILENT-DROP-01 Stream4Accepted match_id=%s "
        "narrative_source=%s edge_tier=%s verdict_len=%d",
        match_id, _wg_src, edge_tier, len(verdict_html or ""),
    )

    # FIX-W82-BASELINE-PRICE-TALKING-01 (locked 2026-04-27): scan W82 baseline
    # Setup for banned pricing vocabulary before persistence. The W82 deterministic
    # baseline path bypasses _validate_polish gate 8a, so without this scan a future
    # template change could leak banned vocab (price/bookmaker/odds/implied/etc.)
    # into Setup with no gate to catch it. On hit, log + return early (don't persist) —
    # the in-memory _analysis_cache already holds the narrative for immediate serving,
    # and the next pregen cycle will rebuild from cleaned templates. See CLAUDE.md
    # Narrative Generation Pipeline Rule 12.
    if _wg_src == "w82":
        _baseline_setup_reasons = _validate_baseline_setup(html)
        if _baseline_setup_reasons:
            log.warning(
                "BASELINE REJECT: setup-pricing-leak match_id=%s reasons=%s — "
                "skipping W82 persistence (in-memory cache still serves)",
                match_id, ", ".join(_baseline_setup_reasons),
            )
            return

    # FIX-NARRATIVE-ROT-ROOT-01 Phase 2: unified pre-persist validator.
    # Runs the full gate stack (venue / setup-pricing strict + semantic /
    # manager hallucination / claim verification / verdict quality / banned
    # phrases) and applies tier-aware enforcement policy:
    #   - Premium (Diamond/Gold) + CRITICAL or MAJOR → refuse write
    #   - Non-premium (Silver/Bronze) + CRITICAL → refuse write
    #   - Non-premium + MAJOR → write with quality_status='quarantined'
    # Sits AFTER the Rule 23 / Rule 24 (premium W82 refusal) and AFTER the
    # legacy _validate_baseline_setup gate (kept for log-marker compatibility).
    from narrative_validator import _validate_narrative_for_persistence

    _evidence_pack_dict: dict | None = None
    if evidence_json:
        try:
            import json as _json_mod
            _evidence_pack_dict = _json_mod.loads(evidence_json)
            if not isinstance(_evidence_pack_dict, dict):
                _evidence_pack_dict = None
        except Exception:
            _evidence_pack_dict = None

    _validation = _validate_narrative_for_persistence(
        content={
            "narrative_html": html,
            "verdict_html": verdict_html,
            "match_id": match_id,
            "narrative_source": narrative_source,
        },
        evidence_pack=_evidence_pack_dict,
        edge_tier=edge_tier,
        source_label=narrative_source,
    )

    _quality_status_override: str | None = None
    if not _validation.passed:
        _premium = (edge_tier or "").lower() in ("gold", "diamond")
        _crit = _validation.critical_count > 0
        _major = _validation.major_count > 0
        _gates_failed = ",".join(f.gate for f in _validation.failures)
        if _premium and (_crit or _major):
            log.warning(
                "FIX-NARRATIVE-ROT-ROOT-01 PremiumValidatorRefused "
                "match_id=%s tier=%s source=%s gates_failed=%s",
                match_id, edge_tier, narrative_source, _gates_failed,
            )
            return
        if not _premium and _crit:
            log.warning(
                "FIX-NARRATIVE-ROT-ROOT-01 BaselineValidatorRefused "
                "match_id=%s tier=%s source=%s gates_failed=%s",
                match_id, edge_tier, narrative_source, _gates_failed,
            )
            return
        if not _premium and _major:
            _quality_status_override = "quarantined"
            log.warning(
                "FIX-NARRATIVE-ROT-ROOT-01 BaselineQuarantined "
                "match_id=%s tier=%s source=%s gates_failed=%s",
                match_id, edge_tier, narrative_source, _gates_failed,
            )

    def _store():
        # W84-RT3: 3s timeout — WAL mode handles transient scraper locks up to 3s.
        # If lock lasts longer (scraper bulk write), we skip this persist gracefully.
        conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
        try:
            now = datetime.now(timezone.utc)
            expires = now + timedelta(seconds=_NARRATIVE_CACHE_TTL)
            odds_hash = _compute_odds_hash(match_id)
            # INV-CARD-NARRATIVE-SERVE-01: Preserve existing verdict_html when pregen
            # doesn't generate one. INSERT OR REPLACE would otherwise wipe a verdict
            # stored by _store_verdict_cache_sync on serve-time, causing the verdict to
            # change on re-navigation (different Sonnet call generates different text).
            nonlocal verdict_html
            if verdict_html is None:
                try:
                    _ev = conn.execute(
                        "SELECT verdict_html FROM narrative_cache WHERE match_id = ?",
                        (match_id,),
                    ).fetchone()
                    if _ev and _ev[0]:
                        verdict_html = _ev[0]
                except Exception:
                    pass
            conn.execute(
                "INSERT OR REPLACE INTO narrative_cache "
                "(match_id, narrative_html, model, edge_tier, tips_json, odds_hash, "
                "evidence_json, narrative_source, coverage_json, created_at, expires_at, "
                "structured_card_json, verdict_html, evidence_class, tone_band, "
                "spec_json, context_json, generation_ms, "
                "setup_validated, verdict_validated, setup_attempts, verdict_attempts, "
                "quality_status) "
                "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                (
                    match_id, html, model, edge_tier,
                    json.dumps(tips, default=str),
                    odds_hash,
                    evidence_json,
                    narrative_source,
                    coverage_json,
                    now.isoformat(),
                    expires.isoformat(),
                    structured_card_json,
                    verdict_html,
                    evidence_class,
                    tone_band,
                    spec_json,
                    context_json,
                    generation_ms,
                    setup_validated,
                    verdict_validated,
                    setup_attempts,
                    verdict_attempts,
                    _quality_status_override,
                ),
            )
            conn.commit()
            # FIX-NARRATIVE-CACHE-SILENT-DROP-01 A.1: Confirm the INSERT actually
            # committed. If we see Stream4Accepted but not CommitOK for a match_id,
            # the row was silently dropped by an exception swallowed below.
            log.info(
                "FIX-NARRATIVE-CACHE-SILENT-DROP-01 CommitOK match_id=%s "
                "narrative_source=%s edge_tier=%s quality_status=%s",
                match_id, narrative_source, edge_tier, _quality_status_override,
            )
        except sqlite3.IntegrityError as e:
            if sentry_sdk:
                with sentry_sdk.push_scope() as scope:
                    scope.set_tag("contract", "contract_violation:narrative_cache")
                    scope.set_tag("match_id", match_id)
                    sentry_sdk.capture_exception(e)
            log.warning("Narrative cache IntegrityError for %s: %s", match_id, e)
        except sqlite3.OperationalError as e:
            if "locked" in str(e).lower():
                import time as _time
                log.warning("Narrative cache persist deferred (DB contention) for %s: %s", match_id, e)
                _time.sleep(0.1)
                try:
                    conn.execute(
                        "INSERT OR REPLACE INTO narrative_cache "
                        "(match_id, narrative_html, model, edge_tier, tips_json, odds_hash, "
                        "evidence_json, narrative_source, coverage_json, created_at, expires_at, "
                        "structured_card_json, verdict_html, evidence_class, tone_band, "
                        "spec_json, context_json, generation_ms, "
                        "setup_validated, verdict_validated, setup_attempts, verdict_attempts, "
                        "quality_status) "
                        "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                        (
                            match_id, html, model, edge_tier,
                            json.dumps(tips, default=str),
                            odds_hash,
                            evidence_json,
                            narrative_source,
                            coverage_json,
                            now.isoformat(),
                            expires.isoformat(),
                            structured_card_json,
                            verdict_html,
                            evidence_class,
                            tone_band,
                            spec_json,
                            context_json,
                            generation_ms,
                            setup_validated,
                            verdict_validated,
                            setup_attempts,
                            verdict_attempts,
                            _quality_status_override,
                        ),
                    )
                    conn.commit()
                except sqlite3.OperationalError:
                    if sentry_sdk:
                        sentry_sdk.capture_message(
                            f"Narrative cache persist still locked after retry for {match_id}",
                            level="warning",
                        )
            else:
                log.warning("Narrative cache persist failed for %s: %s", match_id, e)
        finally:
            conn.close()

    await asyncio.to_thread(_store)


async def _get_current_ev_for_match(match_key: str) -> float | None:
    """Compute current EV live via calculate_edge_v2() for the given match_key.

    COVERAGE-GATE-BUILD: Used by serve-time EV gate to determine if a cached
    edge:detail card still has positive EV before serving it.
    Falls back to stored predicted_ev on calculation error or timeout.
    Returns None if the match is not found or on any error.
    """
    def _compute():
        try:
            from scrapers.db_connect import connect_odds_db as _conn_fn
            from scrapers.edge.edge_config import DB_PATH as _DB_PATH
            _conn = _conn_fn(_DB_PATH)
            row = _conn.execute(
                "SELECT predicted_ev, bet_type, sport, league FROM edge_results "
                "WHERE match_key = ? AND result IS NULL "
                "ORDER BY id DESC LIMIT 1",
                (match_key,),
            ).fetchone()
            _conn.close()
            if not row:
                return None
            stored_ev = float(row[0]) if row[0] is not None else None
            bet_type = row[1] or "home"
            sport = row[2] or "soccer"
            league = row[3] or ""
            # Normalise bet_type to outcome key
            _bt = bet_type.strip()
            if _bt == "Home Win" or _bt == "home":
                outcome = "home"
            elif _bt == "Away Win" or _bt == "away":
                outcome = "away"
            elif _bt in ("Draw", "draw", "X"):
                outcome = "draw"
            else:
                outcome = "home"
            # Live calculation
            try:
                from scrapers.edge.edge_v2_helper import calculate_edge_v2
                result = calculate_edge_v2(
                    match_key,
                    outcome=outcome,
                    sport=sport,
                    league=league,
                    _skip_log=True,
                )
                if result and result.get("predicted_ev") is not None:
                    return float(result["predicted_ev"])
            except Exception as _calc_err:
                log.debug(
                    "_get_current_ev_for_match live calc failed for %s: %s",
                    match_key, _calc_err,
                )
            # Fallback to stored value
            return stored_ev
        except Exception as _e:
            log.debug("_get_current_ev_for_match failed for %s: %s", match_key, _e)
            return None

    return await asyncio.to_thread(_compute)


async def _delete_narrative_cache(match_id: str) -> None:
    """Delete a cached narrative by match_id (e.g. on outcome mismatch — R14-BUILD-01)."""
    import sqlite3
    from db_connection import get_connection

    def _delete():
        conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
        try:
            conn.execute("DELETE FROM narrative_cache WHERE match_id = ?", (match_id,))
            conn.commit()
        except sqlite3.OperationalError as e:
            if "locked" in str(e).lower():
                log.debug("Narrative cache delete deferred (DB contention) for %s: %s", match_id, e)
            else:
                log.warning("Narrative cache delete failed for %s: %s", match_id, e)
        finally:
            conn.close()

    await asyncio.to_thread(_delete)


def _get_cached_verdict(match_key: str) -> dict | None:
    """PIPELINE-BUILD-01: Fetch cached verdict from narrative_cache. Synchronous.

    Returns dict with verdict_html, evidence_class, tone_band, odds_hash, created_at
    or None if not found.
    """
    import sqlite3
    from db_connection import get_connection
    if not match_key:
        return None
    try:
        conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
        try:
            row = conn.execute(
                "SELECT verdict_html, evidence_class, tone_band, odds_hash, "
                "created_at, expires_at, tips_json, quality_status "
                "FROM narrative_cache WHERE match_id = ?",
                (match_key,),
            ).fetchone()
            if not row or not row[0]:
                return None
            # Reject verdicts that failed quality gates during pregeneration —
            # quality_status='skipped_banned_shape' means the stored verdict_html
            # is from a partial/failed polish attempt and will be too short or incoherent.
            if row[7] == "skipped_banned_shape":
                log.debug(
                    "_get_cached_verdict: rejecting skipped_banned_shape for %s", match_key
                )
                return None
            # NOTE: _VERDICT_MIN_CHARS floor is NOT applied here. verdict_html in
            # narrative_cache is the short card-summary snippet (designed 60-150 chars).
            # Applying a 140-char minimum here rejects valid short verdicts and forces
            # fallback to longer padded text with different formatting (regression fix).
            # Extract cached odds/bookmaker/ev from tips_json for serve-time staleness checks
            _cached_bookie = ""
            _cached_odds = 0.0
            _cached_ev = 0.0
            if row[6]:
                try:
                    import json as _json_vc
                    _tips_vc = _json_vc.loads(row[6])
                    if _tips_vc:
                        _t0 = _tips_vc[0]
                        _cached_bookie = str(_t0.get("bookie") or _t0.get("bookmaker") or "")
                        _cached_odds = float(_t0.get("odds") or 0)
                        _cached_ev = float(_t0.get("ev") or 0)
                except Exception:
                    pass
            return {
                "verdict_html": row[0],
                "evidence_class": row[1] or "",
                "tone_band": row[2] or "",
                "odds_hash": row[3] or "",
                "created_at": row[4] or "",
                "expires_at": row[5] or "",
                "cached_bookmaker": _cached_bookie,
                "cached_odds": _cached_odds,
                "cached_ev": _cached_ev,
            }
        finally:
            conn.close()
    except sqlite3.OperationalError:
        return None
    except Exception:
        return None


def _is_verdict_stale(cached: dict) -> bool:
    """PIPELINE-BUILD-01: Staleness rules for cached verdict.

    0–6h: serve as-is
    6–24h: serve, but flag for background refresh if odds_hash changed
    >24h: regenerate
    """
    from datetime import datetime, timezone
    created_str = cached.get("created_at", "")
    if not created_str:
        return True
    try:
        created = datetime.fromisoformat(created_str)
        if created.tzinfo is None:
            created = assume_utc(created)
        age_hours = (datetime.now(timezone.utc) - created).total_seconds() / 3600
        if age_hours > 24:
            return True
        if age_hours > 6:
            # Check if odds have changed
            match_key = cached.get("match_key", "")
            if match_key:
                current_hash = _compute_odds_hash(match_key)
                if current_hash and current_hash != cached.get("odds_hash", ""):
                    return True
        return False
    except (ValueError, TypeError):
        return True


def _store_verdict_cache_sync(match_key: str, verdict_html: str, tip_data: dict) -> None:
    """PIPELINE-BUILD-01: Store verdict in narrative_cache. Synchronous, best-effort.

    Updates verdict_html column on existing row (from pregenerate or narrative cache).
    If no row exists, creates a minimal one.

    W92-VERDICT-QUALITY P2: enforces min_verdict_quality() gate BEFORE writing. Rejects
    verdicts that fail the tier-aware quality floor (length, analytical vocabulary,
    banned shapes, Diamond price-prefix, markdown leak, manager fabrication). A failing
    verdict is silently SKIPPED (no INSERT) with a Sentry breadcrumb for observability.
    """
    import json
    import sqlite3
    from datetime import datetime, timedelta, timezone
    from db_connection import get_connection
    from narrative_spec import min_verdict_quality
    if not match_key or not verdict_html:
        return

    # W92-VERDICT-QUALITY P2: pre-write quality gate.
    # Tier is carried in tip_data under several possible keys — normalise to lowercase.
    _tier_raw = (
        tip_data.get("edge_tier")
        or tip_data.get("tier")
        or tip_data.get("display_tier")
        or "bronze"
    )
    _tier = str(_tier_raw).lower().strip() or "bronze"
    _evidence_pack = tip_data.get("evidence_pack") if isinstance(tip_data, dict) else None
    if not min_verdict_quality(verdict_html, tier=_tier, evidence_pack=_evidence_pack):
        log.warning(
            "_store_verdict_cache_sync: verdict rejected by quality gate "
            "(match_key=%s tier=%s len=%d sample=%r)",
            match_key, _tier, len(verdict_html), verdict_html[:60],
        )
        try:
            import sentry_sdk as _sentry_mod
            if _sentry_mod:
                _sentry_mod.add_breadcrumb(
                    category="verdict",
                    message="verdict_cache_rejected",
                    level="warning",
                    data={
                        "match_id": match_key,
                        "tier": _tier,
                        "verdict_len": len(verdict_html),
                        "sample": verdict_html[:80],
                    },
                )
        except Exception:
            pass
        return

    # FIX-VERDICT-CLOSURE-MINIMAL-RESTORE-01 (2026-04-30) — AC-3.
    # Route verdict-cache through the dedicated `_validate_verdict_for_persistence`
    # helper (verdict-only subset of the unified validator). Tier-aware
    # enforcement matrix matching AC-1:
    #   - Diamond + Gold: CRITICAL → refuse write (log PremiumVerdictRefused).
    #   - Silver: CRITICAL → refuse; MAJOR → write with quality_status='quarantined'.
    #   - Bronze: CRITICAL → refuse; MAJOR → log + write.
    # MINOR severity is informational; never blocks.
    _vc_quality_status: str | None = None
    try:
        from narrative_validator import _validate_verdict_for_persistence as _vvfp
        # The verdict-only validator wraps `_validate_narrative_for_persistence`;
        # gates 6 (verdict venue), 7 (banned phrases), 8 (telemetry), 9
        # (strong-band tone), 10 (closure rule), 11 (vague content) all fire
        # against verdict_html when narrative_html is empty.
        _vc_pack = _evidence_pack if isinstance(_evidence_pack, dict) else None
        # Inject match_id into the pack so the validator log markers carry it.
        if _vc_pack is not None and "match_id" not in _vc_pack:
            _vc_pack = dict(_vc_pack)
            _vc_pack["match_id"] = match_key
        elif _vc_pack is None:
            _vc_pack = {"match_id": match_key}
        _vc_validation = _vvfp(
            verdict_html=verdict_html,
            edge_tier=_tier,
            evidence_pack=_vc_pack,
            source_label="verdict-cache",
        )
        if not _vc_validation.passed:
            _vc_crit = _vc_validation.critical_count > 0
            _vc_gates = ",".join(f.gate for f in _vc_validation.failures)
            _vc_premium = _tier in ("diamond", "gold")
            if _vc_crit:
                if _vc_premium:
                    log.warning(
                        "FIX-VERDICT-CLOSURE-MINIMAL-RESTORE-01 PremiumVerdictRefused "
                        "match_key=%s tier=%s gates=%s",
                        match_key, _tier, _vc_gates,
                    )
                else:
                    log.warning(
                        "FIX-VERDICT-CLOSURE-MINIMAL-RESTORE-01 VerdictCacheCriticalRefused "
                        "match_key=%s tier=%s gates=%s",
                        match_key, _tier, _vc_gates,
                    )
                return
            # MAJOR severity — Silver/Bronze write with quarantined status flag,
            # Premium tiers shouldn't reach here (CRITICAL already short-circuited),
            # but defence-in-depth: refuse premium MAJOR too.
            if _vc_premium:
                log.warning(
                    "FIX-VERDICT-CLOSURE-MINIMAL-RESTORE-01 PremiumVerdictRefused "
                    "match_key=%s tier=%s gates=%s severity=MAJOR",
                    match_key, _tier, _vc_gates,
                )
                return
            log.warning(
                "FIX-VERDICT-CLOSURE-MINIMAL-RESTORE-01 VerdictCacheQuarantined "
                "match_key=%s tier=%s gates=%s",
                match_key, _tier, _vc_gates,
            )
            _vc_quality_status = "quarantined"
    except Exception as _vc_exc:
        # Validator failures must never block verdict-cache writes — log and proceed.
        log.warning(
            "FIX-VERDICT-CLOSURE-MINIMAL-RESTORE-01 VerdictCacheValidatorErr "
            "match_key=%s err=%s",
            match_key, _vc_exc,
        )

    try:
        conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
        try:
            # Check if row exists
            existing = conn.execute(
                "SELECT match_id FROM narrative_cache WHERE match_id = ?",
                (match_key,),
            ).fetchone()
            if existing:
                # Update verdict on existing row; clear skipped_banned_shape so
                # _get_cached_verdict() serves this fresh verdict next time.
                conn.execute(
                    "UPDATE narrative_cache SET verdict_html = ?, "
                    "quality_status = CASE WHEN quality_status = 'skipped_banned_shape' "
                    "THEN NULL ELSE quality_status END "
                    "WHERE match_id = ?",
                    (verdict_html, match_key),
                )
            else:
                # Create minimal row for verdict
                now = datetime.now(timezone.utc)
                expires = now + timedelta(seconds=_NARRATIVE_CACHE_TTL)
                conn.execute(
                    "INSERT OR REPLACE INTO narrative_cache "
                    "(match_id, narrative_html, verdict_html, model, edge_tier, "
                    "tips_json, odds_hash, narrative_source, created_at, expires_at) "
                    "VALUES (?, '', ?, 'view-time', ?, ?, ?, 'verdict-cache', ?, ?)",
                    (
                        match_key,
                        verdict_html,
                        tip_data.get("edge_tier", ""),
                        json.dumps([tip_data], default=str),
                        _compute_odds_hash(match_key),
                        now.isoformat(),
                        expires.isoformat(),
                    ),
                )
            # FIX-VERDICT-CLOSURE-MINIMAL-RESTORE-01 (2026-04-30) — AC-3.
            # Apply quarantine flag post-write when validator returned MAJOR on
            # non-premium tiers. Best-effort: a row that landed without a
            # quality_status column survives; the AI Breakdown visibility gate
            # already filters on quarantined rows via its DISQUALIFYING_STATUSES.
            if _vc_quality_status == "quarantined":
                try:
                    conn.execute(
                        "UPDATE narrative_cache SET quality_status = ? "
                        "WHERE match_id = ?",
                        (_vc_quality_status, match_key),
                    )
                except Exception:
                    pass
            conn.commit()
        finally:
            conn.close()
    except sqlite3.OperationalError as e:
        if "locked" in str(e).lower():
            log.debug("Verdict cache persist deferred (DB contention) for %s", match_key)
        else:
            log.warning("Verdict cache persist failed for %s: %s", match_key, e)
    except Exception as e:
        log.debug("Verdict cache persist error for %s: %s", match_key, e)


async def _store_narrative_evidence(match_id: str, evidence_json: str) -> bool:
    """Best-effort update of evidence_json for an existing narrative cache row.

    FIX-NARRATIVE-ROT-ROOT-01 Phase 2: this UPDATE only touches `evidence_json`
    (no narrative/verdict text) so the unified validator is not invoked. We DO
    sanity-check that the new payload parses as a JSON object — a corrupted
    evidence_json column poisons every downstream gate (manager validator,
    rating anchor, claim validator) and is silent until those gates fire.
    On parse failure we log + return False (best-effort, no exception).
    """
    import json as _json_mod
    import sqlite3
    from db_connection import get_connection

    if evidence_json:
        try:
            _parsed = _json_mod.loads(evidence_json)
            if not isinstance(_parsed, dict):
                log.warning(
                    "FIX-NARRATIVE-ROT-ROOT-01 EvidenceUpdateInvalidShape "
                    "match_id=%s type=%s — refusing UPDATE",
                    match_id, type(_parsed).__name__,
                )
                return False
        except Exception as _ej_exc:
            log.warning(
                "FIX-NARRATIVE-ROT-ROOT-01 EvidenceUpdateInvalidJson "
                "match_id=%s err=%s — refusing UPDATE",
                match_id, _ej_exc,
            )
            return False

    def _store() -> bool:
        conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
        try:
            cur = conn.execute(
                "UPDATE narrative_cache SET evidence_json = ? WHERE match_id = ?",
                (evidence_json, match_id),
            )
            conn.commit()
            return bool(cur.rowcount)
        except sqlite3.OperationalError as e:
            if "locked" in str(e).lower():
                log.debug("Narrative evidence persist deferred (DB contention) for %s: %s", match_id, e)
                return False
            log.warning("Narrative evidence persist failed for %s: %s", match_id, e)
            return False
        finally:
            conn.close()

    return await asyncio.to_thread(_store)


async def _store_shadow_narrative(
    *,
    match_key: str,
    evidence_json: str,
    prompt_text: str,
    raw_draft: str,
    verified_draft: str | None,
    verification_report: str,
    verification_passed: bool,
    w82_baseline: str,
    w82_polished: str | None,
    richness_score: str,
    model: str,
    duration_ms: int | None = None,
    token_count: int | None = None,
) -> bool:
    """Persist a shadow narrative row. Shadow failures never affect live serving."""
    import sqlite3
    from db_connection import get_connection

    def _store() -> bool:
        conn = get_connection(_NARRATIVE_DB_PATH, timeout_ms=3000)
        try:
            conn.execute(
                "INSERT INTO shadow_narratives ("
                "match_key, evidence_json, prompt_text, raw_draft, verified_draft, "
                "verification_report, verification_passed, w82_baseline, w82_polished, "
                "richness_score, model, duration_ms, token_count"
                ") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                (
                    match_key,
                    evidence_json,
                    prompt_text,
                    raw_draft,
                    verified_draft,
                    verification_report,
                    int(bool(verification_passed)),
                    w82_baseline,
                    w82_polished,
                    richness_score,
                    model,
                    duration_ms,
                    token_count,
                ),
            )
            conn.commit()
            return True
        except sqlite3.OperationalError as e:
            if "locked" in str(e).lower():
                log.debug("Shadow narrative persist deferred (DB contention) for %s: %s", match_key, e)
                return False
            log.warning("Shadow narrative persist failed for %s: %s", match_key, e)
            return False
        finally:
            conn.close()

    return await asyncio.to_thread(_store)


