async def _notify_payment_outcome(bot, outcome: dict[str, object]) -> None:
    user_id = outcome.get("user_id")
    if not user_id:
        return

    _success_mkp = InlineKeyboardMarkup([
        [InlineKeyboardButton("💎 Edge Picks", callback_data="hot:go")],
        [InlineKeyboardButton("📋 My Status", callback_data="sub:billing")],
    ])

    if outcome.get("outcome") in {"confirmed", "already_founding_member"}:
        slot_number = int(outcome.get("slot_number") or 0)
        if slot_number:
            # Founding member path — plain text (existing behaviour)
            await bot.send_message(
                chat_id=int(user_id),
                text=_founding_confirmation_text(slot_number),
                parse_mode=ParseMode.HTML,
                reply_markup=_success_mkp,
            )
        else:
            # Non-founding Gold/Diamond — send confirmation card with plain-text fallback
            _card_sent = False
            try:
                _u = await db.get_user(int(user_id))
                if _u:
                    _pc = getattr(_u, "plan_code", "") or ""
                    _ea = getattr(_u, "tier_expires_at", None)
                    _ac = config.STITCH_PRODUCTS.get(_pc, {}).get("price", 0)
                    _cd = build_sub_payment_confirmed_data(_u, _pc, _ac, _ea)
                    await send_card_or_fallback(
                        bot, int(user_id),
                        "sub_payment_confirmed.html",
                        _cd,
                        "✅ Payment confirmed! Your paid access is active now.",
                        _success_mkp,
                        message_to_edit=None,
                    )
                    _card_sent = True
            except Exception as _ce:
                log.error("sub_payment_confirmed card failed for user %s: %s", user_id, _ce)
            if not _card_sent:
                await bot.send_message(
                    chat_id=int(user_id),
                    text="✅ <b>Payment confirmed!</b>\n\nYour paid access is active now. Use /status to see your plan.",
                    parse_mode=ParseMode.HTML,
                    reply_markup=_success_mkp,
                )
    elif outcome.get("outcome") == "no_slot_available":
        await bot.send_message(
            chat_id=int(user_id),
            text=_founding_no_slot_text(),
            parse_mode=ParseMode.HTML,
        )
    elif outcome.get("outcome") == "cancelled":
        await bot.send_message(
            chat_id=int(user_id),
            text=(
                "⚠️ <b>Payment cancelled</b>\n\n"
                "No founding slot was assigned. Use /founding to try again if slots remain."
            ),
            parse_mode=ParseMode.HTML,
        )
    elif outcome.get("outcome") == "failed":
        await bot.send_message(
            chat_id=int(user_id),
            text=(
                "⚠️ <b>Payment failed</b>\n\n"
                "No access changes were made. Use /founding to try again."
            ),
            parse_mode=ParseMode.HTML,
        )
    else:
        return


_EDGEOPS_CHAT_ID = -1003877525865  # Standing Order #20: EdgeOps only. Never public channels.

# ── BUILD-STITCH-EDGEOPS-WIRE-01 ─────────────────────────────────────────────
# Failure event types that warrant an immediate EdgeOps alert.
_STITCH_FAILURE_EVENT_TYPES: frozenset[str] = frozenset({
    "payment.failed",
    "payment.cancelled",
    "payment.expired",
    "subscription.cancelled",
    "subscription.expired",
})

_STITCH_FAILURE_EMOJI: dict[str, str] = {
    "payment.failed": "❌",
    "payment.cancelled": "🚫",
    "payment.expired": "⏰",
    "subscription.cancelled": "🚫",
    "subscription.expired": "⏰",
}


async def _send_edgeops_payment_alert(
    event_type: str,
    outcome: dict[str, object],
    event: dict[str, object],
) -> None:
    """Send a Stitch payment failure alert to the EdgeOps Telegram channel.

    BUILD-STITCH-EDGEOPS-WIRE-01: Fires on payment.failed, payment.cancelled,
    payment.expired, subscription.cancelled, subscription.expired.

    Standing Order #20: EdgeOps alerts ONLY (chat_id -1003877525865).
    NEVER sends to @MzansiEdgeAlerts.
    """
    import urllib.request as _urllib_request
    import urllib.error as _urllib_error

    token = os.environ.get("BOT_TOKEN", "")
    if not token:
        log.warning("_send_edgeops_payment_alert: BOT_TOKEN not set — alert skipped")
        return

    emoji = _STITCH_FAILURE_EMOJI.get(event_type, "⚠️")
    user_id = outcome.get("user_id")
    plan_code = outcome.get("plan_code") or event.get("data", {}).get("beneficiaryReference", "unknown")
    amount_cents = outcome.get("amount_cents", 0)
    amount_rands = (amount_cents or 0) / 100
    outcome_label = outcome.get("outcome", "unknown")
    provider_payment_id = event.get("data", {}).get("id", "n/a")

    user_line = f"user_id={user_id}" if user_id else "user_id=unknown"
    amount_line = f"R{amount_rands:.2f}" if amount_cents else "amount=unknown"

    text = (
        f"{emoji} <b>Stitch Payment Failure</b>\n\n"
        f"<b>Event:</b> <code>{event_type}</code>\n"
        f"<b>Outcome:</b> <code>{outcome_label}</code>\n"
        f"<b>Plan:</b> <code>{plan_code}</code>\n"
        f"<b>Amount:</b> {amount_line}\n"
        f"<b>User:</b> {user_line}\n"
        f"<b>Payment ID:</b> <code>{provider_payment_id}</code>"
    )

    payload = json.dumps({
        "chat_id": _EDGEOPS_CHAT_ID,
        "text": text,
        "parse_mode": "HTML",
    }).encode("utf-8")

    url = f"https://api.telegram.org/bot{token}/sendMessage"
    req = _urllib_request.Request(
        url, data=payload,
        headers={"Content-Type": "application/json"},
    )
    try:
        resp = _urllib_request.urlopen(req, timeout=8)
        if resp.status == 200:
            log.info(
                "BUILD-STITCH-EDGEOPS-WIRE-01: EdgeOps alert sent event_type=%s user_id=%s",
                event_type, user_id,
            )
        else:
            log.warning(
                "BUILD-STITCH-EDGEOPS-WIRE-01: EdgeOps alert HTTP %s", resp.status
            )
    except _urllib_error.HTTPError as exc:
        log.warning("BUILD-STITCH-EDGEOPS-WIRE-01: EdgeOps alert HTTP error %s: %s", exc.code, exc.read()[:200])
    except Exception as exc:
        log.warning("BUILD-STITCH-EDGEOPS-WIRE-01: EdgeOps alert send error: %s", exc)


def _derive_plan_code_from_reference(reference: str) -> str:
    parts = reference.split("-")
    if len(parts) >= 4:
        return "-".join(parts[2:-1])
    if len(parts) >= 3:
        return "-".join(parts[2:])
    return ""


def _map_webhook_state(event: dict) -> tuple[str, str]:
    event_type = event.get("type", "")
    if event_type in {"payment.cancelled", "subscription.cancelled"}:
        return "cancelled", "cancelled"
    if event_type == "payment.failed":
        return "failed", "failed"
    if event_type in {"payment.expired", "subscription.expired"}:
        return "expired", "expired"
    return "confirmed", "active"


async def _process_stitch_event(event: dict) -> dict[str, object]:
    try:
        data = event.get("data", {})
        provider_payment_id = data.get("id", "")
        provider_reference = data.get("beneficiaryReference", "")
        external_ref = data.get("externalReference", "")
        provider_event_id = event.get("id")
        plan_code = _derive_plan_code_from_reference(provider_reference)

        payment = None
        if provider_reference:
            payment = await db.get_payment_by_reference("stitch", provider_reference)
        if not payment and provider_payment_id:
            payment = await db.get_payment_by_provider_payment_id("stitch", provider_payment_id)

        if payment:
            plan_code = payment.plan_code
            provider_reference = payment.provider_reference

        if not provider_reference:
            provider_reference = f"stitch-{external_ref or provider_payment_id}"

        amount_obj = data.get("amount", {})
        amount_quantity = amount_obj.get("quantity", "0")
        try:
            amount_cents = int(round(float(amount_quantity) * 100))
        except (TypeError, ValueError):
            amount_cents = payment.amount_cents if payment else 0

        event_status, billing_status = _map_webhook_state(event)
        outcome = await db.apply_payment_event(
            provider="stitch",
            provider_reference=provider_reference,
            provider_payment_id=provider_payment_id,
            provider_event_id=provider_event_id,
            plan_code=plan_code or "founding_diamond",
            amount_cents=amount_cents,
            event_status=event_status,
            billing_status=billing_status,
            raw_event=json.dumps(event, sort_keys=True),
        )
        outcome["plan_code"] = plan_code or "founding_diamond"
        outcome["amount_cents"] = amount_cents
        return outcome
    except Exception as _exc:
        if sentry_sdk:
            try:
                sentry_sdk.set_context("stitch_event", {
                    "type": event.get("type", ""),
                    "id": event.get("id"),
                })
                sentry_sdk.capture_exception(_exc)
            except Exception:
                pass
        raise


