# ── Webhook handler (aiohttp) ────────────────────────────

async def _run_webhook_server(app_instance) -> None:
    """Start a small aiohttp server to receive Stitch webhooks."""
    from aiohttp import web

    async def handle_founding_success(request: web.Request) -> web.Response:
        html = (
            "<html><body style='font-family: sans-serif; padding: 32px;'>"
            "<h1>Founding payment received</h1>"
            "<p>This page does not activate access.</p>"
            "<p><strong>Webhook confirmation is the source of truth.</strong> "
            "Your Telegram confirmation and /status will update after the webhook is processed.</p>"
            "<p>If Telegram does not update shortly, open the bot and use /status.</p>"
            "</body></html>"
        )
        return web.Response(text=html, content_type="text/html")

    async def handle_stitch_webhook(request: web.Request) -> web.Response:
        body = await request.read()
        headers = dict(request.headers)

        if not config.STITCH_MOCK_MODE and not stitch_service.verify_webhook(headers, body):
            log.warning("Invalid Stitch webhook signature")
            if sentry_sdk:
                sentry_sdk.capture_message(
                    "stitch webhook signature verification failed",
                    level="warning",
                )
            return web.Response(status=400)

        event = stitch_service.parse_webhook_event(body)
        event_type = event.get("type", "")
        log.info("Stitch webhook: %s", event_type)

        outcome = await _process_stitch_event(event)
        user_id = outcome.get("user_id")
        if user_id and event_type in ("payment.complete", "subscription.created", "subscription.renewed"):
            analytics_track(int(user_id), "subscription_confirmed", {
                "plan": "founding_diamond",
                "outcome": outcome.get("outcome", "unknown"),
            })
            asyncio.create_task(
                meta_capi.fire_purchase_event(
                    int(user_id),
                    int(outcome.get("amount_cents", 0)),
                    str(outcome.get("plan_code", "founding_diamond")),
                )
            )
        elif user_id and event_type in ("payment.cancelled", "subscription.cancelled"):
            analytics_track(int(user_id), "subscription_cancelled")
        elif user_id and event_type == "payment.failed":
            analytics_track(int(user_id), "payment_failed")

        # BUILD-STITCH-EDGEOPS-WIRE-01: fire EdgeOps alert on any failure event.
        # Runs for ALL failure types regardless of whether user_id was resolved —
        # an unmatched payment failure is equally important to flag.
        if event_type in _STITCH_FAILURE_EVENT_TYPES:
            asyncio.create_task(
                _send_edgeops_payment_alert(event_type, outcome, event)
            )

        try:
            await _notify_payment_outcome(app_instance.bot, outcome)
        except Exception as exc:
            log.warning("Failed to send payment outcome notification: %s", exc)

        return web.Response(status=200, text="OK")

    # ── WA-CLOUD-API-01: WhatsApp webhook ─────────────────────────────────────
    _WA_VERIFY_TOKEN = os.getenv("WHATSAPP_VERIFY_TOKEN", "")
    _WA_DB_PATH = _QA_BOT_DB_PATH  # same mzansiedge.db as the rest of the bot

    def _now_sast_iso() -> str:
        import datetime as _dt
        from timezone_utils import SAST as _SAST
        return _dt.datetime.now(_SAST).isoformat()

    async def handle_wa_verify(request: web.Request) -> web.Response:
        mode = request.rel_url.query.get("hub.mode", "")
        token = request.rel_url.query.get("hub.verify_token", "")
        challenge = request.rel_url.query.get("hub.challenge", "")
        if mode == "subscribe" and token == _WA_VERIFY_TOKEN:
            log.info("WhatsApp webhook verified")
            return web.Response(status=200, text=challenge)
        log.warning("WhatsApp webhook verify failed: token mismatch")
        return web.Response(status=403, text="Forbidden")

    async def handle_wa_webhook(request: web.Request) -> web.Response:
        try:
            body = await request.json()
        except Exception as exc:
            log.warning("WhatsApp webhook: invalid JSON: %s", exc)
            return web.Response(status=400, text="Bad Request")
        try:
            for entry in body.get("entry", []):
                for change in entry.get("changes", []):
                    value = change.get("value", {})
                    contacts = value.get("contacts", [])
                    messages = value.get("messages", [])
                    for msg in messages:
                        wa_id = msg.get("from", "")
                        phone_number = "+" + wa_id if wa_id and not wa_id.startswith("+") else wa_id
                        display_name = ""
                        for c in contacts:
                            if c.get("wa_id") == wa_id:
                                display_name = c.get("profile", {}).get("name", "")
                                break
                        referral = msg.get("referral", {})
                        ctwa_clid = referral.get("ctwa_clid") or None
                        source = "ctwa" if ctwa_clid else "organic"
                        now = _now_sast_iso()

                        from db_connection import get_connection as _wa_conn
                        conn = _wa_conn(_WA_DB_PATH, timeout_ms=5000)
                        try:
                            conn.execute(
                                """INSERT INTO wa_contacts
                                   (wa_id, phone_number, display_name, ctwa_clid, source,
                                    opted_in, opted_in_at, last_seen_at)
                                   VALUES (?, ?, ?, ?, ?, 1, ?, ?)
                                   ON CONFLICT(wa_id) DO UPDATE SET
                                   last_seen_at = excluded.last_seen_at,
                                   ctwa_clid = COALESCE(excluded.ctwa_clid, ctwa_clid),
                                   phone_number = COALESCE(excluded.phone_number, phone_number)
                                """,
                                (wa_id, phone_number, display_name, ctwa_clid, source, now, now),
                            )
                            conn.commit()
                            log.info(
                                "wa_contacts upserted: wa_id=%s source=%s ctwa_clid=%s",
                                wa_id, source, ctwa_clid,
                            )
                        finally:
                            conn.close()
        except Exception as exc:
            log.error("WhatsApp webhook processing error: %s", exc, exc_info=True)
            if sentry_sdk:
                sentry_sdk.capture_exception(exc)
            return web.Response(status=500, text="Internal Server Error")
        return web.Response(status=200, text="OK")

    webhook_app = web.Application()
    webhook_app.router.add_post("/webhook/stitch", handle_stitch_webhook)
    webhook_app.router.add_get("/founding-success", handle_founding_success)
    webhook_app.router.add_get("/webhook/whatsapp", handle_wa_verify)
    webhook_app.router.add_post("/webhook/whatsapp", handle_wa_webhook)

    runner = web.AppRunner(webhook_app)
    await runner.setup()
    site = web.TCPSite(runner, "0.0.0.0", 8443)
    await site.start()
    log.info("Stitch webhook server listening on port 8443")


# ── Wave 25C: Post-match result alerts ────────────────────


async def _result_alerts_job(ctx: ContextTypes.DEFAULT_TYPE) -> None:
    """Every 2h: send result alerts to users who viewed recently settled edges.

    Tier-gated templates:
    - Bronze (saw locked Gold/Diamond that HIT): upgrade CTA
    - Bronze (MISS): transparency line + season accuracy
    - Gold (HIT): streak + Diamond teaser
    - Diamond (HIT): full CLV data + season stats
    - All (MISS): same prominence as wins, season accuracy always shown
    """
    if not NOTIFICATIONS_ENABLED:
        return
    # FIX-HIDE-EDGE-TRACKER-P0-01: Result alerts broadcast hit/miss + season accuracy.
    # Internal settlement pipeline still runs; user-facing alerts are suppressed.
    if EDGE_PERFORMANCE_HIDDEN:
        log.info("Result alerts skipped — EDGE_PERFORMANCE_HIDDEN")
        return
    log.info("Result alerts job running")
    _ra_mon = _CronMonitor("settlement-pipeline")
    _ra_mon.begin()
    _sentry_tags(cron_job="settlement-pipeline")

    try:
        from scrapers.edge.settlement import get_recently_settled_since, get_edge_stats
    except Exception as exc:
        log.warning("Result alerts: settlement import failed: %s", exc)
        _ra_mon.done()
        return

    recently = await asyncio.to_thread(get_recently_settled_since, 2.5)
    if not recently:
        log.info("Result alerts: no recently settled edges")
        return

    # Fetch season accuracy once
    season_stats = None
    try:
        season_stats = await asyncio.to_thread(get_edge_stats, 30)
    except Exception:
        pass
    season_rate = f"{season_stats['hit_rate'] * 100:.0f}%" if season_stats and season_stats.get("total", 0) > 0 else "N/A"

    from renderers.edge_renderer import EDGE_EMOJIS, render_result_emoji

    # Track per-user alerts to enable bundling
    user_alerts: dict[int, list[dict]] = {}

    for edge in recently:
        edge_id = edge.get("edge_id", "")
        if not edge_id:
            continue

        viewers = await db.get_edge_viewers(edge_id)
        if not viewers:
            continue

        for viewer in viewers:
            uid = viewer["user_id"]
            if uid not in user_alerts:
                user_alerts[uid] = []
            user_alerts[uid].append(edge)

    sent = 0
    for uid, edges in user_alerts.items():
        try:
            if not await _can_send_notification(uid):
                continue

            user_tier = await get_effective_tier(uid)

            # Bundle rule: >3 results for one user → send summary
            if len(edges) > 3:
                hits = sum(1 for e in edges if e.get("result") == "hit")
                misses = len(edges) - hits
                text = (
                    f"📊 <b>Results Update — {len(edges)} edges settled</b>\n\n"
                    f"✅ <b>{hits} hit</b> · ❌ {misses} missed\n"
                    f"Season accuracy: <b>{season_rate}</b>"
                )
                buttons = [[InlineKeyboardButton("📊 My Results", callback_data="results:7")]]
                if user_tier in ("bronze", "gold"):
                    buttons.append([InlineKeyboardButton("✨ View Plans", callback_data="sub:plans")])

                _bundle_net = f"+{hits * 10}%" if hits > 0 else ""
                await send_card_or_fallback(
                    bot=ctx.bot,
                    chat_id=uid,
                    template="notify_result_bundle.html",
                    data=build_notify_result_bundle_data(
                        hits=hits,
                        misses=misses,
                        total=len(edges),
                        net_on_R100=_bundle_net,
                        accuracy_window=f"Season: {season_rate}",
                    ),
                    text_fallback="",
                    markup=InlineKeyboardMarkup(buttons),
                )
                await _after_send(uid)
                sent += 1
                continue

            # Individual alerts
            for edge in edges:
                if not await _can_send_notification(uid):
                    break

                result = edge.get("result", "")
                r_emoji = render_result_emoji(result)
                tier = edge.get("edge_tier", "bronze")
                tier_emoji = EDGE_EMOJIS.get(tier, "")
                match_display = _display_team_name(edge.get("match_key", ""))
                odds = edge.get("recommended_odds", 0)
                score = edge.get("match_score", "")
                ev = edge.get("predicted_ev", 0)

                from renderers.edge_renderer import format_return as _fmt_return
                from tier_gate import get_edge_access_level as _ra_access

                _alert_access = _ra_access(user_tier, tier)

                lines = []
                if result == "hit":
                    lines.append(f"{r_emoji} <b>Edge Hit!</b> {tier_emoji}\n")
                    lines.append(f"⚽ {match_display}")
                    if score:
                        lines.append(f"📋 Final score: {score}")

                    if _alert_access in ("full", "partial"):
                        # Full/partial: show odds + EV + return
                        if odds:
                            lines.append(f"💰 @ {odds:.2f} · +{ev:.1f}% EV")
                            lines.append(f"   {_fmt_return(odds, stake=300)}")
                    elif _alert_access == "blurred":
                        # Blurred: show return only, no odds/bookmaker/EV
                        if odds:
                            _ra_ret = odds * 300
                            lines.append(f"💰 R{_ra_ret:,.0f} return on R300")

                    # FOMO line for blurred/locked
                    if _alert_access in ("blurred", "locked"):
                        lines.append(f"\nThis {tier.title()} Edge was locked for you — it just hit.")
                    lines.append(f"\nSeason accuracy: <b>{season_rate}</b>")

                else:  # miss
                    lines.append(f"{r_emoji} <b>Edge Missed</b> {tier_emoji}\n")
                    lines.append(f"⚽ {match_display}")
                    if score:
                        lines.append(f"📋 Final score: {score}")

                    if _alert_access in ("full", "partial"):
                        lines.append(f"\nOur edge rating was +{ev:.1f}% — the market was right this time.")
                    else:
                        lines.append("\nOne of our edges missed — that's part of the game.")
                    lines.append(f"Season accuracy: <b>{season_rate}</b>")

                    # Track consecutive misses
                    u = await db.get_user(uid)
                    new_count = (getattr(u, "consecutive_misses", 0) or 0) + 1
                    await db.update_consecutive_misses(uid, new_count)

                # Build buttons — check consecutive misses BEFORE resetting
                buttons = [[InlineKeyboardButton("📊 My Results", callback_data="results:7")]]
                u = await db.get_user(uid)
                consec = getattr(u, "consecutive_misses", 0) or 0
                if user_tier in ("bronze", "gold") and result == "hit" and consec < 3:
                    buttons.append([InlineKeyboardButton("✨ View Plans", callback_data="sub:plans")])
                elif consec >= 3:
                    # Educational text replaces upgrade CTA during losing streaks
                    s_total = season_stats.get("total", 0) if season_stats else 0
                    s_hits = season_stats.get("hits", 0) if season_stats else 0
                    s_pct = f"{season_stats['hit_rate'] * 100:.0f}" if season_stats and s_total > 0 else "N/A"
                    lines.append(
                        f"\n📊 Recent edges haven't gone our way — that's value betting.\n"
                        f"Season accuracy: {s_hits}/{s_total} ({s_pct}%)\n"
                        f"Edge = long-term advantage, not every-bet certainty."
                    )

                # Reset consecutive misses on hit (after button decision)
                if result == "hit":
                    await db.update_consecutive_misses(uid, 0)

                _profit_r100 = f"+R{round((odds - 1) * 100)}" if odds > 1 else ""
                _loss_r100 = f"-R100" if result == "miss" else ""
                if result == "hit":
                    await send_card_or_fallback(
                        bot=ctx.bot,
                        chat_id=uid,
                        template="notify_result_hit.html",
                        data=build_notify_result_hit_data(
                            match=match_display,
                            pick=edge.get("bet_type", ""),
                            odds=odds,
                            profit_on_R100=_profit_r100,
                            season_accuracy=season_rate,
                            tier=tier,
                            tier_emoji=tier_emoji,
                            score=score,
                        ),
                        text_fallback="",
                        markup=InlineKeyboardMarkup(buttons),
                    )
                else:
                    await send_card_or_fallback(
                        bot=ctx.bot,
                        chat_id=uid,
                        template="notify_result_miss.html",
                        data=build_notify_result_miss_data(
                            match=match_display,
                            pick=edge.get("bet_type", ""),
                            odds=odds,
                            loss_on_R100=_loss_r100,
                            season_accuracy=season_rate,
                            transparency_note="The market was right on this one.",
                            tier=tier,
                            tier_emoji=tier_emoji,
                            score=score,
                            consecutive_misses=consec,
                        ),
                        text_fallback="",
                        markup=InlineKeyboardMarkup(buttons),
                    )
                await _after_send(uid)
                sent += 1
        except Exception:
            pass  # Silently skip blocked users

    log.info("Result alerts: sent %d alerts to %d users", sent, len(user_alerts))
    _ra_mon.done()


# ── P3-05: Pre-match Gold+ alert ──────────────────────────

# Tracks match_keys already alerted today; keyed by SAST date string.
_pre_match_alert_sent: dict[str, set] = {}


def _kickoff_for_match_key(match_key: str):
    """Synchronous. Return timezone-aware kickoff datetime from broadcast_schedule, or None."""
    try:
        from datetime import datetime  # noqa: PLC0415
        from zoneinfo import ZoneInfo  # noqa: PLC0415
        from db_connection import get_connection  # noqa: PLC0415
        from scrapers.edge.edge_config import DB_PATH  # noqa: PLC0415

        # Parse date and team keywords from match_key (format: home_vs_away_YYYY-MM-DD)
        parts = match_key.rsplit("_", 1)
        if len(parts) != 2 or len(parts[1]) != 10:
            return None
        match_date, rest = parts[1], parts[0]
        if "_vs_" not in rest:
            return None
        home_raw, away_raw = rest.split("_vs_", 1)
        home_kw = home_raw.split("_")[0].lower()[:5]
        away_kw = away_raw.split("_")[0].lower()[:5]

        # INV-TIMEZONE-POST-SAST-UNIFY-REGRESSION-01: supersport_scraper-only;
        # DStv EPG re-airs would otherwise mislabel the pre-match alert window.
        conn = get_connection(DB_PATH, readonly=True, timeout_ms=3000)
        row = conn.execute(
            """
            SELECT start_time FROM broadcast_schedule
            WHERE source = 'supersport_scraper'
              AND broadcast_date = ?
              AND (LOWER(home_team) LIKE ? OR LOWER(home_team) LIKE ?)
            LIMIT 1
            """,
            (match_date, f"%{home_kw}%", f"%{away_kw}%"),
        ).fetchone()
        conn.close()
        if not row or not row[0]:
            return None
        dt = datetime.fromisoformat(str(row[0]))
        if dt.tzinfo is None:
            dt = assume_sast(dt)
        return dt
    except Exception as exc:
        log.debug("_kickoff_for_match_key(%s) failed: %s", match_key, exc)
        return None


async def _pre_match_gold_alert_job(ctx: ContextTypes.DEFAULT_TYPE) -> None:
    """Hourly: send audible pre-match alert when Gold/Diamond edges kick off in 2-4h.

    AC-2: Gold+ only. Audible if budget allows.
    AC-7: Scheduled from edge_results. No duplicates per day.
    """
    if not NOTIFICATIONS_ENABLED:
        return
    from datetime import datetime as dt_cls  # noqa: PLC0415
    from zoneinfo import ZoneInfo  # noqa: PLC0415
    import notification_budget as _nb  # noqa: PLC0415

    tz = ZoneInfo(config.TZ)
    now = dt_cls.now(tz)
    today = now.date().isoformat()

    # Initialise / rotate daily dedup set
    if today not in _pre_match_alert_sent:
        _pre_match_alert_sent.clear()
        _pre_match_alert_sent[today] = set()
    already_sent = _pre_match_alert_sent[today]

    # Query today's Gold/Diamond unsettled edges
    try:
        from scrapers.db_connect import connect_odds_db  # noqa: PLC0415
        from scrapers.edge.edge_config import DB_PATH  # noqa: PLC0415
        _pma_conn = connect_odds_db(DB_PATH)
        _pma_conn.row_factory = lambda c, r: dict(
            zip([col[0] for col in c.description], r)
        )
        gold_rows = _pma_conn.execute(
            """
            SELECT match_key, edge_tier, bet_type, recommended_odds,
                   bookmaker, predicted_ev, league, composite_score
            FROM edge_results
            WHERE match_date = ? AND result IS NULL
              AND edge_tier IN ('gold', 'diamond')
            ORDER BY composite_score DESC
            """,
            (today,),
        ).fetchall()
        _pma_conn.close()
    except Exception as exc:
        log.debug("Pre-match gold alert: edge_results query failed: %s", exc)
        return

    if not gold_rows:
        return

    # Deduplicate by match_key (keep highest composite_score)
    _seen: dict[str, dict] = {}
    for row in gold_rows:
        mk = row["match_key"]
        if mk not in _seen or row["composite_score"] > _seen[mk]["composite_score"]:
            _seen[mk] = row
    unique_edges = list(_seen.values())

    # Find edges with kickoff in the 2-4h window
    qualifying: list[dict] = []
    for edge in unique_edges:
        mk = edge["match_key"]
        if mk in already_sent:
            continue
        kickoff = await asyncio.to_thread(_kickoff_for_match_key, mk)
        if kickoff is None:
            continue
        hours_until = (kickoff - now).total_seconds() / 3600
        if 2.0 <= hours_until <= 4.0:
            qualifying.append(edge)

    if not qualifying:
        return

    log.info(
        "Pre-match gold alert: %d qualifying edge(s) kicking off in 2-4h", len(qualifying)
    )

    from renderers.edge_renderer import EDGE_EMOJIS as _pma_emojis  # noqa: PLC0415

    users = await db.get_all_onboarded_users()
    sent_count = 0

    # P3-06: Pre-load edge sport key for filter checks
    _edge_sports = set()
    for edge in qualifying:
        _edge_league = edge.get("league", "")
        _edge_sk = _DB_LEAGUE_SPORT.get(_edge_league, "soccer")
        _edge_sports.add(_edge_sk)

    for user in users:
        try:
            user_tier = await get_effective_tier(user.id)
            if user_tier not in ("gold", "diamond"):
                continue  # AC-2: Gold+ only

            if not await _can_send_notification(user.id):
                continue

            # P3-06: Check user's sport filter
            try:
                import user_settings as _us_pma  # noqa: PLC0415
                _pma_pref = await asyncio.to_thread(_us_pma.get_settings, user.id)
                _pma_active = set(_pma_pref["sport_filter"].split(","))
                _pma_match = any(
                    (sk in _pma_active)
                    or (sk == "combat" and ("mma" in _pma_active or "boxing" in _pma_active))
                    for sk in _edge_sports
                )
                if not _pma_match:
                    continue
            except Exception as _pma_err:
                log.debug("Pre-match sport filter error (fail-open): %s", _pma_err)

            audible = await asyncio.to_thread(_nb.can_send_audible, user.id)

            # Build card for first qualifying edge (most important)
            _pma_edge = qualifying[0]
            _pma_match = _display_team_name(_pma_edge["match_key"])
            _pma_tier = _pma_edge["edge_tier"]
            _pma_tier_emoji = _pma_emojis.get(_pma_tier, "")
            _pma_odds = _pma_edge.get("recommended_odds", 0)
            _pma_ev = _pma_edge.get("predicted_ev", 0)
            _pma_bk_key = (_pma_edge.get("bookmaker") or "").lower()
            _pma_league = _pma_edge.get("league", "")
            _pma_bk_url = config.get_affiliate_url()
            _pma_hours_h = int(hours_until)
            _pma_hours_m = int((hours_until - _pma_hours_h) * 60)
            _pma_kickoff_in = f"{_pma_hours_h}h {_pma_hours_m:02d}m" if _pma_hours_h > 0 else f"{_pma_hours_m}m"
            markup = InlineKeyboardMarkup([
                [InlineKeyboardButton("💎 Edge Picks", callback_data="hot:go")],
            ])
            await send_card_or_fallback(
                bot=ctx.bot,
                chat_id=user.id,
                template="notify_pre_match_gold.html",
                data=build_notify_pre_match_gold_data(
                    match=_pma_match,
                    kickoff_in=_pma_kickoff_in,
                    pick=_pma_edge.get("bet_type", ""),
                    odds=_pma_odds,
                    bookmaker_url=_pma_bk_url,
                    tier=_pma_tier,
                    tier_emoji=_pma_tier_emoji,
                    league=_pma_league,
                    ev=_pma_ev,
                ),
                text_fallback="",
                markup=markup,
            )
            if audible:
                await asyncio.to_thread(_nb.record_audible, user.id)
            await _after_send(user.id)
            sent_count += 1
        except Exception as exc:
            log.debug("Pre-match alert: failed to send to user %d: %s", user.id, exc)

    # Mark these edges as sent today (do this once, regardless of users reached)
    for edge in qualifying:
        already_sent.add(edge["match_key"])

    log.info("Pre-match gold alert: sent to %d users", sent_count)


# ── P3-05: Budget reset (00:00 SAST) ─────────────────────


async def _budget_reset_job(ctx: ContextTypes.DEFAULT_TYPE) -> None:
    """Hourly: prune stale audible budget rows at 00:00 SAST."""
    from datetime import datetime as dt_cls  # noqa: PLC0415
    from zoneinfo import ZoneInfo  # noqa: PLC0415
    import notification_budget as _nb  # noqa: PLC0415

    now = dt_cls.now(ZoneInfo(config.TZ))
    if now.hour != 0:
        return

    log.info("Budget reset job running at 00:00 SAST")
    await asyncio.to_thread(_nb.reset)


# ── Wave 25A: /mute command ───────────────────────────────


async def cmd_mute(update: Update, ctx: ContextTypes.DEFAULT_TYPE) -> None:
    """Handle /mute, /unmute, /quiet — pause proactive notifications."""
    import datetime as _dt

    user_id = update.effective_user.id
    args = ctx.args or []
    arg = args[0].lower().strip() if args else ""

    # /unmute or /mute off → clear mute
    if arg == "off" or (update.message and update.message.text and update.message.text.startswith("/unmute")):
        await db.set_muted_until(user_id, None)
        _mute_resume_mkp = InlineKeyboardMarkup([
            [InlineKeyboardButton("💎 Edge Picks", callback_data="hot:go")],
        ])
        await update.message.reply_text(
            "🔔 <b>Notifications unmuted!</b>\nYou're back — we'll alert you as normal.",
            parse_mode=ParseMode.HTML,
            reply_markup=_mute_resume_mkp,
        )
        return

    # Parse duration
    now = _dt.datetime.now(_dt.timezone.utc)
    if arg in ("week", "7d", "7"):
        until = now + _dt.timedelta(days=7)
        label = "7 days"
    elif arg in ("48h", "48"):
        until = now + _dt.timedelta(hours=48)
        label = "48 hours"
    else:
        # Default: 24 hours
        until = now + _dt.timedelta(hours=24)
        label = "24 hours"

    await db.set_muted_until(user_id, until)
    from zoneinfo import ZoneInfo as _mute_tz
    _resumes_str = until.astimezone(_mute_tz(config.TZ)).strftime("%a %d %b at %H:%M")
    _mute_confirm_mkp = InlineKeyboardMarkup([
        [InlineKeyboardButton("🔔 Unmute now", callback_data="mute:off")],
    ])
    await update.message.reply_text(
        f"🔕 <b>Notifications muted for {label}.</b>\nResumes {_resumes_str}.",
        parse_mode=ParseMode.HTML,
        reply_markup=_mute_confirm_mkp,
    )


# ── Wave 25A: Re-engagement nudge ────────────────────────


async def _reengagement_nudge_job(ctx: ContextTypes.DEFAULT_TYPE) -> None:
    """Hourly job: send re-engagement nudge to inactive users at 18:00 SAST.

    Rules:
    - Only fires at 18:00 SAST
    - Targets users inactive for 72h+
    - Max 1 nudge per 7 days (enforced by DB query)
    - After 2 consecutive unanswered nudges (14+ days), switch to monthly lighter tone
    - Shows real data, never generic messaging
    """
    if not NOTIFICATIONS_ENABLED:
        return
    # FIX-HIDE-EDGE-TRACKER-P0-01: Nudge body uses 7D hit rate + top hit returns.
    if EDGE_PERFORMANCE_HIDDEN:
        log.info("Re-engagement nudge skipped — EDGE_PERFORMANCE_HIDDEN")
        return
    from datetime import datetime as dt_cls
    from zoneinfo import ZoneInfo

    now = dt_cls.now(ZoneInfo(config.TZ))
    if now.hour != 18:
        return

    log.info("Re-engagement nudge job running at 18:00 SAST")
    _rn_mon = _CronMonitor("reengagement-nudge")
    _rn_mon.begin()
    _sentry_tags(cron_job="reengagement-nudge")

    inactive_users = await db.get_inactive_users(hours=72, nudge_cooldown_days=7)
    if not inactive_users:
        log.info("No inactive users to nudge")
        _rn_mon.done()
        return

    # Fetch settlement stats once
    edge_stats = None
    best_hits = None
    try:
        _ge, _, _gbh, _, *_ = _get_settlement_funcs()
        edge_stats = await asyncio.to_thread(_ge, 7)
        best_hits = await asyncio.to_thread(_gbh, 7, 3)
    except Exception as exc:
        log.warning("Re-engagement: settlement data unavailable: %s", exc)

    from renderers.edge_renderer import EDGE_EMOJIS, format_return

    sent = 0
    for user in inactive_users:
        try:
            if not await _can_send_notification(user.id):
                continue

            user_tier = await get_effective_tier(user.id)

            # Check consecutive misses for lighter tone
            consecutive = getattr(user, "consecutive_misses", 0) or 0
            lighter_tone = consecutive >= 2

            lines = []
            if lighter_tone:
                lines.append("👋 <b>Quick update from MzansiEdge</b>\n")
            else:
                name = h(user.first_name or "there")
                lines.append(f"👋 <b>Hey {name}, we've missed you!</b>\n")

            # Show real stats
            if edge_stats and edge_stats.get("total", 0) > 0:
                hits = edge_stats.get("hits", 0)
                total = edge_stats["total"]
                rate = edge_stats.get("hit_rate", 0)
                lines.append(
                    f"This week: <b>{hits}/{total}</b> edges hit (<b>{rate * 100:.0f}%</b>)"
                )

            # Show best hit
            if best_hits:
                top = best_hits[0]
                mk = _display_team_name(top.get("match_key", ""))
                odds = top.get("recommended_odds", 0)
                lines.append(f"✅ Top hit: {mk} @ {odds:.2f}")
                if odds > 0:
                    lines.append(f"   {format_return(odds)}")
                lines.append("")

            # Portfolio stat (Wave 25B)
            pf_line = _get_portfolio_line()
            if pf_line:
                lines.append(pf_line)
                lines.append("")

            # Tier-specific CTA
            buttons = [[InlineKeyboardButton("💎 Edge Picks", callback_data="hot:go")]]
            if user_tier in ("bronze", "gold"):
                if not lighter_tone:
                    lines.append("See what edges are live right now!")
                buttons.append([InlineKeyboardButton("✨ View Plans", callback_data="sub:plans")])
            else:
                if not lighter_tone:
                    lines.append("Your Diamond edges are waiting.")

            # Build settlement stats dict for card adapter
            _rn_stats = {}
            if edge_stats and edge_stats.get("total", 0) > 0:
                _rn_stats = {
                    "hits": edge_stats.get("hits", 0),
                    "total": edge_stats["total"],
                    "rate_pct": f"{edge_stats.get('hit_rate', 0) * 100:.0f}",
                }
            _rn_best = None
            if best_hits:
                _rn_top = best_hits[0]
                _rn_mk = _display_team_name(_rn_top.get("match_key", ""))
                _rn_odds = _rn_top.get("recommended_odds", 0)
                _rn_best = {
                    "match": _rn_mk,
                    "odds": _rn_odds,
                    "profit_str": format_return(_rn_odds) if _rn_odds > 0 else "",
                }
            _pf_line = _get_portfolio_line()

            if lighter_tone:
                await send_card_or_fallback(
                    bot=ctx.bot,
                    chat_id=user.id,
                    template="notify_reengagement_lighter.html",
                    data=build_notify_reengagement_lighter_data(
                        days_since_active=3,
                        settlement_stats=_rn_stats,
                        mute_cta="Mute for 7 days with /mute week",
                    ),
                    text_fallback="",
                    markup=InlineKeyboardMarkup(buttons),
                )
            else:
                await send_card_or_fallback(
                    bot=ctx.bot,
                    chat_id=user.id,
                    template="notify_reengagement.html",
                    data=build_notify_reengagement_data(
                        days_since_active=3,
                        edges_missed=_rn_stats.get("total", 0),
                        return_cta="See what edges are live right now!",
                        responsible_footer=True,
                        settlement_stats=_rn_stats,
                        best_hit=_rn_best,
                    ),
                    text_fallback="",
                    markup=InlineKeyboardMarkup(buttons),
                )

            # Update nudge tracking
            import datetime as _dt
            async with db.async_session() as s:
                db_user = await s.get(db.User, user.id)
                if db_user:
                    db_user.nudge_sent_at = _dt.datetime.now(_dt.timezone.utc)
                    db_user.consecutive_misses = (db_user.consecutive_misses or 0) + 1
                    await s.commit()

            await _after_send(user.id)
            sent += 1
        except Exception:
            pass  # Silently skip blocked users
    log.info("Re-engagement nudge: sent to %d/%d inactive users", sent, len(inactive_users))
    _rn_mon.done()


# ── QA Admin Command (TEMPORARY — TODO: Remove before launch) ──────────

# QA tier override — in-memory, cleared on restart
_QA_TIER_OVERRIDES: dict[int, str] = {}


async def get_effective_tier(user_id: int) -> str:
    """Return user's effective tier, respecting QA overrides."""
    if user_id in _QA_TIER_OVERRIDES:
        return _QA_TIER_OVERRIDES[user_id]
    return await db.get_user_tier(user_id)


def _qa_banner(user_id: int) -> str:
    """Return QA mode banner if tier override is active, else empty string."""
    tier = _QA_TIER_OVERRIDES.get(user_id)
    if tier:
        return f"⚠️ QA Mode: Viewing as {tier.upper()}\n\n"
    return ""


# ── BUILD-QA-HARNESS-01: profile data model helpers ───────────────────────────

_QA_BOT_DB_PATH: str = str(config.DATABASE_PATH) if config.DATABASE_PATH else os.path.join(
    os.path.dirname(os.path.abspath(__file__)), "data", "mzansiedge.db"
)


def _qa_get_profile(profile_id: str) -> dict | None:
    """Load a single QA profile by ID. Read-only."""
    try:
        from db_connection import get_connection as _gc
        conn = _gc(_QA_BOT_DB_PATH, timeout_ms=3000)
        row = conn.execute(
            "SELECT * FROM qa_profiles WHERE profile_id = ?",
            (profile_id.upper(),),
        ).fetchone()
        conn.close()
        return dict(row) if row else None
    except Exception as _e:
        log.warning("_qa_get_profile(%s) failed: %s", profile_id, _e)
        return None


def _qa_list_profiles() -> list[dict]:
    """List all QA profiles ordered by ID."""
    try:
        from db_connection import get_connection as _gc
        conn = _gc(_QA_BOT_DB_PATH, timeout_ms=3000)
        rows = conn.execute(
            "SELECT profile_id, display_name, last_baselined_at, active "
            "FROM qa_profiles ORDER BY profile_id"
        ).fetchall()
        conn.close()
        return [dict(r) for r in rows]
    except Exception as _e:
        log.warning("_qa_list_profiles failed: %s", _e)
        return []


def _qa_log_harness_command(
    profile_id: str,
    command: str,
    invoked_by: int,
    result_path: str | None,
    duration_ms: int,
) -> None:
    """Write a row to qa_command_log. Best-effort — never raises."""
    try:
        from db_connection import get_connection as _gc
        conn = _gc(_QA_BOT_DB_PATH, timeout_ms=3000)
        conn.execute(
            "INSERT INTO qa_command_log "
            "(profile_id, command, invoked_by, invoked_at, result_path, duration_ms) "
            "VALUES (?, ?, ?, datetime('now'), ?, ?)",
            (profile_id, command, invoked_by, result_path, duration_ms),
        )
        conn.commit()
        conn.close()
    except Exception as _e:
        log.debug("qa_command_log write failed: %s", _e)


